  "name": "Dari Native Bridge",
  "description": "A specialized linguistic AI tool that localizes Iranian Persian (Farsi) and English into authentic, native Dari (Afghan Persian). Supports text, images, and audio translation with expert localization notes.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
