import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum TranslationMode {
  TEXT = 'TEXT',
  IMAGE = 'IMAGE',
  AUDIO = 'AUDIO',
  CSV = 'CSV'
}

export interface LocalizationResult {
  sourceLanguage: 'English' | 'Farsi' | 'Unknown';
  dariTranslation: string;
  transliteration?: string;
  localizationNotes: string[];
}

export interface ProcessingState {
  loading: boolean;
  error: string | null;
  result: LocalizationResult | null;
}

import { GoogleGenAI, Type } from "@google/genai";
import { LocalizationResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
You are the "Dari Native Bridge," a specialized linguistic AI expert. Your primary goal is to localize and translate Iranian Persian (Farsi) and English into authentic, native Dari (Afghan Persian). 
You prioritize "Dari-first" vocabulary, avoiding Iranian-specific neologisms or overly Westernized terms when a native Dari equivalent exists.

Linguistic Rules:
1. Vocabulary: Replace Iranian terms (e.g., Daneshgah) with Dari equivalents (e.g., Pohantun). Use Pashto-influenced Dari where appropriate for local flavor.
2. Formal vs. Informal: Recognize the context and provide the appropriate level of Dari politeness (e.g., "Shoma" vs. "Tu" in an Afghan context).
3. Grammar: Adjust syntax to match Afghan speech patterns (e.g., specific verb endings and prepositions common in Kabul, Herat, or Mazar-i-Sharif).

Output format MUST be a JSON object:
{
  "sourceLanguage": "English" | "Farsi",
  "dariTranslation": "The Dari text in Persian alphabet",
  "transliteration": "Latin script transliteration for pronunciation",
  "localizationNotes": ["Array of strings explaining specific word choices"]
}
`;

export const localizeText = async (text: string): Promise<LocalizationResult> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `Translate and localize the following text to authentic Dari: "${text}"`,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          sourceLanguage: { type: Type.STRING },
          dariTranslation: { type: Type.STRING },
          transliteration: { type: Type.STRING },
          localizationNotes: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["sourceLanguage", "dariTranslation", "localizationNotes"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

export const localizeFile = async (base64: string, mimeType: string, prompt: string): Promise<LocalizationResult> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: [
      {
        inlineData: {
          data: base64,
          mimeType: mimeType,
        },
      },
      { text: prompt },
    ],
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          sourceLanguage: { type: Type.STRING },
          dariTranslation: { type: Type.STRING },
          transliteration: { type: Type.STRING },
          localizationNotes: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["sourceLanguage", "dariTranslation", "localizationNotes"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

