import React, { useState, useRef } from 'react';
import { TranslationMode } from '../types';

interface Props {
  onTranslate: (data: { text?: string; file?: File; mode: TranslationMode }) => void;
  loading: boolean;
}

const TranslationInput: React.FC<Props> = ({ onTranslate, loading }) => {
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TEXT);
  const [text, setText] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (mode === TranslationMode.TEXT && text.trim()) {
      onTranslate({ text, mode });
    } else if (file) {
      onTranslate({ file, mode });
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selected = e.target.files?.[0];
    if (selected) setFile(selected);
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
      <div className="flex border-b border-gray-100 bg-gray-50/50">
        <button
          onClick={() => setMode(TranslationMode.TEXT)}
          className={`flex-1 py-3 text-sm font-semibold transition-colors ${mode === TranslationMode.TEXT ? 'text-emerald-600 bg-white' : 'text-gray-500 hover:text-gray-700'}`}
        >
          Text
        </button>
        <button
          onClick={() => setMode(TranslationMode.IMAGE)}
          className={`flex-1 py-3 text-sm font-semibold transition-colors ${mode === TranslationMode.IMAGE ? 'text-emerald-600 bg-white' : 'text-gray-500 hover:text-gray-700'}`}
        >
          Image/PDF
        </button>
        <button
          onClick={() => setMode(TranslationMode.AUDIO)}
          className={`flex-1 py-3 text-sm font-semibold transition-colors ${mode === TranslationMode.AUDIO ? 'text-emerald-600 bg-white' : 'text-gray-500 hover:text-gray-700'}`}
        >
          Audio/Video
        </button>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-4">
        {mode === TranslationMode.TEXT ? (
          <textarea
            className="w-full h-40 p-4 text-lg border border-gray-200 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all resize-none"
            placeholder="Type or paste your English or Farsi text here..."
            value={text}
            onChange={(e) => setText(e.target.value)}
          />
        ) : (
          <div className="border-2 border-dashed border-gray-200 rounded-xl p-8 text-center bg-gray-50 hover:bg-gray-100 transition-colors cursor-pointer" onClick={() => fileInputRef.current?.click()}>
            <input
              type="file"
              ref={fileInputRef}
              className="hidden"
              onChange={handleFileChange}
              accept={mode === TranslationMode.IMAGE ? "image/*,application/pdf" : "audio/*,video/*"}
            />
            <div className="flex flex-col items-center">
              <svg className="w-12 h-12 text-gray-400 mb-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
              </svg>
              <p className="text-gray-600 font-medium">
                {file ? file.name : `Click to upload ${mode === TranslationMode.IMAGE ? 'an image or PDF' : 'audio or video'}`}
              </p>
              <p className="text-gray-400 text-sm mt-1">Maximum file size 20MB</p>
            </div>
          </div>
        )}

        <button
          type="submit"
          disabled={loading || (mode === TranslationMode.TEXT ? !text.trim() : !file)}
          className="w-full bg-emerald-600 text-white font-bold py-4 rounded-xl hover:bg-emerald-700 disabled:bg-gray-300 disabled:cursor-not-allowed transition-all shadow-md active:scale-[0.98] flex items-center justify-center space-x-2"
        >
          {loading ? (
            <>
              <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              <span>Processing...</span>
            </>
          ) : (
            <>
              <span>Bridge to Dari</span>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
              </svg>
            </>
          )}
        </button>
      </form>
    </div>
  );
};

export default TranslationInput;

