import React, { useState } from 'react';
import Header from './components/Header';
import TranslationInput from './components/TranslationInput';
import ResultView from './components/ResultView';
import { TranslationMode, ProcessingState } from './types';
import { localizeText, localizeFile } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<ProcessingState>({
    loading: false,
    error: null,
    result: null,
  });

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const result = reader.result as string;
        resolve(result.split(',')[1]);
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleTranslate = async (data: { text?: string; file?: File; mode: TranslationMode }) => {
    setState(prev => ({ ...prev, loading: true, error: null, result: null }));

    try {
      if (data.mode === TranslationMode.TEXT && data.text) {
        const result = await localizeText(data.text);
        setState({ loading: false, error: null, result });
      } else if (data.file) {
        const base64 = await fileToBase64(data.file);
        const prompt = data.mode === TranslationMode.IMAGE 
          ? "OCR this image or PDF and localize the content into authentic Dari."
          : "Transcribe this audio or video and localize the spoken content into authentic Dari.";

        const result = await localizeFile(base64, data.file.type, prompt);
        setState({ loading: false, error: null, result });
      }
    } catch (err: any) {
      console.error(err);
      setState({
        loading: false,
        error: err.message || "An unexpected error occurred during translation.",
        result: null
      });
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Header />

      <main className="flex-grow max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-8 w-full space-y-8">
        <section className="text-center space-y-2">
          <h2 className="text-3xl font-bold text-gray-900 sm:text-4xl">
            Linguistic Localization Expert
          </h2>
          <p className="text-gray-500 max-w-2xl mx-auto">
            Bridge the gap between Iranian Farsi or English and authentic, native Afghan Dari with specialized linguistic rules and expert context.
          </p>
        </section>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="space-y-6">
            <TranslationInput onTranslate={handleTranslate} loading={state.loading} />

            <div className="bg-emerald-50 rounded-2xl p-6 border border-emerald-100">
              <h3 className="text-emerald-800 font-bold mb-3 flex items-center">
                <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
                </svg>
                Why Dari Native Bridge?
              </h3>
              <ul className="text-sm text-emerald-700 space-y-2">
                <li className="flex items-center">
                  <span className="mr-2">✓</span>
                  Swaps Farsi neologisms for native Dari equivalents.
                </li>
                <li className="flex items-center">
                  <span className="mr-2">✓</span>
                  Respects Afghan politeness registers (Etiquette).
                </li>
                <li className="flex items-center">
                  <span className="mr-2">✓</span>
                  Processes audio, video, images, and text seamlessly.
                </li>
              </ul>
            </div>
          </div>

          <div className="space-y-6">
            {state.error && (
              <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-xl flex items-center space-x-3">
                <svg className="w-5 h-5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
                <p className="text-sm font-medium">{state.error}</p>
              </div>
            )}

            {state.result ? (
              <ResultView result={state.result} />
            ) : (
              !state.loading && (
                <div className="h-full min-h-[400px] flex flex-col items-center justify-center bg-gray-50 border border-dashed border-gray-200 rounded-2xl text-gray-400 p-8 text-center">
                  <div className="bg-white p-4 rounded-full shadow-sm mb-4">
                    <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M3 5h12M9 3v2m1.048 9.5A18.022 18.022 0 016.412 9m6.088 9h7M11 21l5-10 5 10M12.751 5C11.783 10.77 8.07 15.61 3 18.129" />
                    </svg>
                  </div>
                  <h4 className="text-gray-900 font-bold text-lg mb-2">Ready for Translation</h4>
                  <p className="max-w-xs">Enter text or upload a file on the left to see your localized Dari translation here.</p>
                </div>
              )
            )}

            {state.loading && (
              <div className="h-full min-h-[400px] flex flex-col items-center justify-center space-y-4">
                <div className="relative">
                  <div className="w-16 h-16 border-4 border-emerald-200 border-t-emerald-600 rounded-full animate-spin"></div>
                  <div className="absolute inset-0 flex items-center justify-center">
                    <span className="w-2 h-2 bg-emerald-600 rounded-full animate-pulse"></span>
                  </div>
                </div>
                <div className="text-center">
                  <p className="text-gray-900 font-bold">Bridging Languages</p>
                  <p className="text-gray-400 text-sm italic">Analyzing linguistic nuances...</p>
                </div>
              </div>
            )}
          </div>
        </div>
      </main>

      <footer className="bg-white border-t border-gray-100 py-8 mt-auto">
        <div className="max-w-5xl mx-auto px-4 text-center">
          <p className="text-gray-400 text-xs">
            © {new Date().getFullYear()} Dari Native Bridge. Specialized for Afghan Persian (Dari) Localization.
          </p>
          <p className="text-gray-400 text-[10px] mt-2 italic">
            Note: This tool uses advanced AI models to ensure native authenticity and regional accuracy.
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

