  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      const chunks: Blob[] = [];

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunks.push(e.data);
      };

      recorder.onstop = () => {
        const blob = new Blob(chunks, { type: 'audio/webm' });
        const recordedFile = new File([blob], `recording_${new Date().getTime()}.webm`, { type: 'audio/webm' });
        setFile(recordedFile);
        stream.getTracks().forEach(track => track.stop());
        if (timerRef.current) clearInterval(timerRef.current);
        setRecordingTime(0);
      };

      mediaRecorderRef.current = recorder;
      recorder.start();
      setIsRecording(true);

      setRecordingTime(0);
      timerRef.current = window.setInterval(() => {
        setRecordingTime(prev => prev + 1);
      }, 1000);

    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Could not access microphone. Please check permissions.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
      <div className="flex border-b border-gray-100 bg-gray-50/50">
        <button
          type="button"
          onClick={() => { setMode(TranslationMode.TEXT); setIsRecording(false); }}
          className={`flex-1 py-3 text-sm font-semibold transition-colors ${mode === TranslationMode.TEXT ? 'text-emerald-600 bg-white' : 'text-gray-500 hover:text-gray-700'}`}
        >
          Text
        </button>
        <button
          type="button"
          onClick={() => { setMode(TranslationMode.IMAGE); setIsRecording(false); }}
          className={`flex-1 py-3 text-sm font-semibold transition-colors ${mode === TranslationMode.IMAGE ? 'text-emerald-600 bg-white' : 'text-gray-500 hover:text-gray-700'}`}
        >
          Image/PDF
        </button>
        <button
          type="button"
          onClick={() => setMode(TranslationMode.AUDIO)}
          className={`flex-1 py-3 text-sm font-semibold transition-colors ${mode === TranslationMode.AUDIO ? 'text-emerald-600 bg-white' : 'text-gray-500 hover:text-gray-700'}`}
        >
          Audio/Video
        </button>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-4">
        {/* Tone Selector */}
        <div className="flex items-center space-x-2 bg-gray-100 p-1 rounded-lg w-fit">
          <button
            type="button"
            onClick={() => setTone(TranslationTone.FORMAL)}
            className={`px-4 py-1.5 text-xs font-bold rounded-md transition-all ${tone === TranslationTone.FORMAL ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
          >
            FORMAL
          </button>
          <button
            type="button"
            onClick={() => setTone(TranslationTone.INFORMAL)}
            className={`px-4 py-1.5 text-xs font-bold rounded-md transition-all ${tone === TranslationTone.INFORMAL ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
          >
            INFORMAL
          </button>
        </div>

        {mode === TranslationMode.TEXT ? (
          <textarea
            className="w-full h-40 p-4 text-lg border border-gray-200 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all resize-none"
            placeholder="Type or paste your English or Farsi text here..."
            value={text}
            onChange={(e) => setText(e.target.value)}
          />
        ) : (
          <div className="space-y-4">
            <div 
              className={`border-2 border-dashed border-gray-200 rounded-xl p-8 text-center bg-gray-50 hover:bg-gray-100 transition-colors cursor-pointer ${isRecording ? 'opacity-50 cursor-not-allowed' : ''}`} 
              onClick={() => !isRecording && fileInputRef.current?.click()}
            >
              <input
                type="file"
                ref={fileInputRef}
                className="hidden"
                onChange={handleFileChange}
                accept={mode === TranslationMode.IMAGE ? "image/*,application/pdf" : "audio/*,video/*"}
              />
              <div className="flex flex-col items-center">
                <svg className="w-12 h-12 text-gray-400 mb-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                </svg>
                <p className="text-gray-600 font-medium">
                  {file ? file.name : `Click to upload ${mode === TranslationMode.IMAGE ? 'an image or PDF' : 'audio or video'}`}
                </p>
                <p className="text-gray-400 text-sm mt-1">Maximum file size 20MB</p>
              </div>
            </div>

            {mode === TranslationMode.AUDIO && (
              <div className="flex flex-col items-center space-y-3 p-4 bg-emerald-50 rounded-xl border border-emerald-100">
                <div className="flex items-center space-x-4">
                  {!isRecording ? (
                    <button
                      type="button"
                      onClick={startRecording}
                      className="flex items-center space-x-2 bg-emerald-600 text-white px-4 py-2 rounded-lg hover:bg-emerald-700 transition-all shadow-sm font-medium"
                    >
                      <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
                        <path fillRule="evenodd" d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8a1 1 0 10-2 0A5 5 0 015 8a1 1 0 00-2 0 7.001 7.001 0 005.93 6.93V17H6a1 1 0 100 2h8a1 1 0 100-2h-3v-2.07z" clipRule="evenodd" />
                      </svg>
                      <span>Record Audio</span>
                    </button>
                  ) : (
                    <button
                      type="button"
                      onClick={stopRecording}
