const App: React.FC = () => {
  const [state, setState] = useState<ProcessingState>({
    loading: false,
    error: null,
    result: null,
  });

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const result = reader.result as string;
        resolve(result.split(',')[1]);
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleTranslate = async (data: { text?: string; file?: File; mode: TranslationMode; tone: TranslationTone }) => {
    setState(prev => ({ ...prev, loading: true, error: null, result: null }));

    try {
      let result: LocalizationResult;
      if (data.mode === TranslationMode.TEXT && data.text) {
        result = await localizeText(data.text, data.tone);
      } else if (data.file) {
        const base64 = await fileToBase64(data.file);
        const prompt = data.mode === TranslationMode.IMAGE 
          ? "OCR this image or PDF and localize the content into authentic Dari."
          : "Transcribe this audio or video and localize the spoken content into authentic Dari.";

        result = await localizeFile(base64, data.file.type, prompt, data.tone);
      } else {
        throw new Error("No input provided");
      }

      // After translation, generate a visual representation
      if (result.visualPrompt) {
        try {
          const imageUrl = await generateImage(result.visualPrompt);
          result.imageUrl = imageUrl;
        } catch (imageErr) {
          console.error("Image generation failed, continuing without image:", imageErr);
        }
      }

      setState({ loading: false, error: null, result });
    } catch (err: any) {
      console.error(err);
      setState({
        loading: false,
        error: err.message || "An unexpected error occurred during translation.",
        result: null
      });
