import React, { useState, useRef } from 'react';
import { TranslationMode, TranslationTone } from '../types';

interface Props {
  onTranslate: (data: { text?: string; file?: File; mode: TranslationMode; tone: TranslationTone }) => void;
  loading: boolean;
}

const TranslationInput: React.FC<Props> = ({ onTranslate, loading }) => {
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TEXT);
  const [tone, setTone] = useState<TranslationTone>(TranslationTone.FORMAL);
  const [text, setText] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [isRecording, setIsRecording] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerRef = useRef<number | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (mode === TranslationMode.TEXT && text.trim()) {
      onTranslate({ text, mode, tone });
    } else if (file) {
      onTranslate({ file, mode, tone });
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selected = e.target.files?.[0];
    if (selected) {
      setFile(selected);
      setIsRecording(false);
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      const chunks: Blob[] = [];

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunks.push(e.data);
      };

      recorder.onstop = () => {
        const blob = new Blob(chunks, { type: 'audio/webm' });
        const recordedFile = new File([blob], `recording_${new Date().getTime()}.webm`, { type: 'audio/webm' });
        setFile(recordedFile);
        stream.getTracks().forEach(track => track.stop());
        if (timerRef.current) clearInterval(timerRef.current);
        setRecordingTime(0);
      };

      mediaRecorderRef.current = recorder;
      recorder.start();
      setIsRecording(true);

      setRecordingTime(0);
      timerRef.current = window.setInterval(() => {
        setRecordingTime(prev => prev + 1);
      }, 1000);

    } catch (err) {
      console.error("Microphone error:", err);
      alert("Microphone access denied.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl shadow-gray-200/50 border border-gray-100 overflow-hidden">
      <div className="flex p-1.5 bg-gray-50/80 m-2 rounded-2xl border border-gray-100">
        <button
          type="button"
          onClick={() => { setMode(TranslationMode.TEXT); setIsRecording(false); }}
          className={`flex-1 py-2.5 text-sm font-bold rounded-xl transition-all ${mode === TranslationMode.TEXT ? 'text-emerald-700 bg-white shadow-sm' : 'text-gray-400'}`}
        >
          Text
        </button>
        <button
          type="button"
          onClick={() => setMode(TranslationMode.MEDIA)}
          className={`flex-1 py-2.5 text-sm font-bold rounded-xl transition-all ${mode === TranslationMode.MEDIA ? 'text-emerald-700 bg-white shadow-sm' : 'text-gray-400'}`}
        >
          Media
        </button>
      </div>

      <form onSubmit={handleSubmit} className="p-4 sm:p-6 space-y-6">
        <div className="flex items-center justify-center space-x-2 bg-gray-50 p-1 rounded-xl w-full max-w-xs mx-auto border border-gray-100">
          <button
            type="button"
            onClick={() => setTone(TranslationTone.FORMAL)}
            className={`flex-1 py-2 text-[10px] font-black tracking-widest rounded-lg transition-all ${tone === TranslationTone.FORMAL ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-400'}`}
          >
            FORMAL
          </button>
          <button
            type="button"
            onClick={() => setTone(TranslationTone.INFORMAL)}
            className={`flex-1 py-2 text-[10px] font-black tracking-widest rounded-lg transition-all ${tone === TranslationTone.INFORMAL ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-400'}`}
          >
            INFORMAL
          </button>
        </div>

        {mode === TranslationMode.TEXT ? (
          <div className="relative group">
            <textarea
              className="w-full h-48 p-5 text-lg font-medium border-0 bg-gray-50/50 rounded-2xl focus:ring-2 focus:ring-emerald-500/20 outline-none transition-all resize-none placeholder:text-gray-300"
              placeholder="Start typing..."
              value={text}
              onChange={(e) => setText(e.target.value)}
            />
            {text && (
              <button 
                type="button" 
                onClick={() => setText('')}
                className="absolute top-4 right-4 text-gray-300 hover:text-gray-500"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            )}
          </div>
        ) : (
          <div className="space-y-4">
            <div 
              className={`border-2 border-dashed border-gray-200 rounded-3xl p-6 sm:p-10 text-center bg-gray-50/50 hover:bg-emerald-50/30 transition-all cursor-pointer group ${isRecording ? 'opacity-50 pointer-events-none' : ''}`} 
              onClick={() => fileInputRef.current?.click()}
            >
              <input
                type="file"
                ref={fileInputRef}
                className="hidden"
                onChange={handleFileChange}
                accept="image/*,application/pdf,audio/*,video/*"
              />
              <div className="flex flex-col items-center">
                <div className="w-14 h-14 bg-white rounded-2xl shadow-sm border border-gray-100 flex items-center justify-center mb-4 group-hover:scale-110 transition-transform duration-300">
                  <svg className="w-7 h-7 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-8l-4-4m0 0l-4-4m4 4v12" />
                  </svg>
                </div>
                <p className="text-gray-800 font-bold text-sm">
                  {file ? file.name : "Image, PDF, Audio or Video"}
                </p>
                <p className="text-gray-400 text-[10px] mt-1 font-bold uppercase tracking-wider">Tap to upload up to 20MB</p>
              </div>
            </div>

            <div className="relative">
              <div className="absolute inset-0 flex items-center" aria-hidden="true">
                <div className="w-full border-t border-gray-100"></div>
              </div>
              <div className="relative flex justify-center text-xs uppercase font-bold text-gray-300">
                <span className="bg-white px-3">or</span>
              </div>
            </div>

            <div className="flex flex-col items-center space-y-3 p-4 bg-emerald-50/50 rounded-2xl border border-emerald-100/50">
              {!isRecording ? (
                <button
                  type="button"
                  onClick={startRecording}
                  className="w-full flex items-center justify-center space-x-2 bg-emerald-600 text-white py-3.5 rounded-xl hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-200 font-bold text-sm"
                >
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
                    <path fillRule="evenodd" d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8a1 1 0 10-2 0A5 5 0 015 8a1 1 0 00-2 0 7.001 7.001 0 005.93 6.93V17H6a1 1 0 100 2h8a1 1 0 100-2h-3v-2.07z" clipRule="evenodd" />
                  </svg>
                  <span>Voice Record</span>
                </button>
              ) : (
                <button
                  type="button"
                  onClick={stopRecording}
                  className="w-full flex items-center justify-center space-x-2 bg-red-500 text-white py-3.5 rounded-xl animate-pulse font-bold text-sm shadow-lg shadow-red-100"
                >
                  <div className="w-2 h-2 bg-white rounded-full"></div>
                  <span>Stop ({formatTime(recordingTime)})</span>
                </button>
              )}
            </div>
          </div>
        )}

        <button
          type="submit"
          disabled={loading || isRecording || (mode === TranslationMode.TEXT ? !text.trim() : !file)}
          className="w-full bg-gray-900 text-white font-black py-4.5 rounded-2xl hover:bg-black disabled:bg-gray-200 disabled:cursor-not-allowed transition-all shadow-xl shadow-gray-200 active:scale-[0.97] flex items-center justify-center space-x-3"
        >
          {loading ? (
            <div className="flex items-center space-x-2">
              <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
              <span className="text-sm uppercase tracking-widest">Processing</span>
            </div>
          ) : (
            <span className="text-sm uppercase tracking-widest font-black">Bridge to Dari</span>
          )}
        </button>
      </form>
    </div>
  );
};

