import React, { useState, useRef } from 'react';
import { LocalizationResult } from '../types';
import { generateSpeech, decodeBase64, decodePCM } from '../services/geminiService';

interface Props {
  result: LocalizationResult;
}

const ResultView: React.FC<Props> = ({ result }) => {
  const [playingVoice, setPlayingVoice] = useState<'Puck' | 'Kore' | null>(null);
  const [isDownloading, setIsDownloading] = useState<'Puck' | 'Kore' | null>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);

  const handlePlayVoice = async (voiceName: 'Puck' | 'Kore') => {
    if (playingVoice) return;

    try {
      setPlayingVoice(voiceName);
      const base64 = await generateSpeech(result.dariTranslation, voiceName);

      if (!audioCtxRef.current) {
        audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const ctx = audioCtxRef.current;
      if (ctx.state === 'suspended') await ctx.resume();

      const audioData = decodeBase64(base64);
      const audioBuffer = await decodePCM(audioData, ctx);

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.onended = () => setPlayingVoice(null);
      source.start(0);
    } catch (error) {
      console.error("Speech error:", error);
      setPlayingVoice(null);
    }
  };

  const handleDownloadVoice = async (voiceName: 'Puck' | 'Kore') => {
    if (isDownloading) return;
    try {
      setIsDownloading(voiceName);
      const base64 = await generateSpeech(result.dariTranslation, voiceName);
      const audioData = decodeBase64(base64);
      const blob = new Blob([audioData], { type: 'audio/pcm' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `dari_${voiceName.toLowerCase()}.pcm`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } finally {
      setIsDownloading(null);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-6 duration-700">
      <div className="bg-white rounded-[2rem] shadow-2xl shadow-gray-200/50 border border-gray-100 overflow-hidden">

        {result.imageUrl && (
          <div className="w-full aspect-square sm:aspect-video overflow-hidden group">
            <img 
              src={result.imageUrl} 
              alt="Visual concept" 
              className="w-full h-full object-cover transition-transform duration-[2000ms] group-hover:scale-110"
            />
          </div>
        )}

        <div className="p-5 sm:p-8 space-y-8">
          <section className="space-y-4">
            <div className="flex items-center justify-between">
              <span className="text-[10px] font-black uppercase tracking-widest text-emerald-600 bg-emerald-50 px-3 py-1.5 rounded-full">Authentic Dari</span>

              <div className="flex items-center space-x-2">
                <button
                  onClick={() => handlePlayVoice('Puck')}
                  disabled={!!playingVoice}
                  className={`w-9 h-9 flex items-center justify-center rounded-full transition-all ${playingVoice === 'Puck' ? 'bg-blue-600 text-white animate-pulse' : 'bg-blue-50 text-blue-600 hover:bg-blue-100'}`}
                >
                   <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                </button>
                <button
                  onClick={() => handlePlayVoice('Kore')}
                  disabled={!!playingVoice}
                  className={`w-9 h-9 flex items-center justify-center rounded-full transition-all ${playingVoice === 'Kore' ? 'bg-emerald-600 text-white animate-pulse' : 'bg-emerald-50 text-emerald-600 hover:bg-emerald-100'}`}
                >
                   <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" /></svg>
                </button>
                <button 
                  onClick={() => navigator.clipboard.writeText(result.dariTranslation)}
                  className="w-9 h-9 flex items-center justify-center rounded-full bg-gray-50 text-gray-400 hover:text-gray-900 transition-colors"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" /></svg>
                </button>
