import React, { useState, useRef } from 'react';
import { TranslationMode, TranslationTone } from '../types';

interface Props {
  onTranslate: (data: { text?: string; file?: File; mode: TranslationMode; tone: TranslationTone }) => void;
  loading: boolean;
}

const TranslationInput: React.FC<Props> = ({ onTranslate, loading }) => {
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TEXT);
  const [tone, setTone] = useState<TranslationTone>(TranslationTone.FORMAL);
  const [text, setText] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [isRecording, setIsRecording] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerRef = useRef<number | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (mode === TranslationMode.TEXT && text.trim()) {
      onTranslate({ text, mode, tone });
    } else if (file) {
      onTranslate({ file, mode, tone });
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selected = e.target.files?.[0];
    if (selected) {
      setFile(selected);
      setIsRecording(false);
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      const chunks: Blob[] = [];

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunks.push(e.data);
      };

      recorder.onstop = () => {
        const blob = new Blob(chunks, { type: 'audio/webm' });
        const recordedFile = new File([blob], `recording_${new Date().getTime()}.webm`, { type: 'audio/webm' });
        setFile(recordedFile);
        stream.getTracks().forEach(track => track.stop());
        if (timerRef.current) clearInterval(timerRef.current);
        setRecordingTime(0);
      };

      mediaRecorderRef.current = recorder;
      recorder.start();
      setIsRecording(true);

      setRecordingTime(0);
      timerRef.current = window.setInterval(() => {
        setRecordingTime(prev => prev + 1);
      }, 1000);

    } catch (err) {
      console.error("Microphone error:", err);
      alert("Microphone access denied.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Unified Vector Icon for Image, PDF, Audio, and Video
  const MediaVector = () => (
    <svg className="w-16 h-16 text-emerald-500" viewBox="0 0 64 64" fill="none" xmlns="http://www.w3.org/2000/svg">
      {/* Background shape */}
      <rect x="12" y="8" width="40" height="48" rx="8" className="fill-emerald-50 stroke-emerald-100" strokeWidth="2" />
      {/* Image Symbol */}
      <path d="M20 32L26 26L32 32L40 24L44 28" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" />
      <circle cx="24" cy="22" r="3" stroke="currentColor" strokeWidth="2" />
      {/* Play/Video/Audio Symbol Overlay */}
      <circle cx="44" cy="44" r="10" className="fill-white stroke-emerald-500 shadow-sm" strokeWidth="2" />
      <path d="M42 40L48 44L42 48V40Z" fill="currentColor" />
      {/* Document/PDF Corner */}
      <path d="M44 8V16H52" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );

  return (
    <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-gray-200/50 border border-gray-100 overflow-hidden transition-all duration-300">
      {/* Mode Toggle */}
      <div className="flex p-2 bg-gray-50/80 m-3 rounded-[1.75rem] border border-gray-100">
        <button
          type="button"
          onClick={() => { setMode(TranslationMode.TEXT); setIsRecording(false); }}
          className={`flex-1 py-3 text-sm font-black rounded-2xl transition-all duration-300 ${mode === TranslationMode.TEXT ? 'text-emerald-700 bg-white shadow-md' : 'text-gray-400 hover:text-gray-500'}`}
        >
          TEXT
        </button>
        <button
          type="button"
          onClick={() => setMode(TranslationMode.MEDIA)}
          className={`flex-1 py-3 text-sm font-black rounded-2xl transition-all duration-300 ${mode === TranslationMode.MEDIA ? 'text-emerald-700 bg-white shadow-md' : 'text-gray-400 hover:text-gray-500'}`}
        >
          MEDIA
        </button>
      </div>

      <form onSubmit={handleSubmit} className="px-5 pb-6 sm:px-8 sm:pb-8 space-y-6">
        {/* Tone Picker */}
        <div className="flex items-center justify-center space-x-1 bg-gray-50 p-1 rounded-2xl w-full max-w-[240px] mx-auto border border-gray-100">
          <button
            type="button"
            onClick={() => setTone(TranslationTone.FORMAL)}
            className={`flex-1 py-2 text-[10px] font-black tracking-widest rounded-xl transition-all ${tone === TranslationTone.FORMAL ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-400'}`}
          >
            FORMAL
          </button>
          <button
            type="button"
            onClick={() => setTone(TranslationTone.INFORMAL)}
            className={`flex-1 py-2 text-[10px] font-black tracking-widest rounded-xl transition-all ${tone === TranslationTone.INFORMAL ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-400'}`}
          >
            INFORMAL
          </button>
        </div>

        {mode === TranslationMode.TEXT ? (
          <div className="relative">
            <textarea
              className="w-full h-56 p-6 text-xl font-medium border-0 bg-gray-50/40 rounded-[2rem] focus:ring-4 focus:ring-emerald-500/5 outline-none transition-all resize-none placeholder:text-gray-300 placeholder:font-bold leading-relaxed"
              placeholder="What would you like to bridge?"
              value={text}
              onChange={(e) => setText(e.target.value)}
            />
            {text && (
              <button 
                type="button" 
                onClick={() => setText('')}
                className="absolute top-5 right-5 w-8 h-8 flex items-center justify-center bg-white rounded-full shadow-sm text-gray-300 hover:text-red-500 transition-colors"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            )}
          </div>
        ) : (
          <div className="space-y-5">
            {/* Unified Media Dropzone */}
            <div 
              className={`relative border-2 border-dashed rounded-[2.5rem] p-8 sm:p-12 text-center bg-gray-50/30 hover:bg-emerald-50/20 transition-all cursor-pointer group active:scale-[0.98] ${file ? 'border-emerald-200' : 'border-gray-200'} ${isRecording ? 'opacity-50 pointer-events-none' : ''}`} 
              onClick={() => fileInputRef.current?.click()}
            >
              <input
                type="file"
                ref={fileInputRef}
                className="hidden"
                onChange={handleFileChange}
                accept="image/*,application/pdf,audio/*,video/*"
              />
              <div className="flex flex-col items-center">
                <div className="mb-6 group-hover:scale-110 transition-transform duration-500 ease-out">
                  <MediaVector />
                </div>
                <h3 className="text-gray-900 font-black text-sm uppercase tracking-wider">
                  {file ? file.name : "Process Any Media"}
                </h3>
                <p className="text-gray-400 text-[10px] mt-2 font-black uppercase tracking-[0.2em]">Images • PDF • Audio • Video</p>

                {file && (
                   <div className="mt-4 px-4 py-1.5 bg-emerald-100 text-emerald-700 text-[10px] font-black rounded-full uppercase tracking-widest">
                     Ready for bridge
                   </div>
                )}
              </div>
            </div>

            <div className="flex items-center py-2">
              <div className="flex-1 h-[1px] bg-gray-100"></div>
              <span className="px-4 text-[10px] font-black text-gray-300 uppercase tracking-widest">or record voice</span>
              <div className="flex-1 h-[1px] bg-gray-100"></div>
            </div>

            {/* Voice Control */}
            <div className="p-2 bg-gray-50/50 rounded-3xl border border-gray-100/50">
              {!isRecording ? (
                <button
                  type="button"
                  onClick={startRecording}
                  className="w-full flex items-center justify-center space-x-3 bg-emerald-600 text-white py-4 rounded-2xl hover:bg-emerald-700 transition-all shadow-xl shadow-emerald-200/50 font-black text-xs uppercase tracking-widest"
                >
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
                    <path fillRule="evenodd" d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8a1 1 0 10-2 0A5 5 0 015 8a1 1 0 00-2 0 7.001 7.001 0 005.93 6.93V17H6a1 1 0 100 2h8a1 1 0 100-2h-3v-2.07z" clipRule="evenodd" />
                  </svg>
                  <span>Native Capture</span>
                </button>
              ) : (
                <button
                  type="button"
                  onClick={stopRecording}
                  className="w-full flex items-center justify-center space-x-3 bg-red-500 text-white py-4 rounded-2xl animate-pulse font-black text-xs uppercase tracking-widest shadow-xl shadow-red-200/50"
                >
                  <div className="w-3 h-3 bg-white rounded-full"></div>
                  <span>Recording {formatTime(recordingTime)}</span>
                </button>
              )}
            </div>
          </div>
        )}

        <button
          type="submit"
          disabled={loading || isRecording || (mode === TranslationMode.TEXT ? !text.trim() : !file)}
          className="w-full bg-gray-900 text-white font-black py-5 rounded-[1.75rem] hover:bg-black disabled:bg-gray-100 disabled:text-gray-300 disabled:cursor-not-allowed transition-all shadow-2xl shadow-gray-300/50 active:scale-[0.98] flex items-center justify-center"
        >
          {loading ? (
            <div className="flex items-center space-x-3">
              <div className="w-5 h-5 border-[3px] border-white/20 border-t-white rounded-full animate-spin"></div>
              <span className="text-xs uppercase tracking-[0.2em]">Synthesizing...</span>
            </div>
          ) : (
            <div className="flex items-center space-x-2">
              <span className="text-xs uppercase tracking-[0.3em]">Build Bridge</span>
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
            </div>
          )}
        </button>
      </form>
    </div>
  );
};

