}

import React, { useState } from 'react';
import Header from './components/Header';
import TranslationInput from './components/TranslationInput';
import ResultView from './components/ResultView';
import { TranslationMode, TranslationTone, ProcessingState, LocalizationResult } from './types';
import { localizeText, localizeFile, generateImage } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<ProcessingState>({
    loading: false,
    step: 'NONE',
    error: null,
    result: null,
  });

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const result = reader.result as string;
        resolve(result.split(',')[1]);
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleTranslate = async (data: { text?: string; file?: File; mode: TranslationMode; tone: TranslationTone }) => {
    setState({ loading: true, step: 'LOCALIZING', error: null, result: null });

    try {
      let result: LocalizationResult;
      if (data.mode === TranslationMode.TEXT && data.text) {
        result = await localizeText(data.text, data.tone);
      } else if (data.file) {
        const base64 = await fileToBase64(data.file);
        const isVisual = data.file.type.startsWith('image/') || data.file.type === 'application/pdf';
        const prompt = isVisual 
          ? "OCR this document and localize the content into authentic native Dari."
          : "Transcribe this media and localize the spoken content into authentic native Dari.";

        result = await localizeFile(base64, data.file.type, prompt, data.tone);
      } else {
        throw new Error("Missing input data");
      }

      // First, show the text results to the user
      setState({ loading: false, step: 'NONE', error: null, result });

      // Smooth scroll to result on mobile as soon as text is ready
      setTimeout(() => {
        window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
      }, 100);

      // We handle image generation within the ResultView now to provide a 
      // specific loading experience for the visual part.
    } catch (err: any) {
      console.error(err);
      setState({
        loading: false,
        step: 'NONE',
        error: err.message || "Linguistic bridge failed. Please try again.",
        result: null
      });
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header />

      <main className="flex-grow max-w-5xl mx-auto px-4 sm:px-6 py-6 w-full space-y-8">
        <section className="text-center space-y-2 mt-4">
          <h2 className="text-2xl sm:text-4xl font-black text-gray-900 tracking-tight px-4">
            Bridge to Authentic Dari
          </h2>
          <p className="text-gray-400 text-sm sm:text-base font-medium max-w-xl mx-auto px-6">
            Localized linguistics for Afghan Persian (Dari) with cultural nuances.
          </p>
        </section>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-start">
          <div className="space-y-6">
            <TranslationInput onTranslate={handleTranslate} loading={state.loading} />

            <div className="hidden lg:block bg-emerald-50 rounded-3xl p-6 border border-emerald-100">
              <h3 className="text-emerald-800 font-black text-xs uppercase tracking-widest mb-4 flex items-center">
                <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
                </svg>
                Linguistic Fidelity
              </h3>
              <ul className="text-sm text-emerald-700 space-y-3 font-medium">
                <li className="flex items-center"><span className="w-1.5 h-1.5 rounded-full bg-emerald-400 mr-3 shrink-0"></span>Native Dari terminology preservation</li>
                <li className="flex items-center"><span className="w-1.5 h-1.5 rounded-full bg-emerald-400 mr-3 shrink-0"></span>Afghan politeness registers</li>
                <li className="flex items-center"><span className="w-1.5 h-1.5 rounded-full bg-emerald-400 mr-3 shrink-0"></span>Multimodal media support</li>
              </ul>
            </div>
          </div>

          <div className="space-y-6 pb-12">
            {state.error && (
              <div className="bg-red-50 border border-red-100 text-red-600 p-4 rounded-2xl flex items-center space-x-3 animate-in fade-in zoom-in duration-300">
                <svg className="w-5 h-5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                <p className="text-xs font-black uppercase tracking-wider">{state.error}</p>
              </div>
            )}

            {state.result ? (
              <ResultView result={state.result} />
            ) : (
              !state.loading && (
                <div className="h-full min-h-[300px] flex flex-col items-center justify-center bg-white border border-gray-100 rounded-3xl text-gray-300 p-8 text-center shadow-sm">
                  <div className="bg-gray-50 p-6 rounded-full mb-6">
                    <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" />
                    </svg>
                  </div>
                  <h4 className="text-gray-900 font-bold text-lg mb-2">Bridge Inactive</h4>
