export default App;

import React, { useState, useRef, useEffect } from 'react';
import { LocalizationResult } from '../types';
import { generateSpeech, decodeBase64, decodePCM, generateImage } from '../services/geminiService';

interface Props {
  result: LocalizationResult;
}

type AudioFormat = 'WAV' | 'PCM';

const ResultView: React.FC<Props> = ({ result: initialResult }) => {
  const [result, setResult] = useState<LocalizationResult>(initialResult);
  const [playingVoice, setPlayingVoice] = useState<'Puck' | 'Kore' | null>(null);
  const [isDownloading, setIsDownloading] = useState<'Puck' | 'Kore' | null>(null);
  const [showDownloadDialog, setShowDownloadDialog] = useState<'Puck' | 'Kore' | null>(null);
  const [downloadFilename, setDownloadFilename] = useState('');
  const [selectedFormat, setSelectedFormat] = useState<AudioFormat>('WAV');
  const [imageLoading, setImageLoading] = useState(false);
  const [imageProgress, setImageProgress] = useState(0);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const progressIntervalRef = useRef<number | null>(null);

  useEffect(() => {
    // If we have a prompt but no image yet, generate it.
    if (result.visualPrompt && !result.imageUrl && !imageLoading) {
      handleGenerateImage(result.visualPrompt);
    }
  }, [result.visualPrompt]);

  const handleGenerateImage = async (prompt: string) => {
    setImageLoading(true);
    setImageProgress(0);

    // Simulated progress bar while waiting for the API
    // It will intelligently climb to 95% and wait for the finish
    progressIntervalRef.current = window.setInterval(() => {
      setImageProgress(prev => {
        if (prev < 30) return prev + 1.5;
        if (prev < 60) return prev + 0.8;
        if (prev < 90) return prev + 0.3;
        if (prev < 98) return prev + 0.05;
        return prev;
      });
    }, 100);

    try {
      const imageUrl = await generateImage(prompt);
      setImageProgress(100);

      // Short delay for the 100% to be visible before showing image
      setTimeout(() => {
        setResult(prev => ({ ...prev, imageUrl }));
        setImageLoading(false);
      }, 500);
    } catch (err) {
      console.error("Image generation failed:", err);
      setImageLoading(false);
    } finally {
      if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
    }
  };

  const handlePlayVoice = async (voiceName: 'Puck' | 'Kore') => {
    if (playingVoice) return;

    try {
      setPlayingVoice(voiceName);
      const base64 = await generateSpeech(result.dariTranslation, voiceName);

      if (!audioCtxRef.current) {
        audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const ctx = audioCtxRef.current;
      if (ctx.state === 'suspended') await ctx.resume();

      const audioData = decodeBase64(base64);
      const audioBuffer = await decodePCM(audioData, ctx);

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.onended = () => setPlayingVoice(null);
      source.start(0);
    } catch (error) {
      console.error("Speech error:", error);
      setPlayingVoice(null);
    }
  };

  const createWavFile = (pcmData: Uint8Array): Blob => {
    const sampleRate = 24000;
    const numChannels = 1;
    const bitsPerSample = 16;
    const byteRate = (sampleRate * numChannels * bitsPerSample) / 8;
    const blockAlign = (numChannels * bitsPerSample) / 8;
    const dataSize = pcmData.length;
    const headerSize = 44;
    const totalSize = headerSize + dataSize;

    const buffer = new ArrayBuffer(headerSize);
    const view = new DataView(buffer);

    // RIFF identifier
    view.setUint32(0, 0x52494646, false); // "RIFF"
    view.setUint32(4, totalSize - 8, true);
    view.setUint32(8, 0x57415645, false); // "WAVE"

    // fmt chunk
    view.setUint32(12, 0x666d7420, false); // "fmt "
    view.setUint32(16, 16, true); // chunk size
    view.setUint16(20, 1, true); // PCM format
    view.setUint16(22, numChannels, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, byteRate, true);
    view.setUint16(32, blockAlign, true);
    view.setUint16(34, bitsPerSample, true);

    // data chunk
    view.setUint32(36, 0x64617461, false); // "data"
    view.setUint32(40, dataSize, true);

    return new Blob([buffer, pcmData], { type: 'audio/wav' });
  };

  const handleDownloadVoice = async () => {
    if (!showDownloadDialog || isDownloading) return;

    const voiceName = showDownloadDialog;
    try {
      setIsDownloading(voiceName);
      const base64 = await generateSpeech(result.dariTranslation, voiceName);
      const audioData = decodeBase64(base64);

      let blob: Blob;
      if (selectedFormat === 'WAV') {
        blob = createWavFile(audioData);
      } else {
        blob = new Blob([audioData], { type: 'audio/pcm' });
      }

      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;

      const ext = selectedFormat.toLowerCase();
      const finalFilename = (downloadFilename.trim() || `dari_${voiceName.toLowerCase()}`) + `.${ext}`;

      link.download = finalFilename;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
      setShowDownloadDialog(null);
    } catch (err) {
      console.error("Download failed", err);
    } finally {
      setIsDownloading(null);
    }
  };

  const openDownloadDialog = (voiceName: 'Puck' | 'Kore') => {
    setShowDownloadDialog(voiceName);
    setDownloadFilename(`dari_${voiceName.toLowerCase()}_${new Date().getTime()}`);
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-8 duration-700">
      <div className="bg-white rounded-[3rem] shadow-2xl shadow-gray-200/50 border border-gray-100 overflow-hidden relative">

        {/* Download Dialog Overlay */}
        {showDownloadDialog && (
          <div className="absolute inset-0 z-50 bg-white/95 backdrop-blur-sm flex items-center justify-center p-6">
            <div className="w-full max-w-sm space-y-6 animate-in zoom-in-95 duration-200">
              <div className="text-center space-y-2">
                <h3 className="text-lg font-black uppercase tracking-widest text-gray-900">Download Settings</h3>
                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Configure your {showDownloadDialog} voice file</p>
              </div>

              <div className="space-y-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase tracking-widest text-gray-400 ml-2">Filename</label>
                  <input 
                    type="text" 
                    value={downloadFilename}
                    onChange={(e) => setDownloadFilename(e.target.value)}
                    className="w-full bg-gray-50 border border-gray-100 rounded-2xl px-5 py-3 text-sm font-bold focus:ring-4 focus:ring-emerald-500/5 outline-none"
                    placeholder="Enter filename..."
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase tracking-widest text-gray-400 ml-2">Audio Format</label>
                  <div className="flex p-1 bg-gray-50 rounded-2xl border border-gray-100">
                    <button 
                      onClick={() => setSelectedFormat('WAV')}
                      className={`flex-1 py-2 text-xs font-black rounded-xl transition-all ${selectedFormat === 'WAV' ? 'bg-white shadow-sm text-emerald-600' : 'text-gray-400'}`}
                    >
                      WAV (Compatible)
                    </button>
                    <button 
                      onClick={() => setSelectedFormat('PCM')}
                      className={`flex-1 py-2 text-xs font-black rounded-xl transition-all ${selectedFormat === 'PCM' ? 'bg-white shadow-sm text-emerald-600' : 'text-gray-400'}`}
                    >
                      PCM (Raw)
                    </button>
                  </div>
                </div>
              </div>

              <div className="flex space-x-3 pt-2">
                <button 
                  onClick={() => setShowDownloadDialog(null)}
                  className="flex-1 py-4 rounded-2xl bg-gray-50 text-gray-400 font-black text-[10px] uppercase tracking-widest hover:bg-gray-100 transition-colors"
                >
                  Cancel
                </button>
                <button 
                  onClick={handleDownloadVoice}
                  disabled={!!isDownloading}
                  className="flex-2 grow-[2] py-4 rounded-2xl bg-emerald-600 text-white font-black text-[10px] uppercase tracking-widest hover:bg-emerald-700 shadow-xl shadow-emerald-200 flex items-center justify-center space-x-2"
                >
                  {isDownloading ? (
                    <>
                      <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                      <span>Building...</span>
                    </>
                  ) : (
                    <>
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                      <span>Download</span>
                    </>
                  )}
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Improved Image Loading Experience */}
        <div className="relative w-full aspect-[4/3] sm:aspect-video overflow-hidden group bg-gray-100">
          {imageLoading && (
            <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-gray-50 space-y-4 px-10">
              <div className="w-full h-1.5 bg-gray-200 rounded-full overflow-hidden shadow-inner max-w-xs">
                <div 
                  className="h-full bg-emerald-600 transition-all duration-300 ease-out shadow-[0_0_12px_rgba(5,150,105,0.4)]"
                  style={{ width: `${imageProgress}%` }}
                ></div>
              </div>
              <div className="flex flex-col items-center space-y-1">
                <span className="text-[10px] font-black uppercase tracking-[0.3em] text-emerald-600">Generating Context</span>
                <span className="text-[18px] font-black text-gray-900">{Math.round(imageProgress)}%</span>
              </div>
            </div>
          )}

          {result.imageUrl && (
            <img 
              src={result.imageUrl} 
              alt="Visual Context" 
              className={`w-full h-full object-cover transition-all duration-[2000ms] group-hover:scale-105 ${imageLoading ? 'opacity-0' : 'opacity-100'}`}
            />
          )}

          <div className="absolute inset-0 bg-gradient-to-t from-white via-transparent to-transparent opacity-60"></div>
        </div>

        <div className="p-6 sm:p-10 space-y-10">
          <section className="space-y-6">
            <div className="flex items-center justify-between">
              <span className="text-[10px] font-black uppercase tracking-[0.2em] text-emerald-600 bg-emerald-50 px-4 py-2 rounded-full border border-emerald-100/50">
                Native Localization
              </span>

              <div className="flex items-center space-x-3">
                <button
                  onClick={() => handlePlayVoice('Puck')}
                  disabled={!!playingVoice}
                  className={`w-11 h-11 flex items-center justify-center rounded-2xl transition-all shadow-sm ${playingVoice === 'Puck' ? 'bg-blue-600 text-white animate-pulse' : 'bg-blue-50 text-blue-600 hover:bg-blue-100 active:scale-90'}`}
                  title="Listen (Male)"
                >
                   <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                </button>
                <button
                  onClick={() => handlePlayVoice('Kore')}
                  disabled={!!playingVoice}
                  className={`w-11 h-11 flex items-center justify-center rounded-2xl transition-all shadow-sm ${playingVoice === 'Kore' ? 'bg-emerald-600 text-white animate-pulse' : 'bg-emerald-50 text-emerald-600 hover:bg-emerald-100 active:scale-90'}`}
                  title="Listen (Female)"
                >
                   <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" /></svg>
                </button>
                <button 
                  onClick={() => navigator.clipboard.writeText(result.dariTranslation)}
                  className="w-11 h-11 flex items-center justify-center rounded-2xl bg-gray-50 text-gray-400 hover:text-gray-900 transition-all active:scale-90"
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" /></svg>
                </button>
              </div>
            </div>

            <div className="bg-gray-50/50 rounded-[2.5rem] p-8 sm:p-12 border border-gray-100/50">
              <p className="text-4xl sm:text-5xl font-dari text-right leading-[1.7] text-gray-900" dir="rtl">
                {result.dariTranslation}
              </p>
            </div>
          </section>

          {/* Voice Grid */}
          <section className="grid grid-cols-2 gap-4">
            <button 
              onClick={() => openDownloadDialog('Puck')}
              disabled={!!isDownloading}
              className="group p-5 rounded-3xl bg-white border border-gray-100 hover:border-blue-100 hover:bg-blue-50/20 transition-all text-left relative overflow-hidden active:scale-95"
            >
              <div className="relative z-10 flex flex-col items-center">
                <div className="w-10 h-10 rounded-full bg-blue-50 text-blue-600 flex items-center justify-center font-black text-xs mb-3 group-hover:scale-110 transition-transform">M</div>
                <span className="text-[10px] font-black uppercase tracking-widest text-gray-400 group-hover:text-blue-600">Download Male</span>
              </div>
              {isDownloading === 'Puck' && (
                <div className="absolute inset-0 bg-white/80 flex items-center justify-center">
                  <div className="w-5 h-5 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                </div>
              )}
            </button>

            <button 
              onClick={() => openDownloadDialog('Kore')}
              disabled={!!isDownloading}
              className="group p-5 rounded-3xl bg-white border border-gray-100 hover:border-emerald-100 hover:bg-emerald-50/20 transition-all text-left relative overflow-hidden active:scale-95"
            >
              <div className="relative z-10 flex flex-col items-center">
                <div className="w-10 h-10 rounded-full bg-emerald-50 text-emerald-600 flex items-center justify-center font-black text-xs mb-3 group-hover:scale-110 transition-transform">F</div>
                <span className="text-[10px] font-black uppercase tracking-widest text-gray-400 group-hover:text-emerald-600">Download Female</span>
              </div>
              {isDownloading === 'Kore' && (
                <div className="absolute inset-0 bg-white/80 flex items-center justify-center">
                  <div className="w-5 h-5 border-2 border-emerald-600 border-t-transparent rounded-full animate-spin"></div>
                </div>
