              <span className="text-[10px] font-black uppercase tracking-[0.3em] text-gray-400">Linguistic Nuances</span>
            </div>
            <div className="grid gap-4">
              {result.localizationNotes.map((note, i) => (
                <div key={i} className="flex items-start space-x-5 p-5 bg-white border border-gray-50 rounded-[1.75rem] shadow-sm hover:shadow-md transition-shadow">
                  <span className="flex-shrink-0 w-8 h-8 rounded-full bg-emerald-50 text-emerald-600 flex items-center justify-center font-black text-[10px]">
                    {i+1}
                  </span>
                  <p className="text-sm font-bold text-gray-600 leading-relaxed pt-1.5">{note}</p>
                </div>
              ))}
            </div>
          </section>
        </div>

        {/* Footer Status */}
        <div className="bg-gray-900 px-8 py-6 flex justify-between items-center">
          <div className="flex flex-col">
            <span className="text-[8px] font-black uppercase tracking-[0.4em] text-emerald-500 mb-1">Bridge Security</span>
