import { GoogleGenAI, Type, Modality } from "@google/genai";
import { LocalizationResult, TranslationTone } from "../types";

const SYSTEM_INSTRUCTION = `
You are the "Dari Native Bridge," a specialized linguistic AI expert. Your primary goal is to localize and translate Iranian Persian (Farsi) and English into authentic, native Dari (Afghan Persian). 
You prioritize "Dari-first" vocabulary, avoiding Iranian-specific neologisms or overly Westernized terms when a native Dari equivalent exists.

Linguistic Rules:
1. Vocabulary: Replace Iranian terms (e.g., Daneshgah) with Dari equivalents (e.g., Pohantun). Use Pashto-influenced Dari where appropriate for local flavor.
2. Formal vs. Informal: Strictly follow the requested tone. Use Afghan politeness registers (e.g., "Shoma" vs. "Tu" in an Afghan context) and appropriate verb endings.
3. Grammar: Adjust syntax to match Afghan speech patterns (e.g., specific verb endings and prepositions common in Kabul, Herat, or Mazar-i-Sharif).

Output format MUST be a JSON object:
{
  "sourceLanguage": "English" | "Farsi",
  "dariTranslation": "The Dari text in Persian alphabet",
  "transliteration": "Latin script transliteration for pronunciation",
  "localizationNotes": ["Array of strings explaining specific word choices"],
  "visualPrompt": "A short, descriptive English prompt for an AI image generator that visually represents the core subject of the translated text. Keep it neutral and descriptive."
}
`;

/**
 * Helper to handle API retries for transient errors (like 429)
 */
async function withRetry<T>(fn: () => Promise<T>, retries = 2, delay = 1000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const isRateLimit = error?.message?.includes('429') || error?.status === 429 || error?.message?.includes('RESOURCE_EXHAUSTED');
    if (isRateLimit && retries > 0) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

export const localizeText = async (text: string, tone: TranslationTone): Promise<LocalizationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Translate and localize the following text to authentic Dari using a ${tone.toLowerCase()} tone: "${text}"`,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sourceLanguage: { type: Type.STRING },
            dariTranslation: { type: Type.STRING },
            transliteration: { type: Type.STRING },
            localizationNotes: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            visualPrompt: { type: Type.STRING }
          },
          required: ["sourceLanguage", "dariTranslation", "localizationNotes", "visualPrompt"]
        }
      }
    });
    return JSON.parse(response.text || '{}');
  });
};

export const localizeFile = async (base64: string, mimeType: string, prompt: string, tone: TranslationTone): Promise<LocalizationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [
        {
          inlineData: {
            data: base64,
            mimeType: mimeType,
          },
        },
        { text: `${prompt} Use a ${tone.toLowerCase()} tone for the translation.` },
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sourceLanguage: { type: Type.STRING },
            dariTranslation: { type: Type.STRING },
            transliteration: { type: Type.STRING },
            localizationNotes: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            visualPrompt: { type: Type.STRING }
          },
          required: ["sourceLanguage", "dariTranslation", "localizationNotes", "visualPrompt"]
        }
      }
    });
    return JSON.parse(response.text || '{}');
  });
};

export const generateImage = async (visualPrompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            text: `A clear, high-quality visual representation of: ${visualPrompt}. High resolution, professional photography or digital art style, neutral background.`,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      },
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("Failed to generate image");
  });
};

export const generateSpeech = async (text: string, voiceName: 'Puck' | 'Kore'): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  // Sanitize text for TTS: remove special characters that might trigger finishReason OTHER
  const sanitizedText = text.replace(/[^\u0600-\u06FF\s0-9a-zA-Z]/g, ' ').trim();

  if (!sanitizedText) throw new Error("Text is empty after sanitization.");

  const prompt = `Please say the following text in a natural Afghan Dari accent: ${sanitizedText}`;

  return withRetry(async () => {
    try {
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: prompt }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName },
            },
          },
        },
      });

      const candidate = response.candidates?.[0];
      if (!candidate?.content?.parts) {
        const finishReason = candidate?.finishReason;
        if (finishReason === 'RECITATION' || finishReason === 'SAFETY') {
          throw new Error(`Speech generation was blocked due to ${finishReason}.`);
        }
        throw new Error(`Speech generation failed. Finish reason: ${finishReason || 'Unknown'}`);
      }

      const audioPart = candidate.content.parts.find(p => p.inlineData);
      const base64Audio = audioPart?.inlineData?.data;

      if (!base64Audio) {
        const textPart = candidate.content.parts.find(p => p.text);
        if (textPart) {
          throw new Error(`Model returned text instead of audio: ${textPart.text}`);
        }
        throw new Error("No audio data returned from API.");
      }

      return base64Audio;
    } catch (error: any) {
      // More descriptive error for quota/rate limit
      if (error?.message?.includes('429') || error?.status === 429 || error?.message?.includes('RESOURCE_EXHAUSTED')) {
        throw new Error("API Quota exceeded. Please wait a moment and try again.");
      }
      console.error("Gemini TTS Error Details:", error);
      throw error;
    }
  });
};

export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodePCM(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1,
): Promise<AudioBuffer> {
  const numSamples = Math.floor(data.byteLength / 2);
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, numSamples);

  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useState, useRef, useEffect } from 'react';
import { LocalizationResult } from '../types';
import { generateSpeech, decodeBase64, decodePCM, generateImage } from '../services/geminiService';

interface Props {
  result: LocalizationResult;
}

type AudioFormat = 'WAV' | 'PCM';

const ResultView: React.FC<Props> = ({ result: initialResult }) => {
  const [result, setResult] = useState<LocalizationResult>(initialResult);
  const [playingVoice, setPlayingVoice] = useState<'Puck' | 'Kore' | null>(null);
  const [isDownloading, setIsDownloading] = useState<'Puck' | 'Kore' | null>(null);
  const [showDownloadDialog, setShowDownloadDialog] = useState<'Puck' | 'Kore' | null>(null);
  const [downloadFilename, setDownloadFilename] = useState('');
  const [selectedFormat, setSelectedFormat] = useState<AudioFormat>('WAV');
  const [imageLoading, setImageLoading] = useState(false);
  const [imageProgress, setImageProgress] = useState(0);
  const [volume, setVolume] = useState(0.8);
  const [playbackError, setPlaybackError] = useState<string | null>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const progressIntervalRef = useRef<number | null>(null);

  useEffect(() => {
    if (result.visualPrompt && !result.imageUrl && !imageLoading) {
      handleGenerateImage(result.visualPrompt);
    }
  }, [result.visualPrompt]);

  // Update gain node whenever volume changes
  useEffect(() => {
    if (gainNodeRef.current) {
      gainNodeRef.current.gain.value = volume;
    }
  }, [volume]);

  const handleGenerateImage = async (prompt: string) => {
    setImageLoading(true);
    setImageProgress(0);

    progressIntervalRef.current = window.setInterval(() => {
      setImageProgress(prev => {
        if (prev < 30) return prev + 1.5;
        if (prev < 60) return prev + 0.8;
        if (prev < 90) return prev + 0.3;
        if (prev < 98) return prev + 0.05;
        return prev;
      });
    }, 100);

    try {
      const imageUrl = await generateImage(prompt);
      setImageProgress(100);

      setTimeout(() => {
        setResult(prev => ({ ...prev, imageUrl }));
        setImageLoading(false);
      }, 500);
    } catch (err) {
      console.error("Image generation failed:", err);
      setImageLoading(false);
    } finally {
      if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
    }
  };

  const handlePlayVoice = async (voiceName: 'Puck' | 'Kore') => {
    if (playingVoice) return;
    setPlaybackError(null);

    try {
      setPlayingVoice(voiceName);
      const base64 = await generateSpeech(result.dariTranslation, voiceName);

      if (!audioCtxRef.current) {
        audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const ctx = audioCtxRef.current;
      if (ctx.state === 'suspended') await ctx.resume();

      // Setup GainNode for volume control if not already exists
      if (!gainNodeRef.current) {
        gainNodeRef.current = ctx.createGain();
        gainNodeRef.current.connect(ctx.destination);
      }
      gainNodeRef.current.gain.value = volume;

      const audioData = decodeBase64(base64);
      const audioBuffer = await decodePCM(audioData, ctx);

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(gainNodeRef.current);
      source.onended = () => setPlayingVoice(null);
      source.start(0);
    } catch (error: any) {
      console.error("Speech error:", error);
      setPlaybackError(error.message || "Speech generation failed.");
      setPlayingVoice(null);
      // Auto-clear error after 5s
      setTimeout(() => setPlaybackError(null), 5000);
    }
  };

  const createWavFile = (pcmData: Uint8Array): Blob => {
    const sampleRate = 24000;
    const numChannels = 1;
    const bitsPerSample = 16;
    const byteRate = (sampleRate * numChannels * bitsPerSample) / 8;
    const blockAlign = (numChannels * bitsPerSample) / 8;
    const dataSize = pcmData.length;
    const headerSize = 44;
    const totalSize = headerSize + dataSize;

    const buffer = new ArrayBuffer(headerSize);
    const view = new DataView(buffer);

    // RIFF identifier
    view.setUint32(0, 0x52494646, false); // "RIFF"
    view.setUint32(4, totalSize - 8, true);
    view.setUint32(8, 0x57415645, false); // "WAVE"

    // fmt chunk
    view.setUint32(12, 0x666d7420, false); // "fmt "
    view.setUint32(16, 16, true); 
    view.setUint16(20, 1, true); 
    view.setUint16(22, numChannels, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, byteRate, true);
    view.setUint16(32, blockAlign, true);
    view.setUint16(34, bitsPerSample, true);

    // data chunk
    view.setUint32(36, 0x64617461, false); // "data"
    view.setUint32(40, dataSize, true);

    return new Blob([buffer, pcmData], { type: 'audio/wav' });
  };

  const sanitizeFilename = (name: string) => {
    return name.replace(/[<>:"/\\|?*]/g, '').trim() || 'dari_voice';
  };

  const handleDownloadVoice = async () => {
    if (!showDownloadDialog || isDownloading) return;

    const voiceName = showDownloadDialog;
    try {
      setIsDownloading(voiceName);
      const base64 = await generateSpeech(result.dariTranslation, voiceName);
      const audioData = decodeBase64(base64);

      let blob: Blob;
      let extension: string;

      if (selectedFormat === 'WAV') {
        blob = createWavFile(audioData);
        extension = 'wav';
      } else {
        blob = new Blob([audioData], { type: 'audio/pcm' });
        extension = 'pcm';
      }

      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;

      const baseName = sanitizeFilename(downloadFilename);
      link.download = `${baseName}.${extension}`;

      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);

      setTimeout(() => URL.revokeObjectURL(url), 100);

      setShowDownloadDialog(null);
    } catch (err: any) {
      console.error("Download failed", err);
      alert(err.message || "Encountered an error while preparing the audio file. Please try again.");
    } finally {
      setIsDownloading(null);
    }
  };

  const openDownloadDialog = (voiceName: 'Puck' | 'Kore') => {
    setShowDownloadDialog(voiceName);
    const dateStr = new Date().toISOString().split('T')[0];
    setDownloadFilename(`dari_localization_${voiceName.toLowerCase()}_${dateStr}`);
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-8 duration-700">
      <div className="bg-white rounded-[3rem] shadow-2xl shadow-gray-200/50 border border-gray-100 overflow-hidden relative">

        {showDownloadDialog && (
          <div className="absolute inset-0 z-50 bg-white/95 backdrop-blur-md flex items-center justify-center p-6">
