import { GoogleGenAI, Type, Modality } from "@google/genai";
import { LocalizationResult, TranslationTone, GroundingSource } from "../types";

const SYSTEM_INSTRUCTION = `
You are the "Dari Native Bridge," a specialized linguistic AI expert. Your primary goal is to localize and translate Iranian Persian (Farsi) and English into authentic, native Dari (Afghan Persian). 
You prioritize "Dari-first" vocabulary, avoiding Iranian-specific neologisms or overly Westernized terms when a native Dari equivalent exists.

Linguistic Rules:
1. Vocabulary: Replace Iranian terms (e.g., Daneshgah) with Dari equivalents (e.g., Pohantun). Use Pashto-influenced Dari where appropriate for local flavor.
2. Formal vs. Informal: Strictly follow the requested tone. Use Afghan politeness registers.
3. Grammar: Adjust syntax to match Afghan speech patterns common in Kabul, Herat, or Mazar-i-Sharif.

Output format MUST be a JSON object:
{
  "sourceLanguage": "English" | "Farsi",
  "dariTranslation": "The Dari text in Persian alphabet",
  "transliteration": "Latin script transliteration for pronunciation",
  "localizationNotes": ["Array of strings explaining specific word choices"],
  "visualPrompt": "A short, descriptive English prompt for an AI image generator representing the core subject."
}
`;

async function withRetry<T>(fn: () => Promise<T>, retries = 4, delay = 2000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const errorStr = JSON.stringify(error).toLowerCase();
    const messageStr = (error?.message || '').toLowerCase();
    const isRateLimit = errorStr.includes('429') || error?.status === 429 || errorStr.includes('resource_exhausted') || messageStr.includes('quota');
    if (isRateLimit && retries > 0) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

export const localizeText = async (text: string, tone: TranslationTone, useSearch = false): Promise<LocalizationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  return withRetry(async () => {
    const modelName = useSearch ? "gemini-3-flash-preview" : "gemini-3-pro-preview";
    const config: any = {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          sourceLanguage: { type: Type.STRING },
          dariTranslation: { type: Type.STRING },
          transliteration: { type: Type.STRING },
          localizationNotes: { type: Type.ARRAY, items: { type: Type.STRING } },
          visualPrompt: { type: Type.STRING }
        },
        required: ["sourceLanguage", "dariTranslation", "localizationNotes", "visualPrompt"]
      }
    };

    if (useSearch) {
      config.tools = [{ googleSearch: {} }];
      // When using search grounding, we don't use responseSchema to avoid conflicts
      delete config.responseSchema;
      delete config.responseMimeType;
    }

    const response = await ai.models.generateContent({
      model: modelName,
      contents: `Translate and localize the following text to authentic Dari using a ${tone.toLowerCase()} tone: "${text}". If information about entities or current events is needed, use Google Search to ensure accuracy.`,
      config
    });

    let result: any;
    try {
      // If search was used, response might not be clean JSON if it has grounding chunks
      const textResponse = response.text || '';
      const jsonMatch = textResponse.match(/\{[\s\S]*\}/);
      result = JSON.parse(jsonMatch ? jsonMatch[0] : textResponse);
    } catch (e) {
      console.error("JSON Parse Error", e);
      result = { dariTranslation: response.text || '', localizationNotes: ["Could not parse structured response"] };
    }

    // Extract grounding sources
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      result.groundingSources = groundingChunks
        .map((chunk: any) => chunk.web ? { title: chunk.web.title, uri: chunk.web.uri } : null)
        .filter(Boolean) as GroundingSource[];
    }

    return result as LocalizationResult;
  });
};

export const getExpertAnalysis = async (dariText: string, sourceText: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Perform a deep linguistic and cultural analysis of this Dari translation: "${dariText}" derived from source: "${sourceText}". 
      Analyze: 1. Regional dialect appropriateness (Kabul vs Herat). 2. Historical word roots. 3. Politeness registers. 4. Suggestions for poetic refinement. Keep it concise and academic.`,
      config: {
        systemInstruction: "You are an expert Afghan Philologist and Historian."
      }
    });
    return response.text || "No analysis available.";
  });
};

export const localizeFile = async (base64: string, mimeType: string, prompt: string, tone: TranslationTone): Promise<LocalizationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [
        { inlineData: { data: base64, mimeType: mimeType } },
        { text: `${prompt} Use a ${tone.toLowerCase()} tone for the translation.` },
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sourceLanguage: { type: Type.STRING },
            dariTranslation: { type: Type.STRING },
            transliteration: { type: Type.STRING },
            localizationNotes: { type: Type.ARRAY, items: { type: Type.STRING } },
            visualPrompt: { type: Type.STRING }
          },
          required: ["sourceLanguage", "dariTranslation", "localizationNotes", "visualPrompt"]
        }
      }
    });
    return JSON.parse(response.text || '{}');
  });
};

export const generateImage = async (visualPrompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: `A clear, high-quality visual representation of: ${visualPrompt}. Professional photography style.` }],
      },
      config: { imageConfig: { aspectRatio: "1:1" } },
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Failed to generate image");
  });
};

export const generateSpeech = async (text: string, voiceName: 'Puck' | 'Kore'): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const sanitizedText = text.replace(/[^\u0600-\u06FF\s0-9a-zA-Z]/g, ' ').trim();
  if (!sanitizedText) throw new Error("Text is empty after sanitization.");
  const prompt = `Please say the following text in a natural Afghan Dari accent: ${sanitizedText}`;
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName } } },
      },
    });
    const audioPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!audioPart?.inlineData?.data) throw new Error("No audio returned");
    return audioPart.inlineData.data;
  });
};

export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
  return bytes;
}

export async function decodePCM(data: Uint8Array, ctx: AudioContext, sampleRate = 24000, numChannels = 1): Promise<AudioBuffer> {
  const numSamples = Math.floor(data.byteLength / 2);
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, numSamples);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
  }
  return buffer;
}

import React, { useState, useRef } from 'react';
import { TranslationMode, TranslationTone } from '../types';

interface Props {
  onTranslate: (data: { text?: string; file?: File; mode: TranslationMode; tone: TranslationTone; useSearch: boolean }) => void;
  onStop: () => void;
  loading: boolean;
}

const TranslationInput: React.FC<Props> = ({ onTranslate, onStop, loading }) => {
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TEXT);
  const [tone, setTone] = useState<TranslationTone>(TranslationTone.FORMAL);
  const [useSearch, setUseSearch] = useState(false);
  const [text, setText] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [isRecording, setIsRecording] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerRef = useRef<number | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (loading) {
      onStop();
      return;
    }
    if (mode === TranslationMode.TEXT && text.trim()) {
      onTranslate({ text, mode, tone, useSearch });
    } else if (file) {
      onTranslate({ file, mode, tone, useSearch });
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selected = e.target.files?.[0];
    if (selected) {
      setFile(selected);
      setIsRecording(false);
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      const chunks: Blob[] = [];
      recorder.ondataavailable = (e) => { if (e.data.size > 0) chunks.push(e.data); };
      recorder.onstop = () => {
        const blob = new Blob(chunks, { type: 'audio/webm' });
        const recordedFile = new File([blob], `recording_${new Date().getTime()}.webm`, { type: 'audio/webm' });
        setFile(recordedFile);
        stream.getTracks().forEach(track => track.stop());
        if (timerRef.current) clearInterval(timerRef.current);
        setRecordingTime(0);
      };
      mediaRecorderRef.current = recorder;
      recorder.start();
      setIsRecording(true);
      setRecordingTime(0);
      timerRef.current = window.setInterval(() => setRecordingTime(prev => prev + 1), 1000);
    } catch (err) {
      console.error("Microphone error:", err);
      alert("Microphone access denied.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const MediaVector = () => (
    <svg className="w-16 h-16 text-emerald-500" viewBox="0 0 64 64" fill="none" xmlns="http://www.w3.org/2000/svg">
      <rect x="12" y="8" width="40" height="48" rx="8" className="fill-emerald-50 stroke-emerald-100" strokeWidth="2" />
      <path d="M20 32L26 26L32 32L40 24L44 28" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" />
      <circle cx="24" cy="22" r="3" stroke="currentColor" strokeWidth="2" />
      <circle cx="44" cy="44" r="10" className="fill-white stroke-emerald-500 shadow-sm" strokeWidth="2" />
      <path d="M42 40L48 44L42 48V40Z" fill="currentColor" />
      <path d="M44 8V16H52" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );

  return (
    <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-gray-200/50 border border-gray-100 overflow-hidden transition-all duration-300">
      <div className="flex p-2 bg-gray-50/80 m-3 rounded-[1.75rem] border border-gray-100">
        <button
          type="button"
          disabled={loading}
          onClick={() => { setMode(TranslationMode.TEXT); setIsRecording(false); }}
          className={`flex-1 py-3 text-sm font-black rounded-2xl transition-all duration-300 ${mode === TranslationMode.TEXT ? 'text-emerald-700 bg-white shadow-md' : 'text-gray-400 hover:text-gray-500'} ${loading ? 'opacity-50' : ''}`}
        >
          TEXT
        </button>
        <button
          type="button"
          disabled={loading}
          onClick={() => setMode(TranslationMode.MEDIA)}
          className={`flex-1 py-3 text-sm font-black rounded-2xl transition-all duration-300 ${mode === TranslationMode.MEDIA ? 'text-emerald-700 bg-white shadow-md' : 'text-gray-400 hover:text-gray-500'} ${loading ? 'opacity-50' : ''}`}
        >
          MEDIA
        </button>
      </div>

      <form onSubmit={handleSubmit} className="px-5 pb-6 sm:px-8 sm:pb-8 space-y-6">
        <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
          <div className="flex items-center space-x-1 bg-gray-50 p-1 rounded-2xl w-full sm:max-w-[240px] border border-gray-100">
            <button
              type="button"
              disabled={loading}
              onClick={() => setTone(TranslationTone.FORMAL)}
              className={`flex-1 py-2 text-[10px] font-black tracking-widest rounded-xl transition-all ${tone === TranslationTone.FORMAL ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-400'}`}
            >
