            <button
              type="button"
              disabled={loading}
              onClick={() => setTone(TranslationTone.INFORMAL)}
              className={`flex-1 py-2 text-[10px] font-black tracking-widest rounded-xl transition-all ${tone === TranslationTone.INFORMAL ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-400'}`}
