              INFORMAL
            </button>
          </div>

          <label className="flex items-center cursor-pointer space-x-3 bg-emerald-50/50 px-4 py-2 rounded-2xl border border-emerald-100">
            <input 
              type="checkbox" 
              checked={useSearch} 
              onChange={() => setUseSearch(!useSearch)}
              disabled={loading}
              className="hidden"
            />
            <div className={`w-10 h-6 rounded-full transition-colors flex items-center px-1 ${useSearch ? 'bg-emerald-600' : 'bg-gray-300'}`}>
              <div className={`w-4 h-4 bg-white rounded-full transition-transform ${useSearch ? 'translate-x-4' : 'translate-x-0'}`}></div>
            </div>
            <span className="text-[10px] font-black uppercase tracking-widest text-emerald-700">Enhanced Search</span>
          </label>
        </div>

        {mode === TranslationMode.TEXT ? (
          <div className="relative">
            <textarea
              className="w-full h-56 p-6 text-xl font-medium border-0 bg-gray-50/40 rounded-[2rem] focus:ring-4 focus:ring-emerald-500/5 outline-none transition-all resize-none placeholder:text-gray-300 placeholder:font-bold leading-relaxed"
              placeholder="What would you like to bridge?"
              value={text}
              disabled={loading}
              onChange={(e) => setText(e.target.value)}
            />
            {text && !loading && (
              <button 
                type="button" 
                onClick={() => setText('')}
                className="absolute top-5 right-5 w-8 h-8 flex items-center justify-center bg-white rounded-full shadow-sm text-gray-300 hover:text-red-500 transition-colors"
              >
