              </button>
            )}
          </div>
        ) : (
          <div className="space-y-5">
            <div 
              className={`relative border-2 border-dashed rounded-[2.5rem] p-8 sm:p-12 text-center bg-gray-50/30 hover:bg-emerald-50/20 transition-all cursor-pointer group active:scale-[0.98] ${file ? 'border-emerald-200' : 'border-gray-200'} ${isRecording || loading ? 'opacity-50 pointer-events-none' : ''}`} 
              onClick={() => fileInputRef.current?.click()}
            >
              <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileChange} accept="image/*,application/pdf,audio/*,video/*" />
              <div className="flex flex-col items-center">
                <div className="mb-6 group-hover:scale-110 transition-transform duration-500 ease-out"><MediaVector /></div>
                <h3 className="text-gray-900 font-black text-sm uppercase tracking-wider">{file ? file.name : "Process Any Media"}</h3>
                <p className="text-gray-400 text-[10px] mt-2 font-black uppercase tracking-[0.2em]">Images • PDF • Audio • Video</p>
                {file && <div className="mt-4 px-4 py-1.5 bg-emerald-100 text-emerald-700 text-[10px] font-black rounded-full uppercase tracking-widest">Ready for bridge</div>}
              </div>
            </div>

            <div className="flex items-center py-2">
              <div className="flex-1 h-[1px] bg-gray-100"></div>
              <span className="px-4 text-[10px] font-black text-gray-300 uppercase tracking-widest">or record voice</span>
              <div className="flex-1 h-[1px] bg-gray-100"></div>
            </div>

            <div className="p-2 bg-gray-50/50 rounded-3xl border border-gray-100/50">
              {!isRecording ? (
                <button
                  type="button"
                  disabled={loading}
                  onClick={startRecording}
                  className="w-full flex items-center justify-center space-x-3 bg-emerald-600 text-white py-4 rounded-2xl hover:bg-emerald-700 transition-all shadow-xl shadow-emerald-200/50 font-black text-xs uppercase tracking-widest disabled:opacity-50"
                >
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8a1 1 0 10-2 0A5 5 0 015 8a1 1 0 00-2 0 7.001 7.001 0 005.93 6.93V17H6a1 1 0 100 2h8a1 1 0 100-2h-3v-2.07z" clipRule="evenodd" /></svg>
                  <span>Native Capture</span>
