          </div>
        )}

        {loading ? (
          <button type="button" onClick={onStop} className="w-full bg-red-50 text-red-600 font-black py-5 rounded-[1.75rem] hover:bg-red-100 transition-all shadow-xl shadow-red-100 active:scale-[0.98] flex items-center justify-center border border-red-200">
