interface Props {
  result: LocalizationResult;
  sourceText?: string;
}

type AudioFormat = 'WAV' | 'PCM';

const ResultView: React.FC<Props> = ({ result: initialResult, sourceText }) => {
  const [result, setResult] = useState<LocalizationResult>(initialResult);
  const [playingVoice, setPlayingVoice] = useState<'Puck' | 'Kore' | null>(null);
  const [isDownloading, setIsDownloading] = useState<'Puck' | 'Kore' | null>(null);
  const [showDownloadDialog, setShowDownloadDialog] = useState<'Puck' | 'Kore' | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [downloadFilename, setDownloadFilename] = useState('');
  const [selectedFormat, setSelectedFormat] = useState<AudioFormat>('WAV');
  const [imageLoading, setImageLoading] = useState(false);
  const [imageProgress, setImageProgress] = useState(0);
  const [volume, setVolume] = useState(0.8);
  const [playbackError, setPlaybackError] = useState<string | null>(null);

  const voiceCache = useRef<Record<string, string>>({});
  const audioCtxRef = useRef<AudioContext | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const progressIntervalRef = useRef<number | null>(null);

  useEffect(() => {
    if (result.visualPrompt && !result.imageUrl && !imageLoading) {
      handleGenerateImage(result.visualPrompt);
    }
  }, [result.visualPrompt]);

  useEffect(() => {
    if (gainNodeRef.current) gainNodeRef.current.gain.value = volume;
  }, [volume]);

  const handleGenerateImage = async (prompt: string) => {
    setImageLoading(true);
    setImageProgress(0);
    progressIntervalRef.current = window.setInterval(() => {
      setImageProgress(prev => prev < 98 ? prev + 0.1 : prev);
    }, 100);
    try {
      const imageUrl = await generateImage(prompt);
      setImageProgress(100);
      setTimeout(() => { setResult(prev => ({ ...prev, imageUrl })); setImageLoading(false); }, 500);
    } catch (err) {
      console.error(err);
      setImageLoading(false);
    } finally {
      if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
    }
  };

  const handleExpertAnalysis = async () => {
    if (!sourceText || isAnalyzing) return;
    setIsAnalyzing(true);
    try {
      const analysis = await getExpertAnalysis(result.dariTranslation, sourceText);
      setResult(prev => ({ ...prev, expertAnalysis: analysis }));
    } catch (err) {
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const getVoiceAudio = async (voiceName: 'Puck' | 'Kore'): Promise<string> => {
    if (voiceCache.current[voiceName]) return voiceCache.current[voiceName];
    const base64 = await generateSpeech(result.dariTranslation, voiceName);
    voiceCache.current[voiceName] = base64;
    return base64;
  };

  const handlePlayVoice = async (voiceName: 'Puck' | 'Kore') => {
    if (playingVoice) return;
    setPlaybackError(null);
    try {
      setPlayingVoice(voiceName);
      const base64 = await getVoiceAudio(voiceName);
      if (!audioCtxRef.current) audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const ctx = audioCtxRef.current;
      if (ctx.state === 'suspended') await ctx.resume();
      if (!gainNodeRef.current) {
        gainNodeRef.current = ctx.createGain();
        gainNodeRef.current.connect(ctx.destination);
      }
      gainNodeRef.current.gain.value = volume;
      const audioData = decodeBase64(base64);
      const audioBuffer = await decodePCM(audioData, ctx);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(gainNodeRef.current);
      source.onended = () => setPlayingVoice(null);
      source.start(0);
    } catch (error: any) {
      setPlaybackError(error.message || "Speech generation failed.");
      setPlayingVoice(null);
      setTimeout(() => setPlaybackError(null), 5000);
