};

export const localizeFile = async (base64: string, mimeType: string, prompt: string, tone: TranslationTone): Promise<LocalizationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [
        { inlineData: { data: base64, mimeType: mimeType } },
        { text: `${prompt} Use a ${tone.toLowerCase()} tone for the translation.` },
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sourceLanguage: { type: Type.STRING },
            dariTranslation: { type: Type.STRING },
            transliteration: { type: Type.STRING },
            localizationNotes: { type: Type.ARRAY, items: { type: Type.STRING } },
            visualPrompt: { type: Type.STRING }
          },
          required: ["sourceLanguage", "dariTranslation", "localizationNotes", "visualPrompt"]
        }
      }
    });
    return JSON.parse(response.text || '{}');
  });
};

export const generateImage = async (visualPrompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ 
          text: `An authentic artistic visualization of: ${visualPrompt}. 
          CRITICAL STYLE REQUIREMENT: The artwork MUST strictly adhere to Islamic and Afghan-Tajik cultural aesthetics. 
          Incorporate traditional Tajik patterns (Chakan), elegant Islamic calligraphy (Khat-i-Nasta'liq), Afghan architectural motifs, and vibrant silk textures. 
          The final image should feel like a masterpiece of Central Asian or Islamic fine art. No Western tropes.` 
        }],
      },
      config: { imageConfig: { aspectRatio: "1:1" } },
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Failed to generate image");
  });
};

export const generateSpeech = async (text: string, voiceName: 'Puck' | 'Kore'): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const sanitizedText = text.replace(/[^\u0600-\u06FF\s0-9a-zA-Z]/g, ' ').trim();
  if (!sanitizedText) throw new Error("Text is empty after sanitization.");
  const prompt = `Please say the following text in a natural Afghan Dari accent: ${sanitizedText}`;
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName } } },
      },
    });
    const audioPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!audioPart?.inlineData?.data) throw new Error("No audio returned");
    return audioPart.inlineData.data;
  });
};

export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
  return bytes;
}

export async function decodePCM(data: Uint8Array, ctx: AudioContext, sampleRate = 24000, numChannels = 1): Promise<AudioBuffer> {
  const numSamples = Math.floor(data.byteLength / 2);
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, numSamples);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
  }
  return buffer;
}

import React, { useState, useRef, useEffect } from 'react';
import { LocalizationResult } from '../types';
import { generateSpeech, decodeBase64, decodePCM, generateImage, getExpertAnalysis } from '../services/geminiService';

interface Props {
  result: LocalizationResult;
  sourceText?: string;
}

type AudioFormat = 'WAV' | 'PCM';

const ResultView: React.FC<Props> = ({ result: initialResult, sourceText }) => {
  const [result, setResult] = useState<LocalizationResult>(initialResult);
  const [playingVoice, setPlayingVoice] = useState<'Puck' | 'Kore' | null>(null);
  const [isDownloading, setIsDownloading] = useState<'Puck' | 'Kore' | null>(null);
  const [showDownloadDialog, setShowDownloadDialog] = useState<'Puck' | 'Kore' | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [downloadFilename, setDownloadFilename] = useState('');
  const [selectedFormat, setSelectedFormat] = useState<AudioFormat>('WAV');
  const [imageLoading, setImageLoading] = useState(false);
  const [imageProgress, setImageProgress] = useState(0);
  const [volume, setVolume] = useState(0.8);
  const [playbackError, setPlaybackError] = useState<string | null>(null);

  const voiceCache = useRef<Record<string, string>>({});
  const audioCtxRef = useRef<AudioContext | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const progressIntervalRef = useRef<number | null>(null);

  useEffect(() => {
    if (result.visualPrompt && !result.imageUrl && !imageLoading) {
      handleGenerateImage(result.visualPrompt);
    }
  }, [result.visualPrompt]);

  useEffect(() => {
    if (gainNodeRef.current) gainNodeRef.current.gain.value = volume;
  }, [volume]);

  const handleGenerateImage = async (prompt: string) => {
    setImageLoading(true);
    setImageProgress(0);
    progressIntervalRef.current = window.setInterval(() => {
      setImageProgress(prev => prev < 98 ? prev + 0.1 : prev);
    }, 100);
    try {
      const imageUrl = await generateImage(prompt);
      setImageProgress(100);
      setTimeout(() => { setResult(prev => ({ ...prev, imageUrl })); setImageLoading(false); }, 500);
    } catch (err) {
      console.error(err);
      setImageLoading(false);
    } finally {
      if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
    }
  };

  const handleExpertAnalysis = async () => {
    if (!sourceText || isAnalyzing) return;
    setIsAnalyzing(true);
    try {
      const analysis = await getExpertAnalysis(result.dariTranslation, sourceText);
      setResult(prev => ({ ...prev, expertAnalysis: analysis }));
    } catch (err) {
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const getVoiceAudio = async (voiceName: 'Puck' | 'Kore'): Promise<string> => {
    if (voiceCache.current[voiceName]) return voiceCache.current[voiceName];
    const base64 = await generateSpeech(result.dariTranslation, voiceName);
    voiceCache.current[voiceName] = base64;
    return base64;
  };

  const handlePlayVoice = async (voiceName: 'Puck' | 'Kore') => {
    if (playingVoice) return;
    setPlaybackError(null);
    try {
      setPlayingVoice(voiceName);
      const base64 = await getVoiceAudio(voiceName);
      if (!audioCtxRef.current) audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const ctx = audioCtxRef.current;
      if (ctx.state === 'suspended') await ctx.resume();
      if (!gainNodeRef.current) {
        gainNodeRef.current = ctx.createGain();
        gainNodeRef.current.connect(ctx.destination);
      }
      gainNodeRef.current.gain.value = volume;
      const audioData = decodeBase64(base64);
      const audioBuffer = await decodePCM(audioData, ctx);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(gainNodeRef.current);
      source.onended = () => setPlayingVoice(null);
      source.start(0);
    } catch (error: any) {
      setPlaybackError(error.message || "Speech generation failed.");
      setPlayingVoice(null);
      setTimeout(() => setPlaybackError(null), 5000);
    }
  };

  const openDownloadDialog = (voiceName: 'Puck' | 'Kore') => {
    setShowDownloadDialog(voiceName);
    setDownloadFilename(`dari_localization_${voiceName.toLowerCase()}_${new Date().toISOString().split('T')[0]}`);
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-8 duration-700">
      <div className="bg-white rounded-[3rem] shadow-2xl shadow-gray-200/50 border border-gray-100 overflow-hidden relative">
        {/* Visual Context with Islamic Frame Styling */}
        <div className="relative w-full aspect-[4/3] sm:aspect-video overflow-hidden group bg-gray-100">
