/**
 * Enhanced retry helper to handle transient API errors and specific model finish reasons.
 */
async function withRetry<T>(
  fn: () => Promise<T>, 
  retries = 4, 
  delay = 2000, 
  retryOnOther = false
): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const errorStr = JSON.stringify(error).toLowerCase();
    const messageStr = (error?.message || '').toLowerCase();

    const isRateLimit = errorStr.includes('429') || error?.status === 429 || errorStr.includes('resource_exhausted') || messageStr.includes('quota');
    const isOtherFinishReason = retryOnOther && (messageStr.includes('finish reason: other') || messageStr.includes('finish_reason: other'));

    if ((isRateLimit || isOtherFinishReason) && retries > 0) {
      console.warn(`Transient error or quota reached. Retrying in ${delay}ms... (${retries} retries left)`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, delay * 2, retryOnOther);
    }
    throw error;
  }
}

