export const generateSpeech = async (text: string, voiceName: 'Puck' | 'Kore'): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  // Refined sanitization: keep Dari characters and essential punctuation
  const sanitizedText = text
    .replace(/[^\u0600-\u06FF\s0-9a-zA-Z،؛؟.,!]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  if (!sanitizedText) throw new Error("Translation text is empty or invalid for speech.");

  // Direct, simple prompt to minimize 'OTHER' finish reasons
  const prompt = `Say in Dari: ${sanitizedText}`;

  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { 
          voiceConfig: { prebuiltVoiceConfig: { voiceName } } 
        },
      },
    });

    const candidate = response.candidates?.[0];
    const finishReason = candidate?.finishReason;

    // Handle non-stop finish reasons explicitly to trigger retry logic in withRetry
    if (finishReason && finishReason !== 'STOP') {
      if (finishReason === 'RECITATION' || finishReason === 'SAFETY') {
        throw new Error(`Speech generation blocked: ${finishReason}`);
      }
      throw new Error(`Speech generation failed. Finish reason: ${finishReason}`);
    }

    const audioPart = candidate?.content?.parts.find(p => p.inlineData);
    if (!audioPart?.inlineData?.data) {
      throw new Error("No audio payload returned from API.");
    }

    return audioPart.inlineData.data;
  }, 5, 1500, true); // Increased retries and enabled retry on 'OTHER'
};

export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
  return bytes;
}

export async function decodePCM(data: Uint8Array, ctx: AudioContext, sampleRate = 24000, numChannels = 1): Promise<AudioBuffer> {
  const numSamples = Math.floor(data.byteLength / 2);
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, numSamples);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
  }
  return buffer;
}

