export const generateSpeech = async (text: string, voiceName: 'Puck' | 'Kore'): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  // Refined sanitization: allow only Dari letters and standard punctuation to avoid triggering safety/logic filters
  const sanitizedText = text
    .replace(/[^\u0600-\u06FF\s،؛؟.,!]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  if (!sanitizedText) throw new Error("Text content is not suitable for Dari speech generation.");

  // We move the accent instruction to the systemInstruction for better reliability and better accent capture.
  const prompt = `Read this Dari text exactly as provided: ${sanitizedText}`;

  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
