import React, { useState, useRef, useEffect } from 'react';
import { LocalizationResult } from '../types';
import { generateSpeech, decodeBase64, decodePCM, generateImage, getExpertAnalysis } from '../services/geminiService';

interface Props {
  result: LocalizationResult;
  sourceText?: string;
}

const ResultView: React.FC<Props> = ({ result: initialResult, sourceText }) => {
  const [result, setResult] = useState<LocalizationResult>(initialResult);
  const [playingVoice, setPlayingVoice] = useState<'Puck' | 'Kore' | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [imageLoading, setImageLoading] = useState(false);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);

  useEffect(() => {
    if (result.visualPrompt && !result.imageUrl && !imageLoading) {
      handleGenerateImage(result.visualPrompt);
    }
  }, [result.visualPrompt]);

  const handleGenerateImage = async (prompt: string) => {
    setImageLoading(true);
    try {
      const imageUrl = await generateImage(prompt);
      setResult(prev => ({ ...prev, imageUrl }));
    } catch (err) {
      console.error("Image Error", err);
    } finally {
      setImageLoading(false);
    }
  };

  const handleExpertAnalysis = async () => {
    if (!sourceText || isAnalyzing) return;
    setIsAnalyzing(true);
    try {
      const analysis = await getExpertAnalysis(result.dariTranslation, sourceText);
      setResult(prev => ({ ...prev, expertAnalysis: analysis }));
    } catch (err) {
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handlePlayVoice = async (voiceName: 'Puck' | 'Kore') => {
    if (playingVoice) return;
    try {
      setPlayingVoice(voiceName);
      const base64 = await generateSpeech(result.dariTranslation, voiceName);
      if (!audioCtxRef.current) audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const ctx = audioCtxRef.current;
      if (ctx.state === 'suspended') await ctx.resume();
      if (!gainNodeRef.current) {
        gainNodeRef.current = ctx.createGain();
        gainNodeRef.current.connect(ctx.destination);
      }
      const audioData = decodeBase64(base64);
      const audioBuffer = await decodePCM(audioData, ctx);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(gainNodeRef.current);
      source.onended = () => setPlayingVoice(null);
      source.start(0);
    } catch (error) {
      console.error(error);
      setPlayingVoice(null);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-8 duration-500">
      <div className="bg-white rounded-[2rem] shadow-xl border border-gray-100 overflow-hidden">
        {/* Main Semantic AI Generation */}
        <div className="relative w-full aspect-video bg-gray-100 flex items-center justify-center overflow-hidden">
          {imageLoading ? (
            <div className="flex flex-col items-center space-y-4">
              <div className="w-12 h-12 border-4 border-emerald-100 border-t-emerald-600 rounded-full animate-spin"></div>
              <p className="text-[10px] font-black uppercase tracking-widest text-emerald-600">Generating Semantic Visual...</p>
            </div>
          ) : result.imageUrl ? (
            <img src={result.imageUrl} className="w-full h-full object-cover" alt="AI Context" />
          ) : (
            <div className="text-gray-300 font-bold uppercase text-[10px] tracking-widest">No Visual Context</div>
          )}
          <div className="absolute top-4 right-4 bg-gray-900/80 text-white text-[8px] font-black uppercase px-3 py-1.5 rounded-full tracking-widest backdrop-blur-sm">AI Visualization</div>
        </div>

        {/* Web Grounding: 3 Items Below */}
        <div className="grid grid-cols-3 gap-1 p-1 bg-gray-100 border-b border-gray-100">
          {[0, 1, 2].map(i => {
            const source = result.groundingSources?.[i];
            return (
              <div key={i} className="bg-white aspect-square sm:aspect-video flex flex-col items-center justify-center p-2 text-center overflow-hidden border border-gray-100/50 hover:bg-gray-50 transition-colors">
                {source ? (
                  <a href={source.uri} target="_blank" rel="noreferrer" className="flex flex-col items-center justify-center h-full w-full">
                    <svg className="w-4 h-4 text-blue-500 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" /></svg>
                    <span className="text-[8px] font-bold text-gray-700 leading-tight line-clamp-2">{source.title}</span>
                  </a>
                ) : (
                  <div className="flex flex-col items-center opacity-30">
                    <div className="w-4 h-4 bg-gray-200 rounded-sm mb-2"></div>
                    <span className="text-[8px] font-bold text-gray-400">WEB REFERENCE</span>
                  </div>
                )}
              </div>
            );
          })}
        </div>

        <div className="p-6 sm:p-8 space-y-8">
          <section className="space-y-4">
            <div className="flex items-center justify-between">
              <span className="text-[9px] font-black uppercase tracking-widest text-emerald-600 bg-emerald-50 px-3 py-1.5 rounded-full">Native Bridge Session</span>
              <div className="flex space-x-2">
                <button onClick={() => handlePlayVoice('Puck')} disabled={!!playingVoice} className={`w-10 h-10 flex items-center justify-center rounded-xl transition-all shadow-sm ${playingVoice === 'Puck' ? 'bg-blue-600 text-white' : 'bg-blue-50 text-blue-600'}`}>
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" /></svg>
                </button>
                <button onClick={() => handlePlayVoice('Kore')} disabled={!!playingVoice} className={`w-10 h-10 flex items-center justify-center rounded-xl transition-all shadow-sm ${playingVoice === 'Kore' ? 'bg-emerald-600 text-white' : 'bg-emerald-50 text-emerald-600'}`}>
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.707-3.707a1 1 0 011.09-.217zM14.657 2.929a1 1 0 011.414 0A9.972 9.972 0 0119 10a9.972 9.972 0 01-2.929 7.071 1 1 0 01-1.414-1.414A7.971 7.971 0 0017 10c0-2.21-.894-4.208-2.343-5.657a1 1 0 010-1.414zm-2.829 2.828a1 1 0 011.415 0A5.983 5.983 0 0115 10a5.984 5.984 0 01-1.757 4.243 1 1 0 01-1.415-1.415A3.984 3.984 0 0013 10a3.983 3.983 0 00-1.172-2.828 1 1 0 010-1.415z" clipRule="evenodd" /></svg>
                </button>
              </div>
            </div>

            <div className="bg-gray-50 rounded-[1.5rem] p-8 border border-gray-100">
              <p className="text-3xl sm:text-4xl font-dari text-right leading-loose text-gray-900" dir="rtl">{result.dariTranslation}</p>
              {result.transliteration && <p className="mt-4 text-xs text-gray-400 italic text-left">{result.transliteration}</p>}
            </div>
          </section>

          <section className="space-y-4">
            <div className="flex items-center justify-between border-b border-gray-100 pb-2">
              <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">Localization Notes</span>
              <button onClick={handleExpertAnalysis} disabled={isAnalyzing} className="text-[9px] font-black uppercase tracking-widest text-emerald-600 hover:text-emerald-700">
                {isAnalyzing ? "Analyzing..." : "Expert Depth"}
              </button>
            </div>
            {result.expertAnalysis && (
              <div className="bg-emerald-50/30 p-4 rounded-xl text-xs text-emerald-900 leading-relaxed border border-emerald-100/50 italic mb-4">
                {result.expertAnalysis}
              </div>
            )}
            <ul className="space-y-3">
              {result.localizationNotes.map((note, i) => (
                <li key={i} className="flex space-x-3 text-xs text-gray-600">
                  <span className="font-black text-emerald-600 flex-shrink-0">•</span>
                  <span>{note}</span>
                </li>
              ))}
            </ul>
          </section>
        </div>
      </div>
    </div>
  );
};

