import { GoogleGenAI, Type, Modality } from "@google/genai";
import { LocalizationResult, TranslationTone, GroundingSource } from "../types";

const SYSTEM_INSTRUCTION = `
You are the "Dari Native Bridge," a specialized linguistic AI expert. Your primary goal is to localize and translate Iranian Persian (Farsi) and English into authentic, native Dari (Afghan Persian). 
You prioritize "Dari-first" native Afghan vocabulary, avoiding Iranian-specific neologisms.

Linguistic Rules:
1. Vocabulary: Replace Iranian terms (e.g., Daneshgah) with native Dari (e.g., Pohantun).
2. Accent/Cadence: The output must reflect the neutral speech of Afghanistan (Kabul/Mazar/Herat).
3. Visual Intelligence: The 'visualPrompt' MUST be a literal, direct representation of the semantic point of the text. No artistic patterns or stylistic motifs like "Tajik style" unless explicitly requested.

Output format MUST be a JSON object:
{
  "sourceLanguage": "English" | "Farsi",
  "dariTranslation": "The Dari text in Persian alphabet",
  "transliteration": "Latin script transliteration for pronunciation",
  "localizationNotes": ["Array of strings explaining specific word choices"],
  "visualPrompt": "A highly descriptive, literal, realistic English prompt for an image generator representing the core point of the text."
}
`;

async function withRetry<T>(
  fn: () => Promise<T>, 
  retries = 3, 
  delay = 1500
): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const msg = String(error).toLowerCase();
    const isRetryable = 
      msg.includes('500') || 
      msg.includes('internal') || 
      msg.includes('429') || 
      msg.includes('limit') || 
      msg.includes('quota') || 
      msg.includes('other') || 
      msg.includes('finish reason');

    if (isRetryable && retries > 0) {
      // console.log(`Retrying... attempts left: ${retries}. Error: ${msg}`);
      await new Promise(r => setTimeout(r, delay));
      return withRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

export const localizeText = async (text: string, tone: TranslationTone, useSearch = false): Promise<LocalizationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  return withRetry(async () => {
    const modelName = "gemini-3-pro-preview";
    const config: any = {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          sourceLanguage: { type: Type.STRING },
          dariTranslation: { type: Type.STRING },
          transliteration: { type: Type.STRING },
          localizationNotes: { type: Type.ARRAY, items: { type: Type.STRING } },
          visualPrompt: { type: Type.STRING }
        },
        required: ["sourceLanguage", "dariTranslation", "localizationNotes", "visualPrompt"]
      }
    };

    if (useSearch) {
      config.tools = [{ googleSearch: {} }];
      delete config.responseSchema;
      delete config.responseMimeType;
    }

    const response = await ai.models.generateContent({
      model: modelName,
      contents: `Translate to authentic Afghan Dari (${tone.toLowerCase()}): "${text}". Use search to find 3 specific web-grounded visual references or factual sources related to the point of this text. Return JSON.`,
      config
    });

    let result: any;
    const textResponse = response.text || '';
    try {
      const jsonMatch = textResponse.match(/\{[\s\S]*\}/);
      result = JSON.parse(jsonMatch ? jsonMatch[0] : textResponse);
    } catch (e) {
      result = { dariTranslation: textResponse, localizationNotes: ["Parsing Error"] };
    }

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      result.groundingSources = groundingChunks
        .map((chunk: any) => chunk.web ? { title: chunk.web.title, uri: chunk.web.uri } : null)
        .filter(Boolean).slice(0, 3) as GroundingSource[];
    }

    return result as LocalizationResult;
  });
};

export const generateImage = async (visualPrompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: `A literal, realistic, high-definition photo representing: ${visualPrompt}. Realistic style, no artistic filters.` }],
      },
      config: { imageConfig: { aspectRatio: "16:9" } },
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Visuals failed.");
  });
};

export const generateSpeech = async (text: string, voiceName: 'Puck' | 'Kore'): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  // Broader sanitization to allow digits and more punctuation, preventing empty strings for valid inputs
  const sanitized = text.replace(/[^\u0600-\u06FF\s0-9۰-۹،؛؟.!]/g, ' ').replace(/\s+/g, ' ').trim();

  if (!sanitized || sanitized.length < 2) {
    // Return silent or throw specific error? Throwing error for now to be caught by UI
    throw new Error("Text content insufficient for speech.");
  }

  // Simplified prompt to reduce 'Finish Reason: OTHER' errors. 
  // We trust the Persian script + Voice Config to deliver the correct regional approximation.
  const ttsPrompt = sanitized; 

  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: ttsPrompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { 
          voiceConfig: { prebuiltVoiceConfig: { voiceName } } 
        },
      },
    });

    const candidate = response.candidates?.[0];
    if (candidate?.finishReason && candidate.finishReason !== 'STOP') {
      throw new Error(`TTS Finish Reason: ${candidate.finishReason}`);
    }

    const audioData = candidate?.content?.parts.find(p => p.inlineData)?.inlineData?.data;
    if (!audioData) throw new Error("No audio returned");
    return audioData;
  });
};

export const getExpertAnalysis = async (dariText: string, sourceText: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Analyze Dari: "${dariText}" vs Source: "${sourceText}". Focus on Afghan-specific linguistics.`,
      config: { systemInstruction: "You are an expert Afghan linguist." }
    });
    return response.text || "Analysis unavailable.";
  });
};

export const localizeFile = async (base64: string, mimeType: string, prompt: string, tone: TranslationTone): Promise<LocalizationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ inlineData: { data: base64, mimeType: mimeType } }, { text: prompt }],
      config: { systemInstruction: SYSTEM_INSTRUCTION, responseMimeType: "application/json" }
    });
    return JSON.parse(response.text || '{}');
  });
};

export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
  return bytes;
}

export async function decodePCM(data: Uint8Array, ctx: AudioContext, sampleRate = 24000, numChannels = 1): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, data.byteLength / 2);
  const buffer = ctx.createBuffer(numChannels, dataInt16.length / numChannels, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < channelData.length; i++) channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
  }
  return buffer;
}

