                )}
             </div>
             <span className="text-[10px] font-bold text-gray-500 line-clamp-2 leading-tight uppercase tracking-tight text-center">{title}</span>
          </a>
        ) : (
          <div className="flex flex-col items-center opacity-30">
             <div className="w-8 h-8 bg-gray-200 rounded-lg mb-2"></div>
             <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest">No Ref</span>
