const WebImage = ({ url, fallbackUri, title }: { url?: string; fallbackUri?: string; title: string }) => {
  const [src, setSrc] = useState<string | undefined>(url);
  const [loading, setLoading] = useState(true);
  const [useScreenshot, setUseScreenshot] = useState(false);

  useEffect(() => {
    if (url) {
      setSrc(url);
      setUseScreenshot(false);
      setLoading(true);
    } else if (fallbackUri) {
      setSrc(`https://image.thum.io/get/width/600/crop/600/noanimate/${fallbackUri}`);
      setUseScreenshot(true);
      setLoading(true);
    } else {
      setSrc(undefined);
      setLoading(false);
    }
  }, [url, fallbackUri]);

  const handleImageError = () => {
    if (!useScreenshot && fallbackUri) {
      // If direct image failed, try screenshot
      setSrc(`https://image.thum.io/get/width/600/crop/600/noanimate/${fallbackUri}`);
      setUseScreenshot(true);
      setLoading(true);
    } else {
      // Both failed, show placeholder
      setSrc(undefined);
      setLoading(false);
    }
  };

  const handleImageLoad = () => {
    setLoading(false);
  };

  const getFavicon = (uri?: string) => {
    if (!uri) return null;
    try {
      const domain = new URL(uri).hostname;
      return `https://www.google.com/s2/favicons?domain=${domain}&sz=128`;
    } catch {
      return null;
    }
  };

  if (!src) {
    const favicon = getFavicon(fallbackUri);
    return (
      <div className="flex flex-col items-center justify-center h-full w-full bg-gray-50 p-3 group">
        {fallbackUri ? (
          <a href={fallbackUri} target="_blank" rel="noreferrer" className="flex flex-col items-center w-full h-full justify-center">
             <div className="mb-2 p-2 bg-white rounded-xl shadow-sm border border-gray-100 group-hover:scale-110 transition-transform">
                {favicon ? (
                  <img src={favicon} alt="" className="w-8 h-8 object-contain" />
                ) : (
                  <svg className="w-6 h-6 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.899a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1" /></svg>
                )}
             </div>
             <span className="text-[10px] font-bold text-gray-500 line-clamp-2 leading-tight uppercase tracking-tight text-center px-1">{title}</span>
          </a>
        ) : (
          <div className="flex flex-col items-center opacity-30">
             <div className="w-8 h-8 bg-gray-200 rounded-lg mb-2"></div>
             <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest">No Ref</span>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="relative w-full h-full bg-gray-100 group overflow-hidden">
      {loading && (
        <div className="absolute inset-0 flex items-center justify-center bg-gray-50 z-10">
          <div className="w-4 h-4 border-2 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
        </div>
      )}
      <a href={fallbackUri || src} target="_blank" rel="noreferrer" className="block w-full h-full">
        <img 
          src={src} 
          alt={title} 
          className={`w-full h-full object-cover transition-all duration-500 group-hover:scale-105 ${loading ? 'opacity-0' : 'opacity-100'}`}
          onError={handleImageError}
          onLoad={handleImageLoad}
          loading="lazy"
        />
        <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/90 via-black/40 to-transparent p-3 pt-8 opacity-0 group-hover:opacity-100 transition-opacity flex items-end">
          <div className="w-full">
            <p className="text-[9px] text-white font-bold line-clamp-2 leading-tight">{title}</p>
            {fallbackUri && <p className="text-[8px] text-gray-300 truncate mt-0.5">{new URL(fallbackUri).hostname}</p>}
          </div>
        </div>
      </a>
    </div>
  );
