              <p className="text-[10px] font-black uppercase tracking-widest text-emerald-600">Generating Semantic Visual...</p>
            </div>
          ) : result.imageUrl ? (
            <img src={result.imageUrl} className="w-full h-full object-cover transition-opacity duration-700 opacity-100" alt="Literal Context" />
          ) : (
            <div className="text-gray-200 font-bold uppercase text-[10px] tracking-widest">Awaiting Semantic Point...</div>
          )}
          <div className="absolute top-4 right-4 bg-gray-900/80 text-white text-[8px] font-black uppercase px-3 py-1.5 rounded-full tracking-widest backdrop-blur-md">Point Visualization</div>
