import { LocalizationResult, TranslationTone, GroundingSource } from "../types";

const SYSTEM_INSTRUCTION = `
You are the "Dari Native Bridge," a specialized linguistic AI expert. Your primary goal is to localize and translate Iranian Persian (Farsi) and English into authentic, native Dari (Afghan Persian). 
You prioritize "Dari-first" native Afghan vocabulary, avoiding Iranian-specific neologisms.

Linguistic Rules:
1. Vocabulary: Replace Iranian terms (e.g., Daneshgah) with native Dari (e.g., Pohantun).
2. Accent/Cadence: The output must reflect the neutral speech of Afghanistan (Kabul/Mazar/Herat).
3. Visual Intelligence: The 'visualPrompt' MUST be a literal, direct representation of the semantic point of the text.

Output format MUST be a JSON object:
{
  "sourceLanguage": "English" | "Farsi",
  "dariTranslation": "The Dari text in Persian alphabet",
  "transliteration": "Latin script transliteration for pronunciation",
  "localizationNotes": ["Array of strings explaining specific word choices"],
  "visualPrompt": "A highly descriptive, realistic English prompt for an image generator representing the core point of the text.",
  "webRefImages": ["URL1", "URL2", "URL3"]
}
`;

async function withRetry<T>(fn: () => Promise<T>, retries = 3, delay = 1500): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const msg = String(error).toLowerCase();
    const isRetryable = msg.includes('500') || msg.includes('429') || msg.includes('other') || msg.includes('finish reason');
    if (isRetryable && retries > 0) {
      await new Promise(r => setTimeout(r, delay));
      return withRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

export const localizeText = async (text: string, tone: TranslationTone, useSearch = false): Promise<LocalizationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  return withRetry(async () => {
    const modelName = "gemini-3-pro-preview";
    const config: any = {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          sourceLanguage: { type: Type.STRING },
          dariTranslation: { type: Type.STRING },
          transliteration: { type: Type.STRING },
          localizationNotes: { type: Type.ARRAY, items: { type: Type.STRING } },
          visualPrompt: { type: Type.STRING },
          webRefImages: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["sourceLanguage", "dariTranslation", "localizationNotes", "visualPrompt"]
      }
    };

    if (useSearch) {
      config.tools = [{ googleSearch: {} }];
      delete config.responseSchema;
      delete config.responseMimeType;
    }

    const response = await ai.models.generateContent({
      model: modelName,
      contents: `Translate to Afghan Dari (${tone.toLowerCase()}): "${text}". ${useSearch ? "Find 3 relevant web images and grounding sources." : ""} Return JSON.`,
      config
    });

    let result: any;
    const textResponse = response.text || '';
    try {
      const jsonMatch = textResponse.match(/\{[\s\S]*\}/);
      result = JSON.parse(jsonMatch ? jsonMatch[0] : textResponse);
    } catch (e) {
      result = { dariTranslation: textResponse, localizationNotes: ["Parsing Error"] };
    }

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      result.groundingSources = groundingChunks
        .map((chunk: any) => chunk.web ? { title: chunk.web.title, uri: chunk.web.uri } : null)
        .filter(Boolean).slice(0, 3) as GroundingSource[];
    }
    return result as LocalizationResult;
  });
};

export const generateImage = async (visualPrompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ text: `A literal, high-definition photo representing: ${visualPrompt}. Realistic style.` }] },
      config: { imageConfig: { aspectRatio: "16:9" } },
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Visuals failed.");
  });
};

export const generateSpeech = async (text: string, voiceName: 'Puck' | 'Kore'): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const sanitized = text.replace(/[^\u0600-\u06FF\s0-9،؛؟.!]/g, ' ').trim();
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: sanitized }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName } } },
      },
    });
    const audioData = response.candidates?.[0]?.content?.parts.find(p => p.inlineData)?.inlineData?.data;
    if (!audioData) throw new Error("No audio returned");
    return audioData;
  });
};

export const getExpertAnalysis = async (dariText: string, sourceText: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `Expert analysis: Dari "${dariText}" vs Source "${sourceText}". Focus on Afghan linguistics.`,
    config: { systemInstruction: "You are an expert Afghan linguist." }
  });
  return response.text || "Analysis unavailable.";
};

export const localizeFile = async (base64: string, mimeType: string, prompt: string, tone: TranslationTone): Promise<LocalizationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: [{ inlineData: { data: base64, mimeType: mimeType } }, { text: prompt }],
    config: { systemInstruction: SYSTEM_INSTRUCTION, responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{}');
};

export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
  return bytes;
}

export async function decodePCM(data: Uint8Array, ctx: AudioContext, sampleRate = 24000, numChannels = 1): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, data.byteLength / 2);
  const buffer = ctx.createBuffer(numChannels, dataInt16.length / numChannels, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < channelData.length; i++) channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
  }
  return buffer;
}

import React, { useState, useRef, useEffect } from 'react';
import { LocalizationResult } from '../types';
import { generateSpeech, decodeBase64, decodePCM, generateImage, getExpertAnalysis } from '../services/geminiService';

interface Props {
  result: LocalizationResult;
  sourceText?: string;
}

const WebImage = ({ url, fallbackUri, title }: { url?: string; fallbackUri?: string; title: string }) => {
  const [src, setSrc] = useState<string | undefined>(url);
  const [loading, setLoading] = useState(true);
  const [useScreenshot, setUseScreenshot] = useState(false);

  useEffect(() => {
    if (url) {
      setSrc(url);
    } else if (fallbackUri) {
      setSrc(`https://image.thum.io/get/width/600/crop/600/noanimate/${fallbackUri}`);
      setUseScreenshot(true);
    }
  }, [url, fallbackUri]);

  const handleImageError = () => {
    if (!useScreenshot && fallbackUri) {
      setSrc(`https://image.thum.io/get/width/600/crop/600/noanimate/${fallbackUri}`);
      setUseScreenshot(true);
    } else {
      setSrc(undefined);
      setLoading(false);
    }
  };

  const getFavicon = (uri?: string) => {
    if (!uri) return null;
    try {
      const domain = new URL(uri).hostname;
      return `https://www.google.com/s2/favicons?domain=${domain}&sz=128`;
    } catch { return null; }
  };

  if (!src) {
    const favicon = getFavicon(fallbackUri);
    return (
      <div className="flex flex-col items-center justify-center h-full w-full bg-gray-50/50 p-3 border-r border-gray-100 last:border-0">
        {favicon ? <img src={favicon} className="w-6 h-6 mb-2 grayscale opacity-50" alt="" /> : <div className="w-6 h-6 bg-gray-200 rounded-full mb-2" />}
        <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest truncate w-full text-center">{title}</span>
      </div>
    );
  }

  return (
    <div className="relative w-full h-full bg-gray-100 group overflow-hidden border-r border-gray-100 last:border-0">
      <a href={fallbackUri || src} target="_blank" rel="noreferrer" className="block w-full h-full">
        <img 
          src={src} 
          alt={title} 
          className={`w-full h-full object-cover transition-all duration-700 group-hover:scale-110 ${loading ? 'opacity-0' : 'opacity-100'}`}
          onError={handleImageError}
          onLoad={() => setLoading(false)}
        />
        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center p-2">
          <p className="text-[9px] text-white font-black text-center uppercase tracking-tighter leading-tight">{title}</p>
        </div>
      </a>
    </div>
  );
};

const ResultView: React.FC<Props> = ({ result: initialResult, sourceText }) => {
  const [result, setResult] = useState<LocalizationResult>(initialResult);
  const [playingVoice, setPlayingVoice] = useState<'Puck' | 'Kore' | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [imageLoading, setImageLoading] = useState(false);
  const audioCtxRef = useRef<AudioContext | null>(null);

  useEffect(() => {
    if (result.visualPrompt && !result.imageUrl && !imageLoading) {
      handleGenerateImage(result.visualPrompt);
    }
  }, [result.visualPrompt]);

  const handleGenerateImage = async (prompt: string) => {
    setImageLoading(true);
    try {
      const imageUrl = await generateImage(prompt);
      setResult(prev => ({ ...prev, imageUrl }));
    } catch (err) { console.error(err); } finally { setImageLoading(false); }
  };

  const handleExpertAnalysis = async () => {
    if (!sourceText || isAnalyzing) return;
    setIsAnalyzing(true);
    try {
      const analysis = await getExpertAnalysis(result.dariTranslation, sourceText);
      setResult(prev => ({ ...prev, expertAnalysis: analysis }));
    } catch (err) { console.error(err); } finally { setIsAnalyzing(false); }
  };

  const handlePlayVoice = async (voiceName: 'Puck' | 'Kore') => {
    if (playingVoice) return;
    try {
      setPlayingVoice(voiceName);
      const base64 = await generateSpeech(result.dariTranslation, voiceName);
      if (!audioCtxRef.current) audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const ctx = audioCtxRef.current;
      if (ctx.state === 'suspended') await ctx.resume();
      const audioData = decodeBase64(base64);
      const audioBuffer = await decodePCM(audioData, ctx);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.onended = () => setPlayingVoice(null);
      source.start(0);
    } catch (error) { setPlayingVoice(null); }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-8 duration-700 fill-mode-both">
      <div className="bg-white rounded-[3rem] shadow-2xl shadow-emerald-900/5 border border-gray-100 overflow-hidden">
        {/* Main Visual */}
        <div className="relative w-full aspect-[21/9] bg-gray-50 flex items-center justify-center overflow-hidden">
          {imageLoading ? (
            <div className="w-full h-full flex flex-col items-center justify-center space-y-4">
              <div className="w-12 h-12 border-4 border-emerald-100 border-t-emerald-600 rounded-full animate-spin" />
              <span className="text-[10px] font-black uppercase tracking-widest text-emerald-600 animate-pulse">Generating Scene...</span>
            </div>
          ) : result.imageUrl ? (
            <img src={result.imageUrl} className="w-full h-full object-cover" alt="Point Visual" />
          ) : (
            <div className="text-gray-200 font-black uppercase text-[11px] tracking-[0.3em]">Literal Context Awaiting...</div>
          )}
          <div className="absolute top-6 left-6 bg-white/90 backdrop-blur-md px-4 py-2 rounded-2xl border border-gray-100 shadow-sm">
            <span className="text-[10px] font-black text-gray-900 uppercase tracking-widest">Semantic Point</span>
          </div>
        </div>

        {/* Web Grounding Strip */}
        {result.groundingSources && result.groundingSources.length > 0 && (
          <div className="grid grid-cols-3 h-24 sm:h-32 bg-gray-100 border-b border-gray-100">
            {[0, 1, 2].map(i => (
              <WebImage 
                key={i}
                url={result.webRefImages?.[i]} 
                fallbackUri={result.groundingSources?.[i]?.uri} 
                title={result.groundingSources?.[i]?.title || "Grounding Source"} 
              />
            ))}
          </div>
        )}

        <div className="p-8 sm:p-12 space-y-12">
          {/* Translation Section */}
          <section className="space-y-8">
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-2">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
                <span className="text-[10px] font-black uppercase tracking-widest text-emerald-600">Verified Native Output</span>
              </div>
              <div className="flex space-x-4">
                <button onClick={() => handlePlayVoice('Puck')} className={`w-14 h-14 rounded-2xl transition-all shadow-lg flex items-center justify-center ${playingVoice === 'Puck' ? 'bg-blue-600 text-white scale-95' : 'bg-blue-50 text-blue-600 hover:bg-blue-100'}`}>
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z"/></svg>
                </button>
                <button onClick={() => handlePlayVoice('Kore')} className={`w-14 h-14 rounded-2xl transition-all shadow-lg flex items-center justify-center ${playingVoice === 'Kore' ? 'bg-emerald-600 text-white scale-95' : 'bg-emerald-50 text-emerald-600 hover:bg-emerald-100'}`}>
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.707-3.707a1 1 0 011.09-.217zM14.657 2.929a1 1 0 011.414 0A9.972 9.972 0 0119 10a9.972 9.972 0 01-2.929 7.071 1 1 0 01-1.414-1.414A7.971 7.971 0 0017 10c0-2.21-.894-4.208-2.343-5.657a1 1 0 010-1.414zm-2.829 2.828a1 1 0 011.415 0A5.983 5.983 0 0115 10a5.984 5.984 0 01-1.757 4.243 1 1 0 01-1.415-1.415A3.984 3.984 0 0013 10a3.983 3.983 0 00-1.172-2.828 1 1 0 010-1.415z" clipRule="evenodd"/></svg>
                </button>
              </div>
            </div>

            <div className="bg-slate-50 rounded-[2.5rem] p-10 sm:p-14 border border-slate-100 relative group transition-all hover:bg-white hover:shadow-xl">
              <p className="text-5xl sm:text-6xl font-dari text-right leading-[1.7] text-gray-900" dir="rtl">{result.dariTranslation}</p>
              {result.transliteration && (
                <div className="mt-10 pt-8 border-t border-slate-200 flex items-start space-x-4">
                  <span className="text-[10px] font-black uppercase text-slate-300 mt-1">Phonetic</span>
                  <p className="text-lg text-slate-500 font-medium italic tracking-wide">{result.transliteration}</p>
                </div>
              )}
            </div>
          </section>

          {/* Expert Breakdown */}
          <section className="space-y-6 pt-6 border-t border-gray-100">
            <div className="flex items-center justify-between">
              <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-gray-400">Localization Strategy</h3>
              <button onClick={handleExpertAnalysis} disabled={isAnalyzing} className="px-6 py-2 bg-gray-900 text-white text-[10px] font-black uppercase tracking-widest rounded-full hover:bg-black transition-all">
                {isAnalyzing ? "Processing..." : "Expert Breakdown"}
              </button>
            </div>

            {result.expertAnalysis && (
              <div className="bg-blue-50/50 p-8 rounded-[2rem] border border-blue-100 animate-in slide-in-from-top-4 duration-500">
                <span className="block mb-3 text-[9px] font-black text-blue-600 uppercase tracking-widest">Linguistic Analysis</span>
                <p className="text-sm text-blue-900 leading-relaxed font-medium">{result.expertAnalysis}</p>
              </div>
            )}

            <div className="grid grid-cols-1 gap-4">
              {result.localizationNotes.map((note, i) => (
                <div key={i} className="flex items-center space-x-5 bg-gray-50/50 p-6 rounded-3xl border border-gray-100 transition-all hover:bg-white hover:shadow-md">
                  <div className="w-6 h-6 bg-emerald-100 text-emerald-700 rounded-full flex items-center justify-center text-[11px] font-black shrink-0">{i+1}</div>
                  <p className="text-sm text-gray-600 font-medium">{note}</p>
                </div>
              ))}
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

