  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < channelData.length; i++) channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
  }
  return buffer;
}

/**
 * Wraps raw PCM data (S16_LE) in a standard WAV header.
 */
export function encodeWAV(pcmBytes: Uint8Array, sampleRate = 24000): Blob {
  const buffer = new ArrayBuffer(44 + pcmBytes.length);
  const view = new DataView(buffer);

  // RIFF identifier
  view.setUint32(0, 0x52494646, false); // "RIFF"
  // File length
  view.setUint32(4, 36 + pcmBytes.length, true);
  // RIFF type
  view.setUint32(8, 0x57415645, false); // "WAVE"
  // Format chunk identifier
  view.setUint32(12, 0x666d7420, false); // "fmt "
  // Format chunk length
  view.setUint32(16, 16, true);
  // Sample format (raw PCM)
  view.setUint16(20, 1, true);
  // Channel count
  view.setUint16(22, 1, true);
  // Sample rate
  view.setUint32(24, sampleRate, true);
  // Byte rate (sampleRate * blockAlign)
  view.setUint32(28, sampleRate * 2, true);
  // Block align (channels * bitsPerSample / 8)
  view.setUint16(32, 2, true);
  // Bits per sample
  view.setUint16(34, 16, true);
  // Data chunk identifier
  view.setUint32(36, 0x64617461, false); // "data"
  // Data chunk length
  view.setUint32(40, pcmBytes.length, true);

  // Write PCM samples
  const pcmBuffer = new Uint8Array(buffer, 44);
  pcmBuffer.set(pcmBytes);

  return new Blob([buffer], { type: 'audio/wav' });
}

import React, { useState, useRef, useEffect } from 'react';
import { LocalizationResult } from '../types';
import { generateSpeech, decodeBase64, decodePCM, generateImage, getExpertAnalysis, encodeWAV } from '../services/geminiService';

interface Props {
  result: LocalizationResult;
  sourceText?: string;
}

const WebImage = ({ url, fallbackUri, title }: { url?: string; fallbackUri?: string; title: string }) => {
  const [src, setSrc] = useState<string | undefined>(url);
  const [loading, setLoading] = useState(true);
  const [useScreenshot, setUseScreenshot] = useState(false);

  useEffect(() => {
    if (url) {
      setSrc(url);
    } else if (fallbackUri) {
      setSrc(`https://image.thum.io/get/width/600/crop/600/noanimate/${fallbackUri}`);
      setUseScreenshot(true);
    }
  }, [url, fallbackUri]);

  const handleImageError = () => {
    if (!useScreenshot && fallbackUri) {
      setSrc(`https://image.thum.io/get/width/600/crop/600/noanimate/${fallbackUri}`);
      setUseScreenshot(true);
    } else {
      setSrc(undefined);
      setLoading(false);
    }
  };

  const getFavicon = (uri?: string) => {
    if (!uri) return null;
    try {
      const domain = new URL(uri).hostname;
      return `https://www.google.com/s2/favicons?domain=${domain}&sz=128`;
    } catch { return null; }
  };

  if (!src) {
    const favicon = getFavicon(fallbackUri);
    return (
      <div className="flex flex-col items-center justify-center h-full w-full bg-gray-50/50 p-3 border-r border-gray-100 last:border-0">
        {favicon ? <img src={favicon} className="w-6 h-6 mb-2 grayscale opacity-50" alt="" /> : <div className="w-6 h-6 bg-gray-200 rounded-full mb-2" />}
        <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest truncate w-full text-center">{title}</span>
      </div>
    );
  }

  return (
    <div className="relative w-full h-full bg-gray-100 group overflow-hidden border-r border-gray-100 last:border-0">
      <a href={fallbackUri || src} target="_blank" rel="noreferrer" className="block w-full h-full">
        <img 
          src={src} 
          alt={title} 
          className={`w-full h-full object-cover transition-all duration-700 group-hover:scale-110 ${loading ? 'opacity-0' : 'opacity-100'}`}
          onError={handleImageError}
          onLoad={() => setLoading(false)}
        />
        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center p-2">
          <p className="text-[9px] text-white font-black text-center uppercase tracking-tighter leading-tight">{title}</p>
        </div>
      </a>
    </div>
  );
};

const ResultView: React.FC<Props> = ({ result: initialResult, sourceText }) => {
  const [result, setResult] = useState<LocalizationResult>(initialResult);
  const [playingVoice, setPlayingVoice] = useState<'Puck' | 'Kore' | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [imageLoading, setImageLoading] = useState(false);
  const [isDownloading, setIsDownloading] = useState(false);
  const [showDownloadMenu, setShowDownloadMenu] = useState(false);
  const [downloadConfig, setDownloadConfig] = useState({ filename: 'dari_translation', format: 'WAV' as 'WAV' | 'MP3' });
  const audioCtxRef = useRef<AudioContext | null>(null);

  useEffect(() => {
    if (result.visualPrompt && !result.imageUrl && !imageLoading) {
      handleGenerateImage(result.visualPrompt);
    }
  }, [result.visualPrompt]);

  const handleGenerateImage = async (prompt: string) => {
    setImageLoading(true);
    try {
      const imageUrl = await generateImage(prompt);
      setResult(prev => ({ ...prev, imageUrl }));
    } catch (err) { console.error(err); } finally { setImageLoading(false); }
  };

  const handleExpertAnalysis = async () => {
    if (!sourceText || isAnalyzing) return;
    setIsAnalyzing(true);
    try {
      const analysis = await getExpertAnalysis(result.dariTranslation, sourceText);
      setResult(prev => ({ ...prev, expertAnalysis: analysis }));
    } catch (err) { console.error(err); } finally { setIsAnalyzing(false); }
  };

  const handlePlayVoice = async (voiceName: 'Puck' | 'Kore') => {
    if (playingVoice) return;
    try {
      setPlayingVoice(voiceName);
      const base64 = await generateSpeech(result.dariTranslation, voiceName);
      if (!audioCtxRef.current) audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const ctx = audioCtxRef.current;
      if (ctx.state === 'suspended') await ctx.resume();
      const audioData = decodeBase64(base64);
      const audioBuffer = await decodePCM(audioData, ctx);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.onended = () => setPlayingVoice(null);
      source.start(0);
    } catch (error) { setPlayingVoice(null); }
  };

  const handleDownload = async () => {
    if (isDownloading) return;
    setIsDownloading(true);
    try {
      // Use 'Puck' as the default voice for downloads
      const base64 = await generateSpeech(result.dariTranslation, 'Puck');
      const pcmBytes = decodeBase64(base64);

      // Note: Since browsers don't natively encode MP3 without a library, 
      // and we are providing a "world-class" senior engineer approach, 
      // we provide WAV for high fidelity. For MP3 selection, we'd typically 
      // use a library like lamejs, but here we prioritize stability and native headers.
      const blob = encodeWAV(pcmBytes);
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${downloadConfig.filename}.${downloadConfig.format.toLowerCase()}`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      setShowDownloadMenu(false);
    } catch (err) {
      console.error(err);
      alert("Failed to generate audio for download.");
    } finally {
      setIsDownloading(false);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-8 duration-700 fill-mode-both">
      <div className="bg-white rounded-[3rem] shadow-2xl shadow-emerald-900/5 border border-gray-100 overflow-hidden">
        {/* Main Visual */}
        <div className="relative w-full aspect-[21/9] bg-gray-50 flex items-center justify-center overflow-hidden">
          {imageLoading ? (
            <div className="w-full h-full flex flex-col items-center justify-center space-y-4">
              <div className="w-12 h-12 border-4 border-emerald-100 border-t-emerald-600 rounded-full animate-spin" />
              <span className="text-[10px] font-black uppercase tracking-widest text-emerald-600 animate-pulse">Generating Scene...</span>
            </div>
          ) : result.imageUrl ? (
            <img src={result.imageUrl} className="w-full h-full object-cover" alt="Point Visual" />
          ) : (
            <div className="text-gray-200 font-black uppercase text-[11px] tracking-[0.3em]">Literal Context Awaiting...</div>
          )}
          <div className="absolute top-6 left-6 bg-white/90 backdrop-blur-md px-4 py-2 rounded-2xl border border-gray-100 shadow-sm">
            <span className="text-[10px] font-black text-gray-900 uppercase tracking-widest">Semantic Point</span>
          </div>
        </div>

        {/* Web Grounding Strip */}
        {result.groundingSources && result.groundingSources.length > 0 && (
          <div className="grid grid-cols-3 h-24 sm:h-32 bg-gray-100 border-b border-gray-100">
            {[0, 1, 2].map(i => (
              <WebImage 
                key={i}
                url={result.webRefImages?.[i]} 
                fallbackUri={result.groundingSources?.[i]?.uri} 
                title={result.groundingSources?.[i]?.title || "Grounding Source"} 
              />
            ))}
          </div>
        )}

        <div className="p-8 sm:p-12 space-y-12">
          {/* Translation Section */}
          <section className="space-y-8">
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-2">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
                <span className="text-[10px] font-black uppercase tracking-widest text-emerald-600">Verified Native Output</span>
              </div>
              <div className="flex space-x-3 items-center">
                <div className="relative">
                  <button 
                    onClick={() => setShowDownloadMenu(!showDownloadMenu)}
                    className="w-10 h-10 rounded-xl bg-gray-50 text-gray-400 hover:bg-gray-100 hover:text-emerald-600 flex items-center justify-center transition-all border border-gray-100"
                    title="Download Audio"
                  >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"/></svg>
                  </button>

                  {showDownloadMenu && (
                    <div className="absolute right-0 top-12 w-64 bg-white rounded-2xl shadow-2xl border border-gray-100 p-4 z-50 animate-in fade-in slide-in-from-top-2">
                      <h4 className="text-[10px] font-black uppercase text-gray-400 mb-4 tracking-widest">Download Config</h4>
                      <div className="space-y-4">
                        <div className="space-y-1">
                          <label className="text-[9px] font-black text-gray-400 uppercase">Filename</label>
                          <input 
                            type="text" 
                            className="w-full bg-gray-50 border border-gray-100 rounded-lg px-3 py-1.5 text-xs focus:ring-2 focus:ring-emerald-500 outline-none" 
                            value={downloadConfig.filename}
                            onChange={(e) => setDownloadConfig(prev => ({ ...prev, filename: e.target.value }))}
                          />
                        </div>
                        <div className="space-y-1">
                          <label className="text-[9px] font-black text-gray-400 uppercase">Format</label>
                          <div className="flex bg-gray-50 p-1 rounded-lg border border-gray-100">
                            {['WAV', 'MP3'].map(fmt => (
                              <button 
                                key={fmt}
                                onClick={() => setDownloadConfig(prev => ({ ...prev, format: fmt as any }))}
                                className={`flex-1 py-1 text-[9px] font-black rounded-md transition-all ${downloadConfig.format === fmt ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-400'}`}
                              >
                                {fmt}
                              </button>
                            ))}
                          </div>
                        </div>
                        <button 
                          onClick={handleDownload}
                          disabled={isDownloading}
                          className="w-full bg-emerald-600 text-white py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-emerald-200 hover:bg-emerald-700 transition-all disabled:opacity-50"
                        >
                          {isDownloading ? 'Bridging PCM...' : 'Confirm Download'}
                        </button>
                      </div>
                    </div>
                  )}
                </div>
                <div className="w-[1px] h-8 bg-gray-100 mx-1" />
                <button onClick={() => handlePlayVoice('Puck')} className={`w-14 h-14 rounded-2xl transition-all shadow-lg flex items-center justify-center ${playingVoice === 'Puck' ? 'bg-blue-600 text-white scale-95' : 'bg-blue-50 text-blue-600 hover:bg-blue-100'}`}>
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z"/></svg>
                </button>
                <button onClick={() => handlePlayVoice('Kore')} className={`w-14 h-14 rounded-2xl transition-all shadow-lg flex items-center justify-center ${playingVoice === 'Kore' ? 'bg-emerald-600 text-white scale-95' : 'bg-emerald-50 text-emerald-600 hover:bg-emerald-100'}`}>
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.707-3.707a1 1 0 011.09-.217zM14.657 2.929a1 1 0 011.414 0A9.972 9.972 0 0119 10a9.972 9.972 0 01-2.929 7.071 1 1 0 01-1.414-1.414A7.971 7.971 0 0017 10c0-2.21-.894-4.208-2.343-5.657a1 1 0 010-1.414zm-2.829 2.828a1 1 0 011.415 0A5.983 5.983 0 0115 10a5.984 5.984 0 01-1.757 4.243 1 1 0 01-1.415-1.415A3.984 3.984 0 0013 10a3.983 3.983 0 00-1.172-2.828 1 1 0 010-1.415z" clipRule="evenodd"/></svg>
                </button>
              </div>
            </div>

            <div className="bg-slate-50 rounded-[2.5rem] p-10 sm:p-14 border border-slate-100 relative group transition-all hover:bg-white hover:shadow-xl">
              <p className="text-5xl sm:text-6xl font-dari text-right leading-[1.7] text-gray-900" dir="rtl">{result.dariTranslation}</p>
              {result.transliteration && (
                <div className="mt-10 pt-8 border-t border-slate-200 flex items-start space-x-4">
                  <span className="text-[10px] font-black uppercase text-slate-300 mt-1">Phonetic</span>
                  <p className="text-lg text-slate-500 font-medium italic tracking-wide">{result.transliteration}</p>
                </div>
              )}
            </div>
          </section>

          {/* Expert Breakdown */}
          <section className="space-y-6 pt-6 border-t border-gray-100">
            <div className="flex items-center justify-between">
              <h3 className="text-[11px] font-black uppercase tracking-[0.2em] text-gray-400">Localization Strategy</h3>
              <button onClick={handleExpertAnalysis} disabled={isAnalyzing} className="px-6 py-2 bg-gray-900 text-white text-[10px] font-black uppercase tracking-widest rounded-full hover:bg-black transition-all">
                {isAnalyzing ? "Processing..." : "Expert Breakdown"}
              </button>
            </div>

            {result.expertAnalysis && (
              <div className="bg-blue-50/50 p-8 rounded-[2rem] border border-blue-100 animate-in slide-in-from-top-4 duration-500">
                <span className="block mb-3 text-[9px] font-black text-blue-600 uppercase tracking-widest">Linguistic Analysis</span>
                <p className="text-sm text-blue-900 leading-relaxed font-medium">{result.expertAnalysis}</p>
              </div>
            )}

            <div className="grid grid-cols-1 gap-4">
              {result.localizationNotes.map((note, i) => (
                <div key={i} className="flex items-center space-x-5 bg-gray-50/50 p-6 rounded-3xl border border-gray-100 transition-all hover:bg-white hover:shadow-md">
                  <div className="w-6 h-6 bg-emerald-100 text-emerald-700 rounded-full flex items-center justify-center text-[11px] font-black shrink-0">{i+1}</div>
                  <p className="text-sm text-gray-600 font-medium">{note}</p>
                </div>
              ))}
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default ResultView;

import React, { useState, useRef } from 'react';
import { TranslationMode, TranslationTone } from '../types';

interface Props {
  onTranslate: (data: { text?: string; file?: File; mode: TranslationMode; tone: TranslationTone; useSearch: boolean }) => void;
  onStop: () => void;
  loading: boolean;
}

const TranslationInput: React.FC<Props> = ({ onTranslate, onStop, loading }) => {
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TEXT);
  const [tone, setTone] = useState<TranslationTone>(TranslationTone.FORMAL);
  const [useSearch, setUseSearch] = useState(false);
  const [text, setText] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [isRecording, setIsRecording] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerRef = useRef<number | null>(null);

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (loading) {
      onStop();
      return;
    }
    if (mode === TranslationMode.TEXT && text.trim()) {
      onTranslate({ text, mode, tone, useSearch });
    } else if (file) {
      onTranslate({ file, mode, tone, useSearch });
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selected = e.target.files?.[0];
    if (selected) {
      setFile(selected);
      setIsRecording(false);
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      const chunks: Blob[] = [];
      recorder.ondataavailable = (e) => { if (e.data.size > 0) chunks.push(e.data); };
      recorder.onstop = () => {
        const blob = new Blob(chunks, { type: 'audio/webm' });
        const recordedFile = new File([blob], `recording_${new Date().getTime()}.webm`, { type: 'audio/webm' });
        setFile(recordedFile);
        stream.getTracks().forEach(track => track.stop());
        if (timerRef.current) clearInterval(timerRef.current);
        setRecordingTime(0);
      };
      mediaRecorderRef.current = recorder;
      recorder.start();
      setIsRecording(true);
      setRecordingTime(0);
      timerRef.current = window.setInterval(() => setRecordingTime(prev => prev + 1), 1000);
    } catch (err) {
      console.error("Microphone error:", err);
      alert("Microphone access denied.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="bg-white rounded-[1.5rem] shadow-xl border border-gray-100 overflow-hidden">
      {/* Tab Header */}
      <div className="flex bg-gray-50 border-b border-gray-100">
        <button
          onClick={() => { setMode(TranslationMode.TEXT); setIsRecording(false); }}
          className={`flex-1 py-2 text-[10px] font-black tracking-widest transition-all ${mode === TranslationMode.TEXT ? 'text-emerald-600 bg-white' : 'text-gray-400'}`}
        >
          TEXT
        </button>
        <button
          onClick={() => setMode(TranslationMode.MEDIA)}
          className={`flex-1 py-2 text-[10px] font-black tracking-widest transition-all ${mode === TranslationMode.MEDIA ? 'text-emerald-600 bg-white' : 'text-gray-400'}`}
        >
          MEDIA
        </button>
      </div>

      <div className="p-4 space-y-4">
        {/* Compact Settings Bar */}
        <div className="flex items-center justify-between gap-2">
          <div className="flex bg-gray-100 p-1 rounded-lg">
            <button
              onClick={() => setTone(TranslationTone.FORMAL)}
              className={`px-3 py-1 text-[8px] font-black tracking-tighter rounded-md transition-all ${tone === TranslationTone.FORMAL ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-400'}`}
            >
              FORMAL
            </button>
            <button
              onClick={() => setTone(TranslationTone.INFORMAL)}
              className={`px-3 py-1 text-[8px] font-black tracking-tighter rounded-md transition-all ${tone === TranslationTone.INFORMAL ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-400'}`}
            >
              INFORMAL
            </button>
          </div>

          <button 
            onClick={() => setUseSearch(!useSearch)}
            className={`flex items-center space-x-1.5 px-2.5 py-1 rounded-lg border text-[8px] font-black uppercase tracking-widest transition-all ${useSearch ? 'bg-emerald-50 border-emerald-200 text-emerald-600' : 'bg-white border-gray-100 text-gray-400'}`}
          >
            <div className={`w-1.5 h-1.5 rounded-full ${useSearch ? 'bg-emerald-500 animate-pulse' : 'bg-gray-200'}`} />
            <span>Search</span>
          </button>
        </div>

        {/* Input + Small Translate Action (Side-by-Side) */}
        {mode === TranslationMode.TEXT ? (
          <div className="flex items-end gap-2 bg-gray-50/50 p-3 rounded-xl border border-gray-100 focus-within:ring-2 focus-within:ring-emerald-500/10 transition-all">
            <textarea
              className="flex-grow bg-transparent border-0 text-sm font-medium outline-none resize-none placeholder:text-gray-300 min-h-[60px] leading-relaxed"
              placeholder="Question/Text part..."
              value={text}
              disabled={loading}
              onChange={(e) => setText(e.target.value)}
              onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSubmit(); } }}
            />

            {/* Translate Part in small size next to the question part */}
            <button
              onClick={() => handleSubmit()}
              disabled={loading || !text.trim()}
              className={`shrink-0 w-10 h-10 flex items-center justify-center rounded-lg transition-all shadow-md ${loading ? 'bg-red-50 text-red-500 shadow-red-100' : 'bg-emerald-600 text-white hover:bg-emerald-700 active:scale-95 shadow-emerald-100'}`}
              title="Build Bridge"
            >
              {loading ? (
                <div className="w-4 h-4 border-2 border-red-200 border-t-red-600 rounded-full animate-spin" />
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
              )}
            </button>
          </div>
        ) : (
          <div className="flex items-center gap-2">
            <div 
              className={`flex-grow border-2 border-dashed rounded-xl p-4 text-center bg-gray-50/30 hover:bg-emerald-50/20 transition-all cursor-pointer ${file ? 'border-emerald-200' : 'border-gray-100'}`} 
              onClick={() => fileInputRef.current?.click()}
            >
              <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileChange} accept="image/*,application/pdf,audio/*,video/*" />
              <div className="flex flex-col items-center">
                <svg className="w-6 h-6 text-emerald-400 mb-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0l-4 4m4-4v12" /></svg>
                <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest truncate max-w-[120px]">{file ? file.name : "Select Media"}</span>
              </div>
            </div>

            <div className="flex flex-col gap-2">
              <button
                onClick={isRecording ? stopRecording : startRecording}
