import React, { useState, useRef, useEffect } from 'react';
import { LocalizationResult } from '../types';
import { generateSpeech, decodeBase64, decodePCM, generateImage, getExpertAnalysis, encodeWAV } from '../services/geminiService';

interface Props {
  result: LocalizationResult;
  sourceText?: string;
}

const WebImage = ({ url, fallbackUri, title }: { url?: string; fallbackUri?: string; title: string }) => {
  const [src, setSrc] = useState<string | undefined>(url);
  const [isLoaded, setIsLoaded] = useState(false);
  const [progress, setProgress] = useState(0);
  const [error, setError] = useState(false);
  const [useScreenshot, setUseScreenshot] = useState(false);

  // Simulated high-fidelity progress loader
  useEffect(() => {
    if (!isLoaded && !error) {
      const startTime = Date.now();
      const duration = 1200 + Math.random() * 800; // Randomly 1.2s to 2s base duration

      const timer = setInterval(() => {
        const elapsed = Date.now() - startTime;
        const rawProgress = Math.min((elapsed / duration) * 100, 98);

        // Easing function for a more "organic" feel
        const easedProgress = rawProgress + (Math.sin(elapsed / 200) * 2);
        setProgress(Math.max(0, Math.min(98, easedProgress)));
      }, 50);

      return () => clearInterval(timer);
    }
  }, [isLoaded, error]);

  useEffect(() => {
    if (url) {
      setSrc(url);
    } else if (fallbackUri) {
      setSrc(`https://image.thum.io/get/width/600/crop/600/noanimate/${fallbackUri}`);
      setUseScreenshot(true);
    }
  }, [url, fallbackUri]);

  const handleImageLoad = () => {
    setProgress(100);
    setTimeout(() => setIsLoaded(true), 200); // Small delay to show 100% completion
  };

  const handleImageError = () => {
    if (!useScreenshot && fallbackUri) {
      setSrc(`https://image.thum.io/get/width/600/crop/600/noanimate/${fallbackUri}`);
      setUseScreenshot(true);
    } else {
      setError(true);
      setIsLoaded(false);
    }
  };

  const getFavicon = (uri?: string) => {
    if (!uri) return null;
    try {
      const domain = new URL(uri).hostname;
      return `https://www.google.com/s2/favicons?domain=${domain}&sz=128`;
    } catch { return null; }
  };

  if (error) {
    const favicon = getFavicon(fallbackUri);
    return (
      <div className="flex flex-col items-center justify-center h-full w-full bg-gray-50/50 p-4 border-r border-gray-100 last:border-0">
        {favicon ? <img src={favicon} className="w-5 h-5 mb-2 grayscale opacity-40" alt="" /> : <div className="w-5 h-5 bg-gray-200 rounded-full mb-2" />}
        <span className="text-[7px] font-black text-gray-400 uppercase tracking-widest truncate w-full text-center leading-tight">{title}</span>
      </div>
    );
  }

  return (
    <div className="relative w-full h-full bg-slate-50 group overflow-hidden border-r border-gray-100 last:border-0 cursor-pointer">
      <a href={fallbackUri || src} target="_blank" rel="noreferrer" className="block w-full h-full relative">
        {/* Skeleton Layer */}
        {!isLoaded && (
          <div className="absolute inset-0 z-10 flex flex-col items-center justify-center bg-slate-50 overflow-hidden">
            {/* Shimmer Effect */}
            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/40 to-transparent -translate-x-full animate-[shimmer_2s_infinite]" />

            <div className="relative flex flex-col items-center">
              <div className="text-[10px] font-black text-emerald-600/80 font-mono tracking-tighter">
                {Math.floor(progress)}%
              </div>
              <div className="w-12 h-1 bg-emerald-100 rounded-full mt-2 overflow-hidden">
                <div 
                  className="h-full bg-emerald-500 transition-all duration-300 ease-out" 
                  style={{ width: `${progress}%` }}
                />
              </div>
            </div>
            <span className="mt-3 text-[7px] font-black text-slate-300 uppercase tracking-[0.2em] animate-pulse">Fetching Assets</span>
          </div>
        )}

        <img 
          src={src} 
          alt={title} 
          loading="lazy"
          className={`w-full h-full object-cover transition-all duration-1000 group-hover:scale-110 ${isLoaded ? 'opacity-100' : 'opacity-0 scale-105'}`}
          onError={handleImageError}
          onLoad={handleImageLoad}
        />

        {/* Optimized Overlay */}
        <div className={`absolute inset-0 bg-emerald-900/60 transition-opacity duration-300 flex flex-col items-center justify-center p-3 text-center ${isLoaded ? 'opacity-0 group-hover:opacity-100' : 'opacity-0'}`}>
          <svg className="w-4 h-4 text-emerald-200 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"/>
          </svg>
          <p className="text-[8px] text-white font-black uppercase tracking-tighter leading-none px-1 line-clamp-2">{title}</p>
        </div>
      </a>

      <style>{`
        @keyframes shimmer {
          100% { transform: translateX(100%); }
        }
      `}</style>
    </div>
  );
};

const ResultView: React.FC<Props> = ({ result: initialResult, sourceText }) => {
  const [result, setResult] = useState<LocalizationResult>(initialResult);
  const [playingVoice, setPlayingVoice] = useState<'Puck' | 'Kore' | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [imageLoading, setImageLoading] = useState(false);
  const [isDownloading, setIsDownloading] = useState(false);
  const [showDownloadMenu, setShowDownloadMenu] = useState(false);
  const [downloadConfig, setDownloadConfig] = useState({ filename: 'dari_bridge_export', format: 'WAV' as 'WAV' | 'MP3' });
  const audioCtxRef = useRef<AudioContext | null>(null);

  useEffect(() => {
    if (result.visualPrompt && !result.imageUrl && !imageLoading) {
      handleGenerateImage(result.visualPrompt);
    }
  }, [result.visualPrompt]);

  const handleGenerateImage = async (prompt: string) => {
    setImageLoading(true);
    try {
      const imageUrl = await generateImage(prompt);
      setResult(prev => ({ ...prev, imageUrl }));
    } catch (err) { console.error(err); } finally { setImageLoading(false); }
  };

  const handleExpertAnalysis = async () => {
    if (!sourceText || isAnalyzing) return;
    setIsAnalyzing(true);
    try {
      const analysis = await getExpertAnalysis(result.dariTranslation, sourceText);
      setResult(prev => ({ ...prev, expertAnalysis: analysis }));
    } catch (err) { console.error(err); } finally { setIsAnalyzing(false); }
  };

  const handlePlayVoice = async (voiceName: 'Puck' | 'Kore') => {
    if (playingVoice) return;
    try {
      setPlayingVoice(voiceName);
      const base64 = await generateSpeech(result.dariTranslation, voiceName);
      if (!audioCtxRef.current) audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const ctx = audioCtxRef.current;
      if (ctx.state === 'suspended') await ctx.resume();
      const audioData = decodeBase64(base64);
      const audioBuffer = await decodePCM(audioData, ctx);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.onended = () => setPlayingVoice(null);
      source.start(0);
    } catch (error) { setPlayingVoice(null); }
  };

  const handleDownload = async () => {
    if (isDownloading) return;
    setIsDownloading(true);
    try {
      const base64 = await generateSpeech(result.dariTranslation, 'Puck');
      const pcmBytes = decodeBase64(base64);
      const blob = encodeWAV(pcmBytes);
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${downloadConfig.filename}.${downloadConfig.format.toLowerCase()}`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      setShowDownloadMenu(false);
    } catch (err) {
      console.error(err);
      alert("Export Failed.");
    } finally {
      setIsDownloading(false);
    }
  };

  return (
    <div className="space-y-4 animate-in fade-in slide-in-from-right-8 duration-700 fill-mode-both">
