          {imageLoading ? (
            <div className="w-full h-full flex flex-col items-center justify-center space-y-4 bg-slate-50">
              <div className="relative">
                <div className="w-12 h-12 border-4 border-emerald-50 border-t-emerald-600 rounded-full animate-spin" />
                <div className="absolute inset-0 flex items-center justify-center">
                  <div className="w-2 h-2 bg-emerald-600 rounded-full animate-ping" />
                </div>
              </div>
              <div className="flex flex-col items-center">
                <span className="text-[10px] font-black uppercase tracking-[0.3em] text-emerald-600">Visual Synthesis</span>
                <span className="text-[8px] font-bold uppercase tracking-widest text-slate-300 mt-1">Generating Context Layer</span>
              </div>
            </div>
          ) : result.imageUrl ? (
            <img src={result.imageUrl} className="w-full h-full object-cover animate-in fade-in duration-1000" alt="Point Visual" />
          ) : (
            <div className="text-gray-200 font-black uppercase text-[10px] tracking-[0.3em]">Bridge Visual Inactive</div>
