    <div className="space-y-4 animate-in fade-in slide-in-from-right-8 duration-700 fill-mode-both">
      <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/50 border border-gray-100 overflow-hidden">
        {/* Main Semantic Visual */}
        <div className="relative w-full aspect-[21/9] bg-slate-50 flex items-center justify-center overflow-hidden">
          {imageLoading ? (
            <div className="w-full h-full flex flex-col items-center justify-center space-y-4 bg-slate-50">
