import React, { useState, useRef } from 'react';
import { TranslationMode, TranslationTone } from '../types';

interface Props {
  onTranslate: (data: { text?: string; file?: File; mode: TranslationMode; tone: TranslationTone; useSearch: boolean }) => void;
  onStop: () => void;
  loading: boolean;
}

const TranslationInput: React.FC<Props> = ({ onTranslate, onStop, loading }) => {
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TEXT);
  const [tone, setTone] = useState<TranslationTone>(TranslationTone.INFORMAL);
  const [useSearch, setUseSearch] = useState(false);
  const [text, setText] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [isRecording, setIsRecording] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerRef = useRef<number | null>(null);

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (loading) {
      onStop();
      return;
    }
    if (mode === TranslationMode.TEXT && text.trim()) {
      onTranslate({ text, mode, tone, useSearch });
    } else if (file) {
      onTranslate({ file, mode, tone, useSearch });
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selected = e.target.files?.[0];
    if (selected) {
      setFile(selected);
      setIsRecording(false);
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      const chunks: Blob[] = [];
      recorder.ondataavailable = (e) => { if (e.data.size > 0) chunks.push(e.data); };
      recorder.onstop = () => {
        const blob = new Blob(chunks, { type: 'audio/webm' });
        const recordedFile = new File([blob], `recording_${new Date().getTime()}.webm`, { type: 'audio/webm' });
        setFile(recordedFile);
        stream.getTracks().forEach(track => track.stop());
        if (timerRef.current) clearInterval(timerRef.current);
        setRecordingTime(0);
      };
      mediaRecorderRef.current = recorder;
      recorder.start();
      setIsRecording(true);
      setRecordingTime(0);
      timerRef.current = window.setInterval(() => setRecordingTime(prev => prev + 1), 1000);
    } catch (err) {
      console.error("Microphone error:", err);
      alert("Microphone access denied.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="bg-white rounded-[1.5rem] shadow-xl border border-gray-100 overflow-hidden">
      {/* Tab Header */}
      <div className="flex bg-gray-50 border-b border-gray-100">
        <button
          onClick={() => { setMode(TranslationMode.TEXT); setIsRecording(false); }}
          className={`flex-1 py-2 text-[10px] font-black tracking-widest transition-all ${mode === TranslationMode.TEXT ? 'text-emerald-600 bg-white' : 'text-gray-400'}`}
        >
          TEXT
        </button>
        <button
          onClick={() => setMode(TranslationMode.MEDIA)}
          className={`flex-1 py-2 text-[10px] font-black tracking-widest transition-all ${mode === TranslationMode.MEDIA ? 'text-emerald-600 bg-white' : 'text-gray-400'}`}
        >
          MEDIA
        </button>
      </div>

      <div className="p-4 space-y-4">
        {/* Compact Settings Bar */}
        <div className="flex items-center justify-between gap-2">
          <div className="flex bg-gray-100 p-1 rounded-lg">
            <button
              onClick={() => setTone(TranslationTone.FORMAL)}
              className={`px-3 py-1 text-[8px] font-black tracking-tighter rounded-md transition-all ${tone === TranslationTone.FORMAL ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-400'}`}
            >
              FORMAL
            </button>
            <button
              onClick={() => setTone(TranslationTone.INFORMAL)}
              className={`px-3 py-1 text-[8px] font-black tracking-tighter rounded-md transition-all ${tone === TranslationTone.INFORMAL ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-400'}`}
            >
              INFORMAL
            </button>
          </div>

          <button 
            onClick={() => setUseSearch(!useSearch)}
            className={`flex items-center space-x-1.5 px-2.5 py-1 rounded-lg border text-[8px] font-black uppercase tracking-widest transition-all ${useSearch ? 'bg-emerald-50 border-emerald-200 text-emerald-600' : 'bg-white border-gray-100 text-gray-400'}`}
          >
            <div className={`w-1.5 h-1.5 rounded-full ${useSearch ? 'bg-emerald-500 animate-pulse' : 'bg-gray-200'}`} />
            <span>Search</span>
          </button>
        </div>

        {/* Input + Small Translate Action (Side-by-Side) */}
        {mode === TranslationMode.TEXT ? (
          <div className="flex items-end gap-2 bg-gray-50/50 p-3 rounded-xl border border-gray-100 focus-within:ring-2 focus-within:ring-emerald-500/10 transition-all">
            <textarea
              className="flex-grow bg-transparent border-0 text-sm font-medium outline-none resize-none placeholder:text-gray-300 min-h-[60px] leading-relaxed"
              placeholder="Question/Text part..."
              value={text}
              disabled={loading}
              onChange={(e) => setText(e.target.value)}
              onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSubmit(); } }}
            />

            {/* Translate Part in small size next to the question part */}
            <button
              onClick={() => handleSubmit()}
              disabled={loading || !text.trim()}
              className={`shrink-0 w-10 h-10 flex items-center justify-center rounded-lg transition-all shadow-md ${loading ? 'bg-red-50 text-red-500 shadow-red-100' : 'bg-emerald-600 text-white hover:bg-emerald-700 active:scale-95 shadow-emerald-100'}`}
              title="Build Bridge"
            >
              {loading ? (
                <div className="w-4 h-4 border-2 border-red-200 border-t-red-600 rounded-full animate-spin" />
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
              )}
            </button>
          </div>
        ) : (
          <div className="flex items-center gap-2">
            <div 
              className={`flex-grow border-2 border-dashed rounded-xl p-4 text-center bg-gray-50/30 hover:bg-emerald-50/20 transition-all cursor-pointer ${file ? 'border-emerald-200' : 'border-gray-100'}`} 
              onClick={() => fileInputRef.current?.click()}
            >
              <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileChange} accept="image/*,application/pdf,audio/*,video/*" />
              <div className="flex flex-col items-center">
                <svg className="w-6 h-6 text-emerald-400 mb-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0l-4 4m4-4v12" /></svg>
                <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest truncate max-w-[120px]">{file ? file.name : "Select Media"}</span>
              </div>
            </div>

            <div className="flex flex-col gap-2">
              <button
                onClick={isRecording ? stopRecording : startRecording}
                className={`w-10 h-10 rounded-lg flex items-center justify-center transition-all ${isRecording ? 'bg-red-500 text-white animate-pulse' : 'bg-gray-900 text-white hover:bg-black'}`}
              >
                {isRecording ? <div className="w-2 h-2 bg-white rounded-sm" /> : <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8V4a1 1 0 112 0v4a9 9 0 01-8 8.93V19a1 1 0 11-2 0v-2.07A9.001 9.001 0 011 8V4a1 1 0 012 0v4a7 7 0 0014 0z" clipRule="evenodd"/></svg>}
              </button>
              {isRecording && <span className="text-[8px] font-black text-red-500 animate-pulse text-center">{formatTime(recordingTime)}</span>}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default TranslationInput;

import React, { useState, useRef } from 'react';
import { LocalizationResult } from '../types';
import { generateSpeech, decodeBase64, decodePCM, getExpertAnalysis, encodeWAV } from '../services/geminiService';

interface Props {
  result: LocalizationResult;
  sourceText?: string;
}

const WebLink = ({ uri, title }: { uri: string; title: string }) => {
  const getDomain = (url: string) => {
    try {
      return new URL(url).hostname.replace('www.', '');
    } catch {
      return 'Source';
    }
  };

  return (
    <a 
      href={uri} 
      target="_blank" 
      rel="noreferrer" 
      className="group flex flex-col items-center justify-center p-4 bg-white border border-gray-100 rounded-2xl transition-all hover:border-emerald-500 hover:shadow-lg hover:shadow-emerald-500/5 text-center h-full"
    >
      <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-full flex items-center justify-center mb-3 group-hover:bg-emerald-600 group-hover:text-white transition-colors">
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"/>
        </svg>
      </div>
      <span className="text-[9px] font-black text-gray-900 uppercase tracking-tight line-clamp-2 leading-tight mb-1">{title}</span>
      <span className="text-[7px] font-bold text-gray-400 uppercase tracking-widest">{getDomain(uri)}</span>
    </a>
  );
};

const ResultView: React.FC<Props> = ({ result, sourceText }) => {
  const [playingVoice, setPlayingVoice] = useState<'Puck' | 'Kore' | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [expertAnalysis, setExpertAnalysis] = useState<string | undefined>(result.expertAnalysis);
  const [isDownloading, setIsDownloading] = useState(false);
  const [showDownloadMenu, setShowDownloadMenu] = useState(false);
  const [playbackSpeed, setPlaybackSpeed] = useState(1.0);
  const [downloadConfig, setDownloadConfig] = useState({ filename: 'dari_bridge_export', format: 'WAV' as 'WAV' | 'MP3' });
  const audioCtxRef = useRef<AudioContext | null>(null);

  const handleExpertAnalysis = async () => {
    if (!sourceText || isAnalyzing) return;
    setIsAnalyzing(true);
    try {
      const analysis = await getExpertAnalysis(result.dariTranslation, sourceText);
      setExpertAnalysis(analysis);
    } catch (err) { console.error(err); } finally { setIsAnalyzing(false); }
  };

  const handlePlayVoice = async (voiceName: 'Puck' | 'Kore') => {
    if (playingVoice) return;
    try {
      setPlayingVoice(voiceName);
      const base64 = await generateSpeech(result.dariTranslation, voiceName);
      if (!audioCtxRef.current) audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const ctx = audioCtxRef.current;
      if (ctx.state === 'suspended') await ctx.resume();
      const audioData = decodeBase64(base64);
      const audioBuffer = await decodePCM(audioData, ctx);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.playbackRate.value = playbackSpeed;
      source.connect(ctx.destination);
      source.onended = () => setPlayingVoice(null);
      source.start(0);
    } catch (error) { setPlayingVoice(null); }
  };

  const handleDownload = async () => {
    if (isDownloading) return;
    setIsDownloading(true);
    try {
      const base64 = await generateSpeech(result.dariTranslation, 'Puck');
      const pcmBytes = decodeBase64(base64);
      const blob = encodeWAV(pcmBytes);
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${downloadConfig.filename}.${downloadConfig.format.toLowerCase()}`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      setShowDownloadMenu(false);
    } catch (err) {
      console.error(err);
      alert("Export Failed.");
    } finally {
      setIsDownloading(false);
    }
  };

  return (
    <div className="space-y-4 animate-in fade-in slide-in-from-right-8 duration-700 fill-mode-both">
      <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/50 border border-gray-100 overflow-hidden">

        {/* Grounding Vector Section (Links only, no images) */}
        {result.groundingSources && result.groundingSources.length > 0 && (
          <div className="p-6 sm:p-10 pb-0 bg-slate-50/30 border-b border-gray-50">
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center space-x-2">
                <div className="w-8 h-8 rounded-xl bg-emerald-600 flex items-center justify-center text-white shadow-lg shadow-emerald-200">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.826a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1"/>
                  </svg>
                </div>
                <div>
                  <h3 className="text-[10px] font-black text-gray-900 uppercase tracking-widest leading-none">Factual Grounding</h3>
                  <p className="text-[8px] font-bold text-gray-400 uppercase tracking-tighter mt-1">External Web References</p>
                </div>
              </div>
              <span className="px-3 py-1 bg-white rounded-full border border-gray-100 text-[8px] font-black text-emerald-600 uppercase tracking-widest shadow-sm">
                3 Points Verified
              </span>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
              {result.groundingSources.slice(0, 3).map((source, i) => (
                <WebLink key={i} uri={source.uri} title={source.title} />
              ))}
            </div>
          </div>
        )}

        <div className="p-6 sm:p-10 space-y-10">
          {/* Main Translation Display */}
          <section className="space-y-6">
            <div className="flex items-center justify-between pb-4 border-b border-gray-50">
              <div className="flex items-center space-x-2">
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
                <span className="text-[9px] font-black uppercase tracking-widest text-emerald-600">Verified Native Bridge</span>
              </div>

              <div className="flex space-x-2 items-center">
                {/* Export Menu */}
                <div className="relative">
                  <button 
                    onClick={() => setShowDownloadMenu(!showDownloadMenu)}
                    className="w-9 h-9 rounded-xl bg-gray-50 text-gray-400 hover:bg-gray-100 hover:text-emerald-600 flex items-center justify-center transition-all border border-gray-100"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"/>
                    </svg>
                  </button>
                  {showDownloadMenu && (
                    <div className="absolute right-0 top-11 w-56 bg-white rounded-2xl shadow-2xl border border-gray-100 p-4 z-50 animate-in fade-in slide-in-from-top-2">
                      <div className="space-y-4">
                        <div className="space-y-1">
                          <label className="text-[8px] font-black text-gray-400 uppercase">Export Name</label>
                          <input 
                            type="text" 
                            className="w-full bg-gray-50 border border-gray-100 rounded-lg px-2 py-1 text-[10px] outline-none" 
                            value={downloadConfig.filename}
                            onChange={(e) => setDownloadConfig(prev => ({ ...prev, filename: e.target.value }))}
                          />
                        </div>
                        <div className="flex bg-gray-50 p-1 rounded-lg">
                          {['WAV', 'MP3'].map(fmt => (
                            <button 
                              key={fmt}
                              onClick={() => setDownloadConfig(prev => ({ ...prev, format: fmt as any }))}
                              className={`flex-1 py-1 text-[8px] font-black rounded-md transition-all ${downloadConfig.format === fmt ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-400'}`}
                            >
                              {fmt}
                            </button>
                          ))}
                        </div>
                        <button onClick={handleDownload} disabled={isDownloading} className="w-full bg-emerald-600 text-white py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all">
                          {isDownloading ? 'Synthesizing...' : 'Confirm Export'}
                        </button>
                      </div>
                    </div>
                  )}
                </div>

                <div className="w-[1px] h-6 bg-gray-100 mx-1" />

                {/* Playback Speed Control */}
                <div className="flex items-center space-x-1.5 bg-gray-50 px-2.5 py-1 rounded-xl border border-gray-100">
                  <span className="text-[8px] font-black text-gray-400 uppercase tracking-tighter">Speed</span>
                  <select 
                    value={playbackSpeed} 
                    onChange={(e) => setPlaybackSpeed(parseFloat(e.target.value))}
                    className="bg-transparent text-[10px] font-black text-emerald-600 outline-none cursor-pointer"
                  >
                    <option value="0.5">0.5x</option>
                    <option value="0.75">0.75x</option>
                    <option value="1.0">1x</option>
                    <option value="1.25">1.25x</option>
                    <option value="1.5">1.5x</option>
                  </select>
                </div>

                <div className="w-[1px] h-6 bg-gray-100 mx-1" />

                <button onClick={() => handlePlayVoice('Puck')} className={`w-11 h-11 rounded-xl transition-all shadow-md flex items-center justify-center ${playingVoice === 'Puck' ? 'bg-blue-600 text-white scale-95' : 'bg-blue-50 text-blue-600 hover:bg-blue-100'}`} title="Male Voice">
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z"/></svg>
                </button>
                <button onClick={() => handlePlayVoice('Kore')} className={`w-11 h-11 rounded-xl transition-all shadow-md flex items-center justify-center ${playingVoice === 'Kore' ? 'bg-emerald-600 text-white scale-95' : 'bg-emerald-50 text-emerald-600 hover:bg-emerald-100'}`} title="Female Voice">
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.707-3.707a1 1 0 011.09-.217zM14.657 2.929a1 1 0 011.414 0A9.972 9.972 0 0119 10a9.972 9.972 0 01-2.929 7.071 1 1 0 01-1.414-1.414A7.971 7.971 0 0017 10c0-2.21-.894-4.208-2.343-5.657a1 1 0 010-1.414zm-2.829 2.828a1 1 0 011.415 0A5.983 5.983 0 0115 10a5.984 5.984 0 01-1.757 4.243 1 1 0 01-1.415-1.415A3.984 3.984 0 0013 10a3.983 3.983 0 00-1.172-2.828 1 1 0 010-1.415z" clipRule="evenodd"/></svg>
                </button>
              </div>
            </div>

            {/* Split View: Question Area vs Translation Area */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 bg-slate-50/50 p-2 rounded-[2rem] border border-slate-100">
              {/* Question Area (Left/Top) */}
              <div className="p-6 bg-white/70 backdrop-blur-sm rounded-[1.5rem] border border-gray-100 flex flex-col h-full shadow-sm">
                <div className="flex items-center space-x-2 mb-4">
                  <div className="w-1.5 h-1.5 rounded-full bg-slate-300" />
                  <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Input Context</span>
                </div>
                <p className="text-sm text-gray-500 font-medium leading-relaxed italic overflow-auto max-h-[150px]">{sourceText || "Source metadata."}</p>
                <div className="mt-auto pt-6 flex items-center justify-between text-[8px] font-black uppercase text-slate-300 tracking-tighter">
                  <span>Source Fidelity Verified</span>
                </div>
              </div>

              {/* Translation Area (Right/Bottom) */}
              <div className="p-6 bg-white rounded-[1.5rem] shadow-sm border border-emerald-50 flex flex-col h-full">
                <div className="flex items-center space-x-2 mb-4">
                  <div className="w-1.5 h-1.5 rounded-full bg-emerald-500" />
                  <span className="text-[9px] font-black text-emerald-600 uppercase tracking-widest">Dari Output</span>
                </div>
                <p className="text-3xl sm:text-4xl font-dari text-right leading-relaxed text-gray-900" dir="rtl">{result.dariTranslation}</p>
