import { GoogleGenAI, Type, Modality } from "@google/genai";
import { LocalizationResult, TranslationTone, GroundingSource } from "../types";

const SYSTEM_INSTRUCTION = `
You are the "Global Native Bridge," a specialized linguistic AI expert. Your primary goal is to localize and translate text into authentic, native versions of any target language requested. 
You prioritize "native-first" vocabulary, avoiding clinical or overly formal textbook translations in favor of idiomatic, culturally-accurate speech.

Linguistic Rules:
1. Vocabulary: Use local terminology and regional dialects where appropriate (e.g., using specific regional terms for the target language).
2. Accent/Cadence: The output must reflect natural, native speech patterns.
3. Precision: Focus on factual accuracy and deep cultural context.

Output format MUST be a JSON object:
{
  "sourceLanguage": "Detected source language",
  "targetLanguage": "Requested target language",
  "dariTranslation": "The localized translation in the target language's native script",
  "transliteration": "Latin script transliteration for pronunciation (if script is non-Latin)",
  "localizationNotes": ["Array of strings explaining specific word choices and cultural nuances"]
}
`;

async function withRetry<T>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const msg = String(error).toLowerCase();
    const isRetryable = msg.includes('500') || msg.includes('429') || msg.includes('other') || msg.includes('finish reason');
    if (isRetryable && retries > 0) {
      await new Promise(r => setTimeout(r, delay));
      return withRetry(fn, retries - 1, delay * 1.5);
    }
    throw error;
  }
}

export const localizeText = async (text: string, tone: TranslationTone, targetLanguage: string = "Dari", useSearch = false): Promise<LocalizationResult> => {
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const modelName = "gemini-3-pro-preview";

    const config: any = {
      systemInstruction: SYSTEM_INSTRUCTION,
    };

    if (useSearch) {
      config.tools = [{ googleSearch: {} }];
    } else {
      config.responseMimeType = "application/json";
      config.responseSchema = {
        type: Type.OBJECT,
        properties: {
          sourceLanguage: { type: Type.STRING },
          targetLanguage: { type: Type.STRING },
          dariTranslation: { type: Type.STRING },
          transliteration: { type: Type.STRING },
          localizationNotes: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["sourceLanguage", "targetLanguage", "dariTranslation", "localizationNotes"]
      };
    }

    const response = await ai.models.generateContent({
      model: modelName,
      contents: `Translate to native ${targetLanguage} (${tone.toLowerCase()}): "${text}".

      ${useSearch ? `IMPORTANT: Use the Google Search tool to find exactly 3 high-quality web references (articles, facts, or image-hosting sources) that ground the context of this specific translation. These must be reflected in your grounding metadata.` : ""}

      MANDATORY: Return the result strictly as a JSON object inside your response text according to the system instructions.` ,
      config
    });

    let result: any = {};
    const textResponse = response.text || '';

    try {
      const jsonMatch = textResponse.match(/\{[\s\S]*\}/);
      result = JSON.parse(jsonMatch ? jsonMatch[0] : textResponse);
    } catch (e) {
      result = { dariTranslation: textResponse, localizationNotes: ["Contextual Extraction Mode"], targetLanguage };
    }

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      const seenUris = new Set<string>();
      result.groundingSources = groundingChunks
        .map((chunk: any) => {
          if (chunk.web && !seenUris.has(chunk.web.uri)) {
            seenUris.add(chunk.web.uri);
            return { 
              title: chunk.web.title, 
              uri: chunk.web.uri 
            };
          }
          return null;
        })
        .filter(Boolean)
        .slice(0, 3) as GroundingSource[];
    }

    return result as LocalizationResult;
  });
};

export const generateSpeech = async (text: string, voiceName: 'Puck' | 'Kore'): Promise<string> => {
  // TTS might struggle with some scripts, but we pass the raw localized text
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: { parts: [{ text: text }] },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName } } },
      },
    });
    const audioData = response.candidates?.[0]?.content?.parts.find(p => p.inlineData)?.inlineData?.data;
    if (!audioData) throw new Error("No audio returned");
    return audioData;
  });
};

export const getExpertAnalysis = async (translatedText: string, sourceText: string, targetLanguage: string): Promise<string> => {
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Expert analysis: ${targetLanguage} translation "${translatedText}" vs Source "${sourceText}". Focus on native linguistics and cultural authenticity. Provide a concise breakdown.`,
      config: { systemInstruction: `You are an expert ${targetLanguage} linguist.` }
    });
    return response.text || "Analysis unavailable.";
  });
};

export const localizeFile = async (base64: string, mimeType: string, prompt: string, tone: TranslationTone, targetLanguage: string = "Dari"): Promise<LocalizationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: { parts: [{ inlineData: { data: base64, mimeType: mimeType } }, { text: `${prompt} Localize to native ${targetLanguage} (${tone.toLowerCase()}).` }] },
    config: { systemInstruction: SYSTEM_INSTRUCTION, responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{}');
};

export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
  return bytes;
}

export async function decodePCM(data: Uint8Array, ctx: AudioContext, sampleRate = 24000, numChannels = 1): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, data.byteLength / 2);
  const buffer = ctx.createBuffer(numChannels, dataInt16.length / numChannels, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < channelData.length; i++) channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
  }
  return buffer;
}

export function encodeWAV(pcmBytes: Uint8Array, sampleRate = 24000): Blob {
  const buffer = new ArrayBuffer(44 + pcmBytes.length);
  const view = new DataView(buffer);
  view.setUint32(0, 0x52494646, false); // "RIFF"
  view.setUint32(4, 36 + pcmBytes.length, true);
  view.setUint32(8, 0x57415645, false); // "WAVE"
  view.setUint32(12, 0x666d7420, false); // "fmt "
  view.setUint32(16, 16, true);
  view.setUint16(20, 1, true);
  view.setUint16(22, 1, true);
  view.setUint32(24, sampleRate, true);
  view.setUint32(28, sampleRate * 2, true);
  view.setUint16(32, 2, true);
  view.setUint16(34, 16, true);
  view.setUint32(36, 0x64617461, false); // "data"
  view.setUint32(40, pcmBytes.length, true);
  const pcmBuffer = new Uint8Array(buffer, 44);
  pcmBuffer.set(pcmBytes);
  return new Blob([buffer], { type: 'audio/wav' });
}

import React, { useState, useRef } from 'react';
import { TranslationMode, TranslationTone } from '../types';

interface Props {
  onTranslate: (data: { text?: string; file?: File; mode: TranslationMode; tone: TranslationTone; useSearch: boolean; targetLanguage: string }) => void;
  onStop: () => void;
  loading: boolean;
}

const TranslationInput: React.FC<Props> = ({ onTranslate, onStop, loading }) => {
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TEXT);
  const [tone, setTone] = useState<TranslationTone>(TranslationTone.INFORMAL);
  const [targetLanguage, setTargetLanguage] = useState('Dari');
  const [useSearch, setUseSearch] = useState(false);
  const [text, setText] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [isRecording, setIsRecording] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerRef = useRef<number | null>(null);

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (loading) {
      onStop();
      return;
    }
    if (mode === TranslationMode.TEXT && text.trim()) {
      onTranslate({ text, mode, tone, useSearch, targetLanguage });
    } else if (file) {
      onTranslate({ file, mode, tone, useSearch, targetLanguage });
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selected = e.target.files?.[0];
    if (selected) {
      setFile(selected);
      setIsRecording(false);
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      const chunks: Blob[] = [];
      recorder.ondataavailable = (e) => { if (e.data.size > 0) chunks.push(e.data); };
      recorder.onstop = () => {
        const blob = new Blob(chunks, { type: 'audio/webm' });
        const recordedFile = new File([blob], `recording_${new Date().getTime()}.webm`, { type: 'audio/webm' });
        setFile(recordedFile);
        stream.getTracks().forEach(track => track.stop());
        if (timerRef.current) clearInterval(timerRef.current);
        setRecordingTime(0);
      };
      mediaRecorderRef.current = recorder;
      recorder.start();
      setIsRecording(true);
      setRecordingTime(0);
      timerRef.current = window.setInterval(() => setRecordingTime(prev => prev + 1), 1000);
    } catch (err) {
      console.error("Microphone error:", err);
      alert("Microphone access denied.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="bg-white rounded-[1.5rem] shadow-xl border border-gray-100 overflow-hidden">
      {/* Tab Header */}
      <div className="flex bg-gray-50 border-b border-gray-100">
        <button
          onClick={() => { setMode(TranslationMode.TEXT); setIsRecording(false); }}
          className={`flex-1 py-2 text-[10px] font-black tracking-widest transition-all ${mode === TranslationMode.TEXT ? 'text-emerald-600 bg-white' : 'text-gray-400'}`}
        >
