import { GoogleGenAI, Type, Modality } from "@google/genai";
import { LocalizationResult, TranslationTone, GroundingSource } from "../types";

const SYSTEM_INSTRUCTION = `
You are the "Dari Native Bridge," a specialized linguistic AI expert. Your primary goal is to localize and translate text from any world language into authentic, native Dari (Afghan Persian). 
You prioritize "Dari-first" native Afghan vocabulary, avoiding Iranian-specific neologisms or textbook Persian.

Linguistic Rules:
1. Vocabulary: Use native Afghan terms (e.g., using 'Pohantun' instead of 'Daneshgah').
2. Accent/Cadence: The output must reflect the natural, neutral speech patterns of Afghanistan (Kabul/Mazar/Herat).
3. Precision: Focus on factual accuracy and deep cultural context for the Afghan audience.

Output format MUST be a JSON object:
{
  "sourceLanguage": "Detected source language",
  "targetLanguage": "Dari (Native Afghan)",
  "dariTranslation": "The localized translation in the Dari (Persian) script",
  "transliteration": "Latin script transliteration for pronunciation",
  "localizationNotes": ["Array of strings explaining specific word choices and cultural nuances relative to the source language"]
}
`;

async function withRetry<T>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const msg = String(error).toLowerCase();
    const isRetryable = msg.includes('500') || msg.includes('429') || msg.includes('other') || msg.includes('finish reason');
    if (isRetryable && retries > 0) {
      await new Promise(r => setTimeout(r, delay));
      return withRetry(fn, retries - 1, delay * 1.5);
    }
    throw error;
  }
}

export const localizeText = async (text: string, tone: TranslationTone, useSearch = false): Promise<LocalizationResult> => {
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const modelName = "gemini-3-pro-preview";

    const config: any = {
      systemInstruction: SYSTEM_INSTRUCTION,
    };

    if (useSearch) {
      config.tools = [{ googleSearch: {} }];
    } else {
      config.responseMimeType = "application/json";
      config.responseSchema = {
        type: Type.OBJECT,
        properties: {
          sourceLanguage: { type: Type.STRING },
          targetLanguage: { type: Type.STRING },
          dariTranslation: { type: Type.STRING },
          transliteration: { type: Type.STRING },
          localizationNotes: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["sourceLanguage", "targetLanguage", "dariTranslation", "localizationNotes"]
      };
    }

    const response = await ai.models.generateContent({
      model: modelName,
      contents: `Translate the following into native Afghan Dari (${tone.toLowerCase()} tone): "${text}".

      ${useSearch ? `IMPORTANT: Use the Google Search tool to find exactly 3 high-quality web references (articles, facts, or image-hosting sources) that ground the context of this specific translation for an Afghan audience. These must be reflected in your grounding metadata.` : ""}

      MANDATORY: Return the result strictly as a JSON object inside your response text according to the system instructions.` ,
      config
    });

    let result: any = {};
    const textResponse = response.text || '';

    try {
      const jsonMatch = textResponse.match(/\{[\s\S]*\}/);
      result = JSON.parse(jsonMatch ? jsonMatch[0] : textResponse);
    } catch (e) {
      result = { dariTranslation: textResponse, localizationNotes: ["Native Contextual Bridge Mode"], targetLanguage: "Dari (Native Afghan)" };
    }

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      const seenUris = new Set<string>();
      result.groundingSources = groundingChunks
        .map((chunk: any) => {
          if (chunk.web && !seenUris.has(chunk.web.uri)) {
            seenUris.add(chunk.web.uri);
            return { 
              title: chunk.web.title, 
              uri: chunk.web.uri 
            };
          }
          return null;
        })
        .filter(Boolean)
        .slice(0, 3) as GroundingSource[];
    }

    return result as LocalizationResult;
  });
};

export const generateSpeech = async (text: string, voiceName: 'Puck' | 'Kore'): Promise<string> => {
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: { parts: [{ text: text }] },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName } } },
      },
    });
    const audioData = response.candidates?.[0]?.content?.parts.find(p => p.inlineData)?.inlineData?.data;
    if (!audioData) throw new Error("No audio returned");
    return audioData;
  });
};

export const getExpertAnalysis = async (translatedText: string, sourceText: string): Promise<string> => {
  return withRetry(async () => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Expert linguistic analysis: Native Dari translation "${translatedText}" vs Source "${sourceText}". Focus on Afghan cultural authenticity and idiomatic accuracy. Provide a concise breakdown.`,
      config: { systemInstruction: `You are an expert Afghan linguist specializing in native Dari localization.` }
    });
    return response.text || "Analysis unavailable.";
  });
};

export const localizeFile = async (base64: string, mimeType: string, prompt: string, tone: TranslationTone): Promise<LocalizationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: { parts: [{ inlineData: { data: base64, mimeType: mimeType } }, { text: `${prompt} Localize the content into native Afghan Dari (${tone.toLowerCase()} tone).` }] },
    config: { systemInstruction: SYSTEM_INSTRUCTION, responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{}');
};

export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
  return bytes;
}

export async function decodePCM(data: Uint8Array, ctx: AudioContext, sampleRate = 24000, numChannels = 1): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, data.byteLength / 2);
  const buffer = ctx.createBuffer(numChannels, dataInt16.length / numChannels, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < channelData.length; i++) channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
  }
  return buffer;
}

export function encodeWAV(pcmBytes: Uint8Array, sampleRate = 24000): Blob {
  const buffer = new ArrayBuffer(44 + pcmBytes.length);
  const view = new DataView(buffer);
  view.setUint32(0, 0x52494646, false); // "RIFF"
  view.setUint32(4, 36 + pcmBytes.length, true);
  view.setUint32(8, 0x57415645, false); // "WAVE"
  view.setUint32(12, 0x666d7420, false); // "fmt "
  view.setUint32(16, 16, true);
  view.setUint16(20, 1, true);
  view.setUint16(22, 1, true);
  view.setUint32(24, sampleRate, true);
  view.setUint32(28, sampleRate * 2, true);
  view.setUint16(32, 2, true);
  view.setUint16(34, 16, true);
  view.setUint32(36, 0x64617461, false); // "data"
  view.setUint32(40, pcmBytes.length, true);
  const pcmBuffer = new Uint8Array(buffer, 44);
  pcmBuffer.set(pcmBytes);
  return new Blob([buffer], { type: 'audio/wav' });
}

import React, { useState, useRef } from 'react';
import { TranslationMode, TranslationTone } from '../types';

interface Props {
  onTranslate: (data: { text?: string; file?: File; mode: TranslationMode; tone: TranslationTone; useSearch: boolean }) => void;
  onStop: () => void;
  loading: boolean;
}

const TranslationInput: React.FC<Props> = ({ onTranslate, onStop, loading }) => {
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TEXT);
  const [tone, setTone] = useState<TranslationTone>(TranslationTone.INFORMAL);
  const [useSearch, setUseSearch] = useState(false);
  const [text, setText] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [isRecording, setIsRecording] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerRef = useRef<number | null>(null);

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (loading) {
      onStop();
      return;
    }
    if (mode === TranslationMode.TEXT && text.trim()) {
      onTranslate({ text, mode, tone, useSearch });
    } else if (file) {
      onTranslate({ file, mode, tone, useSearch });
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selected = e.target.files?.[0];
    if (selected) {
      setFile(selected);
      setIsRecording(false);
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      const chunks: Blob[] = [];
      recorder.ondataavailable = (e) => { if (e.data.size > 0) chunks.push(e.data); };
      recorder.onstop = () => {
        const blob = new Blob(chunks, { type: 'audio/webm' });
        const recordedFile = new File([blob], `recording_${new Date().getTime()}.webm`, { type: 'audio/webm' });
        setFile(recordedFile);
        stream.getTracks().forEach(track => track.stop());
        if (timerRef.current) clearInterval(timerRef.current);
        setRecordingTime(0);
      };
      mediaRecorderRef.current = recorder;
      recorder.start();
      setIsRecording(true);
      setRecordingTime(0);
      timerRef.current = window.setInterval(() => setRecordingTime(prev => prev + 1), 1000);
    } catch (err) {
      console.error("Microphone error:", err);
      alert("Microphone access denied.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="bg-white rounded-[1.5rem] shadow-xl border border-gray-100 overflow-hidden">
      {/* Tab Header */}
      <div className="flex bg-gray-50 border-b border-gray-100">
        <button
          onClick={() => { setMode(TranslationMode.TEXT); setIsRecording(false); }}
          className={`flex-1 py-2 text-[10px] font-black tracking-widest transition-all ${mode === TranslationMode.TEXT ? 'text-emerald-600 bg-white' : 'text-gray-400'}`}
        >
          TEXT BRIDGE
        </button>
        <button
          onClick={() => setMode(TranslationMode.MEDIA)}
          className={`flex-1 py-2 text-[10px] font-black tracking-widest transition-all ${mode === TranslationMode.MEDIA ? 'text-emerald-600 bg-white' : 'text-gray-400'}`}
        >
          MEDIA BRIDGE
        </button>
      </div>

      <div className="p-4 space-y-4">
        {/* Compact Settings Bar */}
        <div className="flex items-center justify-between">
          <div className="flex bg-gray-100 p-1 rounded-lg">
            <button
              onClick={() => setTone(TranslationTone.FORMAL)}
              className={`px-4 py-1 text-[8px] font-black tracking-tighter rounded-md transition-all ${tone === TranslationTone.FORMAL ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-400'}`}
            >
              FORMAL
            </button>
            <button
              onClick={() => setTone(TranslationTone.INFORMAL)}
              className={`px-4 py-1 text-[8px] font-black tracking-tighter rounded-md transition-all ${tone === TranslationTone.INFORMAL ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-400'}`}
            >
              INFORMAL
            </button>
          </div>

          <button 
            onClick={() => setUseSearch(!useSearch)}
            className={`flex items-center space-x-1.5 px-2.5 py-1 rounded-lg border text-[8px] font-black uppercase tracking-widest transition-all ${useSearch ? 'bg-emerald-50 border-emerald-200 text-emerald-600' : 'bg-white border-gray-100 text-gray-400'}`}
          >
            <div className={`w-1.5 h-1.5 rounded-full ${useSearch ? 'bg-emerald-500 animate-pulse' : 'bg-gray-200'}`} />
            <span>Fact Check</span>
          </button>
        </div>

        {/* Input Area */}
        {mode === TranslationMode.TEXT ? (
          <div className="flex items-end gap-2 bg-gray-50/50 p-3 rounded-xl border border-gray-100 focus-within:ring-2 focus-within:ring-emerald-500/10 transition-all">
            <textarea
              className="flex-grow bg-transparent border-0 text-sm font-medium outline-none resize-none placeholder:text-gray-300 min-h-[80px] leading-relaxed"
              placeholder="Enter text from any world language..."
              value={text}
              disabled={loading}
              onChange={(e) => setText(e.target.value)}
              onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSubmit(); } }}
            />

            <button
              onClick={() => handleSubmit()}
              disabled={loading || !text.trim()}
              className={`shrink-0 w-12 h-12 flex items-center justify-center rounded-xl transition-all shadow-md ${loading ? 'bg-red-50 text-red-500 shadow-red-100' : 'bg-emerald-600 text-white hover:bg-emerald-700 active:scale-95 shadow-emerald-100'}`}
              title="Localize to Dari"
            >
              {loading ? (
                <div className="w-4 h-4 border-2 border-red-200 border-t-red-600 rounded-full animate-spin" />
              ) : (
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
              )}
            </button>
          </div>
        ) : (
          <div className="flex items-center gap-2">
            <div 
              className={`flex-grow border-2 border-dashed rounded-xl p-6 text-center bg-gray-50/30 hover:bg-emerald-50/20 transition-all cursor-pointer ${file ? 'border-emerald-200' : 'border-gray-100'}`} 
              onClick={() => fileInputRef.current?.click()}
            >
              <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileChange} accept="image/*,application/pdf,audio/*,video/*" />
              <div className="flex flex-col items-center">
                <svg className="w-8 h-8 text-emerald-400 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0l-4 4m4-4v12" /></svg>
                <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest truncate max-w-[180px]">{file ? file.name : "Upload Media to Dari Bridge"}</span>
              </div>
            </div>

            <div className="flex flex-col gap-2">
              <button
                onClick={isRecording ? stopRecording : startRecording}
                className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${isRecording ? 'bg-red-500 text-white animate-pulse' : 'bg-gray-900 text-white hover:bg-black'}`}
              >
                {isRecording ? <div className="w-3 h-3 bg-white rounded-sm" /> : <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8V4a1 1 0 112 0v4a9 9 0 01-8 8.93V19a1 1 0 11-2 0v-2.07A9.001 9.001 0 011 8V4a1 1 0 012 0v4a7 7 0 0014 0z" clipRule="evenodd"/></svg>}
              </button>
              {isRecording && <span className="text-[8px] font-black text-red-500 animate-pulse text-center">{formatTime(recordingTime)}</span>}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default TranslationInput;

import React, { useState, useRef } from 'react';
import { LocalizationResult } from '../types';
import { generateSpeech, decodeBase64, decodePCM, getExpertAnalysis, encodeWAV } from '../services/geminiService';

interface Props {
  result: LocalizationResult;
  sourceText?: string;
}

const WebLink = ({ uri, title }: { uri: string; title: string }) => {
  const getDomain = (url: string) => {
    try {
      return new URL(url).hostname.replace('www.', '');
    } catch {
      return 'Source';
    }
  };

  return (
    <a 
      href={uri} 
      target="_blank" 
      rel="noreferrer" 
      className="group flex flex-col items-center justify-center p-3 bg-white border border-gray-100 rounded-xl transition-all hover:border-emerald-500 hover:shadow-lg hover:shadow-emerald-500/5 text-center h-full min-h-[90px]"
    >
      <div className="w-8 h-8 bg-emerald-50 text-emerald-600 rounded-full flex items-center justify-center mb-2 group-hover:bg-emerald-600 group-hover:text-white transition-colors">
        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"/>
        </svg>
      </div>
      <span className="text-[8px] font-black text-gray-900 uppercase tracking-tight line-clamp-2 leading-tight mb-0.5">{title}</span>
      <span className="text-[6px] font-bold text-gray-400 uppercase tracking-widest">{getDomain(uri)}</span>
    </a>
  );
};

const ResultView: React.FC<Props> = ({ result, sourceText }) => {
  const [playingVoice, setPlayingVoice] = useState<'Puck' | 'Kore' | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [expertAnalysis, setExpertAnalysis] = useState<string | undefined>(result.expertAnalysis);
  const [isDownloading, setIsDownloading] = useState(false);
  const [showDownloadMenu, setShowDownloadMenu] = useState(false);
  const [playbackSpeed, setPlaybackSpeed] = useState(1.0);
  const [downloadConfig, setDownloadConfig] = useState({ filename: 'dari_bridge_export', format: 'WAV' as 'WAV' | 'MP3' });
  const audioCtxRef = useRef<AudioContext | null>(null);

  const handleExpertAnalysis = async () => {
    if (!sourceText || isAnalyzing) return;
    setIsAnalyzing(true);
    try {
      const analysis = await getExpertAnalysis(result.dariTranslation, sourceText);
      setExpertAnalysis(analysis);
    } catch (err) { console.error(err); } finally { setIsAnalyzing(false); }
  };

  const handlePlayVoice = async (voiceName: 'Puck' | 'Kore') => {
    if (playingVoice) return;
    try {
      setPlayingVoice(voiceName);
      const base64 = await generateSpeech(result.dariTranslation, voiceName);
      if (!audioCtxRef.current) audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const ctx = audioCtxRef.current;
      if (ctx.state === 'suspended') await ctx.resume();
      const audioData = decodeBase64(base64);
      const audioBuffer = await decodePCM(audioData, ctx);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.playbackRate.value = playbackSpeed;
      source.connect(ctx.destination);
      source.onended = () => setPlayingVoice(null);
      source.start(0);
    } catch (error) { setPlayingVoice(null); }
  };

  const handleDownload = async () => {
    if (isDownloading) return;
    setIsDownloading(true);
    try {
      const base64 = await generateSpeech(result.dariTranslation, 'Puck');
      const pcmBytes = decodeBase64(base64);
      const blob = encodeWAV(pcmBytes);
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${downloadConfig.filename}.${downloadConfig.format.toLowerCase()}`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      setShowDownloadMenu(false);
    } catch (err) {
      console.error(err);
      alert("Export Failed.");
    } finally {
      setIsDownloading(false);
    }
  };

  return (
    <div className="space-y-4 animate-in fade-in slide-in-from-right-8 duration-700 fill-mode-both">
      <div className="bg-white rounded-[2rem] shadow-2xl shadow-slate-200/50 border border-gray-100 overflow-hidden">

        {/* Header Action Bar */}
        <div className="px-6 py-4 border-b border-gray-50 flex items-center justify-between bg-white">
          <div className="flex items-center space-x-2">
            <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-emerald-600">Native Dari Bridge Verified</span>
          </div>

          <div className="flex items-center space-x-2">
            <div className="relative">
              <button 
                onClick={() => setShowDownloadMenu(!showDownloadMenu)}
                className="w-9 h-9 rounded-xl bg-gray-50 text-gray-400 hover:bg-emerald-50 hover:text-emerald-600 flex items-center justify-center transition-all border border-gray-100"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"/>
                </svg>
              </button>
              {showDownloadMenu && (
                <div className="absolute right-0 top-11 w-56 bg-white rounded-2xl shadow-2xl border border-gray-100 p-4 z-50 animate-in fade-in slide-in-from-top-2">
                  <div className="space-y-3">
                    <div className="space-y-1">
                      <label className="text-[8px] font-black text-gray-400 uppercase">Export Name</label>
                      <input 
                        type="text" 
                        className="w-full bg-gray-50 border border-gray-100 rounded-lg px-2 py-1 text-[10px] outline-none" 
                        value={downloadConfig.filename}
                        onChange={(e) => setDownloadConfig(prev => ({ ...prev, filename: e.target.value }))}
                      />
                    </div>
                    <button onClick={handleDownload} disabled={isDownloading} className="w-full bg-emerald-600 text-white py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all">
                      {isDownloading ? 'Synthesizing...' : 'Export to WAV'}
                    </button>
                  </div>
                </div>
              )}
            </div>

            <div className="w-[1px] h-4 bg-gray-100" />

            <div className="flex items-center space-x-2 bg-gray-50/80 px-3 py-1.5 rounded-xl border border-gray-100">
              <span className="text-[8px] font-black text-gray-400 uppercase tracking-tighter">Speed</span>
              <select 
                value={playbackSpeed} 
                onChange={(e) => setPlaybackSpeed(parseFloat(e.target.value))}
                className="bg-transparent text-[10px] font-black text-emerald-600 outline-none cursor-pointer"
              >
                <option value="0.5">0.5x</option>
                <option value="0.75">0.75x</option>
                <option value="1.0">1.0x</option>
                <option value="1.25">1.25x</option>
                <option value="1.5">1.5x</option>
              </select>
            </div>

            <div className="w-[1px] h-4 bg-gray-100" />

            <div className="flex space-x-1.5">
              <button onClick={() => handlePlayVoice('Puck')} className={`w-9 h-9 rounded-xl transition-all flex items-center justify-center ${playingVoice === 'Puck' ? 'bg-blue-600 text-white' : 'bg-blue-50 text-blue-600 border border-blue-100 hover:bg-blue-100'}`} title="Male Voice">
                <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z"/></svg>
              </button>
              <button onClick={() => handlePlayVoice('Kore')} className={`w-9 h-9 rounded-xl transition-all flex items-center justify-center ${playingVoice === 'Kore' ? 'bg-emerald-600 text-white' : 'bg-emerald-50 text-emerald-600 border border-emerald-100 hover:bg-emerald-100'}`} title="Female Voice">
                <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.707-3.707a1 1 0 011.09-.217zM14.657 2.929a1 1 0 011.414 0A9.972 9.972 0 0119 10a9.972 9.972 0 01-2.929 7.071 1 1 0 01-1.414-1.414A7.971 7.971 0 0017 10c0-2.21-.894-4.208-2.343-5.657a1 1 0 010-1.414zm-2.829 2.828a1 1 0 011.415 0A5.983 5.983 0 0115 10a5.984 5.984 0 01-1.757 4.243 1 1 0 01-1.415-1.415A3.984 3.984 0 0013 10a3.983 3.983 0 00-1.172-2.828 1 1 0 010-1.415z" clipRule="evenodd"/></svg>
              </button>
            </div>
          </div>
        </div>

        <div className="p-6 bg-slate-50/50">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="bg-white rounded-[1.5rem] border border-gray-100 p-6 flex flex-col shadow-sm">
              <div className="flex items-center space-x-2 mb-4">
                <div className="w-1.5 h-1.5 rounded-full bg-slate-300" />
                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{result.sourceLanguage || "Source"} Content</span>
              </div>
              <p className="text-sm text-gray-500 font-medium leading-relaxed italic line-clamp-6">{sourceText || "No context provided."}</p>
              <div className="mt-auto pt-6 text-[8px] font-black uppercase text-slate-300 tracking-tighter">Source Identity Detected</div>
            </div>

            <div className="bg-white rounded-[1.5rem] border border-emerald-50 p-6 flex flex-col shadow-sm">
              <div className="flex items-center space-x-2 mb-4">
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500" />
                <span className="text-[9px] font-black text-emerald-600 uppercase tracking-widest">Native Dari Output</span>
              </div>
              <p className="text-3xl sm:text-4xl font-dari text-right leading-relaxed text-gray-900 mb-4" dir="rtl">
                {result.dariTranslation}
              </p>
              {result.transliteration && (
                <div className="mt-auto pt-4 border-t border-emerald-50">
                  <p className="text-[11px] text-emerald-600/60 font-medium italic">{result.transliteration}</p>
                </div>
              )}
            </div>
          </div>
        </div>

        {result.groundingSources && result.groundingSources.length > 0 && (
          <div className="p-6 border-t border-gray-50 bg-white">
            <div className="flex items-center space-x-2 mb-4">
              <svg className="w-4 h-4 text-emerald-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/>
              </svg>
              <span className="text-[9px] font-black text-emerald-900 uppercase tracking-widest">Bridged Factual Grounding</span>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
              {result.groundingSources.map((source, i) => (
                <WebLink key={i} uri={source.uri} title={source.title} />
              ))}
            </div>
          </div>
        )}

        <div className="p-6 border-t border-gray-50 bg-slate-50/30">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-[9px] font-black uppercase tracking-widest text-gray-400">Localization Strategy</h3>
            <button 
              onClick={handleExpertAnalysis} 
              disabled={isAnalyzing} 
              className="text-[10px] font-black uppercase tracking-widest text-emerald-600 hover:text-emerald-700 underline decoration-emerald-200 decoration-2 underline-offset-4"
            >
              {isAnalyzing ? "Analyzing..." : "Afghan Linguistic Analysis"}
            </button>
          </div>

          {expertAnalysis && (
            <div className="bg-emerald-50/40 p-5 rounded-2xl border border-emerald-100/50 mb-6 animate-in slide-in-from-top-2">
              <p className="text-[11px] text-emerald-900 leading-relaxed font-medium">{expertAnalysis}</p>
            </div>
          )}

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            {result.localizationNotes.map((note, i) => (
              <div key={i} className="flex items-start space-x-3 bg-white p-4 rounded-xl border border-gray-100 shadow-sm group">
                <span className="w-5 h-5 bg-gray-50 text-gray-400 group-hover:bg-emerald-600 group-hover:text-white rounded-lg flex items-center justify-center text-[9px] font-black shrink-0 transition-colors">{i+1}</span>
                <p className="text-[10px] text-gray-500 font-medium leading-normal">{note}</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ResultView;

import React, { useState, useRef } from 'react';
import Header from './components/Header';
import TranslationInput from './components/TranslationInput';
import ResultView from './components/ResultView';
import { TranslationMode, TranslationTone, ProcessingState, LocalizationResult } from './types';
import { localizeText, localizeFile } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<ProcessingState>({
    loading: false,
    step: 'NONE',
    error: null,
    result: null,
  });
  const [lastSourceText, setLastSourceText] = useState<string>('');

  const currentRequestId = useRef<number>(0);

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve((reader.result as string).split(',')[1]);
      reader.onerror = error => reject(error);
    });
  };

  const handleStop = () => {
    currentRequestId.current += 1;
    setState(prev => ({ ...prev, loading: false, step: 'NONE' }));
  };

  const handleTranslate = async (data: { text?: string; file?: File; mode: TranslationMode; tone: TranslationTone; useSearch: boolean }) => {
    const requestId = currentRequestId.current;
    setState({ loading: true, step: 'LOCALIZING', error: null, result: null });
    const sourceText = data.text || data.file?.name || 'Media Content';
    setLastSourceText(sourceText);

    try {
      let result: LocalizationResult;
      if (data.mode === TranslationMode.TEXT && data.text) {
        result = await localizeText(data.text, data.tone, data.useSearch);
      } else if (data.file) {
        const base64 = await fileToBase64(data.file);
        const isVisual = data.file.type.startsWith('image/') || data.file.type === 'application/pdf';
        const prompt = isVisual ? "OCR and localize this document content into native Afghan Dari." : "Transcribe and localize this media content into native Afghan Dari.";
        result = await localizeFile(base64, data.file.type, prompt, data.tone);
      } else throw new Error("Missing input data");

      if (currentRequestId.current !== requestId) return;
      setState({ loading: false, step: 'NONE', error: null, result });

      if (window.innerWidth < 1024) {
        setTimeout(() => window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' }), 100);
      }
    } catch (err: any) {
      if (currentRequestId.current !== requestId) return;
      setState({ loading: false, step: 'NONE', error: err.message || "Bridge failed.", result: null });
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header />
      <main className="flex-grow max-w-[1400px] mx-auto px-4 sm:px-6 py-6 w-full">
        {/* Compact Hero Section */}
        <section className="mb-8">
          <h2 className="text-xl sm:text-2xl font-black text-gray-900 tracking-tight">Dari Native Bridge</h2>
          <p className="text-gray-400 text-[10px] font-bold uppercase tracking-[0.2em] mt-1">Bridging Any World Language to Authentic Afghan Dari</p>
        </section>

        {/* Layout */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 items-start">
          {/* Input Area */}
          <div className="lg:col-span-5 space-y-4">
            <TranslationInput onTranslate={handleTranslate} onStop={handleStop} loading={state.loading} />

            <div className="hidden lg:block bg-white rounded-3xl p-6 border border-gray-100 shadow-sm">
              <h3 className="text-gray-400 font-black text-[9px] uppercase tracking-widest mb-4 flex items-center">
                <svg className="w-3.5 h-3.5 mr-2 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" /></svg>
                Active Fidelity Engine
              </h3>
              <div className="space-y-3">
                <div className="flex items-center justify-between text-[11px] font-bold">
                  <span className="text-gray-500">Linguistic Reasoning</span>
                  <span className="text-emerald-600">Gemini 3 Pro</span>
                </div>
                <div className="flex items-center justify-between text-[11px] font-bold">
                  <span className="text-gray-500">Source Detection</span>
                  <span className="text-emerald-600">Dynamic (Multi-Lingual)</span>
                </div>
                <div className="w-full h-1 bg-emerald-50 rounded-full overflow-hidden">
                  <div className="w-full h-full bg-emerald-500 animate-[pulse_2s_infinite]"></div>
                </div>
              </div>
            </div>
          </div>

          {/* Output Area */}
          <div className="lg:col-span-7 space-y-4 min-h-[400px]">
            {state.error && (
              <div className="bg-red-50 border border-red-100 text-red-600 p-4 rounded-2xl flex items-center space-x-3 animate-in fade-in duration-300">
                <p className="text-xs font-black uppercase tracking-wider">{state.error}</p>
              </div>
            )}

            {state.result ? (
              <ResultView result={state.result} sourceText={lastSourceText} />
            ) : state.loading ? (
              <div className="h-full min-h-[450px] flex flex-col items-center justify-center space-y-6 bg-white border border-gray-100 rounded-[2.5rem] p-8 shadow-sm">
                <div className="relative">
                  <div className="w-16 h-16 border-[4px] border-emerald-50 border-t-emerald-600 rounded-full animate-spin"></div>
                  <div className="absolute inset-0 flex items-center justify-center"><div className="w-2.5 h-2.5 bg-emerald-600 rounded-full animate-pulse"></div></div>
                </div>
                <div className="text-center">
                  <p className="text-gray-900 font-black uppercase tracking-[0.2em] text-[10px] mb-1">Bridging Linguistics</p>
                  <p className="text-gray-400 text-[9px] font-bold uppercase">Mapping to Native Dari...</p>
                  <button onClick={handleStop} className="mt-6 px-6 py-2 bg-gray-100 hover:bg-red-50 hover:text-red-600 text-gray-400 rounded-full text-[9px] font-black uppercase tracking-widest transition-all">Abort</button>
                </div>
              </div>
            ) : (
              <div className="h-full min-h-[450px] flex flex-col items-center justify-center bg-white border border-gray-100 rounded-[2.5rem] text-gray-300 p-8 text-center shadow-sm">
                <div className="bg-gray-50 p-6 rounded-full mb-4">
                  <svg className="w-8 h-8 text-gray-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
                </div>
                <h4 className="text-gray-900 font-bold text-base mb-1">Bridge Awaiting Input</h4>
                <p className="text-[11px] font-medium text-gray-400 max-w-[200px]">The Bridge will detect your source language and localize it into native Afghan Dari here.</p>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

